import{_ as t}from"./chunks/audio-player.33a8a7f8.js";import{_ as s}from"./chunks/youtube-embed.088623b1.js";import{_ as i,c as r,d as a,b as n,o as h}from"./app.e8e78a69.js";const f='{"title":"\u0428\u0438\u0432\u0430 \u043C\u0430\u0445\u0438\u043C\u043D\u0430 \u0441\u0442\u043E\u0442\u0440\u0430","description":"","frontmatter":{"title":"\u0428\u0438\u0432\u0430 \u043C\u0430\u0445\u0438\u043C\u043D\u0430 \u0441\u0442\u043E\u0442\u0440\u0430","subtitle":"\u0413\u0438\u043C\u043D \u0432\u0435\u043B\u0438\u0447\u0438\u044F \u0428\u0438\u0432\u044B","sans":"\u092A\u0936\u093F\u0935\u092E\u0939\u093F\u092E\u094D\u0928\u0903 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u092E\u094D","trans":"\u015Aivamahimna\u1E25 stotram","date":"2021-03-06T00:00:00.000Z","tags":"hymn"},"headers":[],"relativePath":"hymns/mahimna/index.md"}',p={},v=n('<p><a href="https://www.sanskrit-trikashaivism.com/ru/shiva-mahimna-stotram-normal-translation-ru/597" class="external-link" target="_blank" rel="noopener noreferrer">\u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430 \u0440\u0443\u0441\u0441\u043A\u0438\u0439 \u0418\u0440\u0438\u043D\u044B \u0412\u0430\u043B\u043B\u0430\u0431\u0445\u0438 \u0441 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u0433\u043E \u0438 \u0438\u0441\u043F\u0430\u043D\u0441\u043A\u043E\u0433\u043E \u043F\u043E\u0441\u043B\u043E\u0432\u043D\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0413\u0443\u0440\u0443 \u0413\u0430\u0431\u0440\u0438\u044D\u043B\u044F \u041F\u0440\u0430\u0434\u0438\u0438\u043F\u0430\u043A\u0438</a></p><div class="stanza"><p class="sans">\u0917\u091C\u093E\u0928\u0928\u0902 \u092D\u0942\u0924\u0917\u0923\u093E\u0927\u093F\u0938\u0947\u0935\u093F\u0924\u0902 \u0915\u092A\u093F\u0924\u094D\u0925\u091C\u092E\u094D\u092C\u0942\u092B\u0932\u091A\u093E\u0930\u0941\u092D\u0915\u094D\u0937\u0923\u092E\u094D \u0964<br> \u0909\u092E\u093E\u0938\u0941\u0924\u0902 \u0936\u094B\u0915\u0935\u093F\u0928\u093E\u0936\u0915\u093E\u0930\u0915\u0902 \u0928\u092E\u093E\u092E\u093F \u0935\u093F\u0918\u094D\u0928\u0947\u0936\u094D\u0935\u0930\u092A\u093E\u0926\u092A\u0919\u094D\u0915\u091C\u092E\u094D\u0965</p><p class="trans">Gaj\u0101nana\u1E41 bh\u016Btaga\u1E47\u0101disevita\u1E41 kapitthajamb\u016Bphalac\u0101rubhak\u1E63anam \u0964<br> Um\u0101suta\u1E41 \u015Bokavin\u0101\u015Bak\u0101raka\u1E41 nam\u0101mi vighne\u015Bvarap\u0101dapa\u1E45kajam\u0965</p><p>\u042F \u043F\u0440\u0435\u043A\u043B\u043E\u043D\u044F\u044E\u0441\u044C <em>(nam\u0101mi)</em> \u043F\u0435\u0440\u0435\u0434 \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u043C\u0438 \u0441\u0442\u043E\u043F\u0430\u043C\u0438 <em>(p\u0101dapa\u1E45kajam)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u0437\u0431\u0430\u0432\u043B\u044F\u0435\u0442 \u043E\u0442] \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439 <em>(vighna)</em> [\u0438] \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 <em>(k\u0101rakam)</em> \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 <em>(vin\u0101\u015Ba)</em> [\u0432\u0441\u0435\u0445] \u0433\u043E\u0440\u0435\u0441\u0442\u0435\u0439 <em>(\u015Boka)</em>, \u0441\u043B\u043E\u043D\u043E\u043B\u0438\u0446\u0435\u0433\u043E <em>(gaja-\u0101nanam)</em> \u0441\u044B\u043D\u0430 <em>(sutam)</em> \u0423\u043C\u044B -- \u0441\u0443\u043F\u0440\u0443\u0433\u0438 \u0428\u0438\u0432\u044B-- <em>(um\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u0441\u043B\u0443\u0436\u0430\u0442 <em>(sevitam)</em> \u0430\u0440\u043C\u0438\u0438 <em>(ga\u1E47a)</em> \u0434\u0443\u0445\u043E\u0432 \u0438 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u0438\u0439 <em>(bh\u016Bta)</em> [\u0428\u0438\u0432\u044B], \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u0438 \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0447\u0430\u0440\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(c\u0101ru)</em> \u0432\u043A\u0443\u0448\u0430\u0435\u0442 <em>(bhak\u1E63a\u1E47am)</em> \u0434\u0438\u043A\u0438\u0435 \u044F\u0431\u043B\u043E\u043A\u0438 <em>(kapittha... phala)</em> \u0438 \u0440\u043E\u0437\u043E\u0432\u044B\u0435 \u044F\u0431\u043B\u043E\u043A\u0438 <em>(jamb\u016Bphala)</em>.</p></div><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u0936\u094D\u0930\u0940\u092A\u0941\u0937\u094D\u092A\u0926\u0928\u094D\u0924 \u0909\u0935\u093E\u091A \u092E\u0939\u093F\u092E\u094D\u0928\u0903 \u092A\u093E\u0930\u0902 \u0924\u0947 \u092A\u0930\u092E\u0935\u093F\u0926\u0941\u0937\u094B \u092F\u0926\u094D\u092F\u0938\u0926\u0943\u0936\u0940 \u0938\u094D\u0924\u0941\u0924\u093F\u0930\u094D\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0926\u0940\u0928\u093E\u092E\u092A\u093F \u0924\u0926\u0935\u0938\u0928\u094D\u0928\u093E\u0938\u094D\u0924\u094D\u0935\u092F\u093F \u0917\u093F\u0930\u0903 \u0964<br> \u0905\u0925\u093E\u0935\u093E\u091A\u094D\u092F\u0903 \u0938\u0930\u094D\u0935\u0903 \u0938\u094D\u0935\u092E\u0924\u093F\u092A\u0930\u093F\u0923\u093E\u092E\u093E\u0935\u0927\u093F \u0917\u0943\u0923\u0928\u094D \u092E\u092E\u093E\u092A\u094D\u092F\u0947\u0937\u0903 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0947 \u0939\u0930 \u0928\u093F\u0930\u092A\u0935\u093E\u0926\u0903 \u092A\u0930\u093F\u0915\u0930\u0903 \u0965\u0967\u0965</p><p class="trans">\u015Ar\u012Bpu\u1E63padanta uv\u0101ca<br> Mahimna\u1E25 p\u0101ra\u1E41 te paramavidu\u1E63o yadyasad\u1E5B\u015B\u012B stutirbrahm\u0101d\u012Bn\u0101mapi tadavasann\u0101stvayi gira\u1E25 \u0964<br> Ath\u0101v\u0101cya\u1E25 sarva\u1E25 svamatipari\u1E47\u0101m\u0101vadhi g\u1E5B\u1E47an mam\u0101pye\u1E63a\u1E25 stotre hara nirapav\u0101da\u1E25 parikara\u1E25 \u09651\u0965</p><p>\u041F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u0439 <em>(\u015Br\u012B)</em> \u041F\u0443\u0448\u043F\u0430\u0434\u0430\u043D\u0442\u0430 --\u0434\u043E\u0441\u043B. \xAB\u0441 \u0437\u0443\u0431\u0430\u043C\u0438 \u0438\u0437 \u0446\u0432\u0435\u0442\u043E\u0432\xBB-- <em>(pu\u1E63padanta\u1E25)</em> \u0441\u043A\u0430\u0437\u0430\u043B <em>(uv\u0101ca)</em>:<br> \u0415\u0441\u043B\u0438 \u0431\u044B <em>(yadi)</em> \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u0435 <em>(stuti\u1E25)</em>, [\u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0435] \u043A\u0435\u043C-\u0442\u043E, \u043A\u0442\u043E \u0441\u043E\u0432\u0441\u0435\u043C <em>(param)</em> \u043D\u0435 \u0437\u043D\u0430\u0435\u0442 <em>(avidusa\u1E25)</em> \u043F\u0440\u0435\u0434\u0435\u043B\u0430 <em>(p\u0101ram)</em> \u0422\u0432\u043E\u0435\u0433\u043E <em>(te)</em> \u0432\u0435\u043B\u0438\u0447\u0438\u044F <em>(mahimna\u1E25)</em>, \u0431\u044B\u043B\u043E \u0431\u044B \u043D\u0435\u043F\u043E\u0434\u043E\u0431\u0430\u044E\u0449\u0435 <em>(asad\u1E5B\u015B\u012B)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432\u043E\u0437\u0433\u043B\u0430\u0441\u044B \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u044F <em>(gira\u1E25)</em> \u0422\u0435\u0431\u044F <em>(tvayi)</em>, [\u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0451\u043D\u043D\u044B\u0435] \u0411\u0440\u0430\u0445\u043C\u043E\u0439 <em>(brahm\u0101)</em> \u0438 \u0442.\u0434., --\u0101di-- <em>(\u0101d\u012Bn\u0101m)</em> [\u0431\u044B\u043B\u0438 \u0431\u044B] \u043E\u0442\u043A\u043B\u043E\u043D\u0435\u043D\u044B \u0438 \u0443\u0432\u044F\u043B\u0438 \u0431\u044B <em>(avasann\u0101\u1E25)</em>. \u041A \u0442\u043E\u043C\u0443 \u0436\u0435 <em>(atha)</em>, [\u0435\u0441\u043B\u0438] \u0432\u0441\u0435 <em>(sarva\u1E25)</em>, \u043A\u0442\u043E \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u0435\u0442 [\u0422\u0435\u0431\u044F] <em>(g\u1E5B\u1E47an)</em> \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E <em>(avadhi)</em> \u0440\u0430\u0437\u0432\u0438\u0442\u043E\u0441\u0442\u0438 <em>(pari\u1E47\u0101ma)</em> \u0441\u0432\u043E\u0435\u0433\u043E <em>(sva)</em> \u0440\u0430\u0437\u0443\u043C\u0430 <em>(mati)</em> \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0431\u044B\u0442\u044C \u043E\u0431\u0432\u0438\u043D\u0435\u043D\u044B \u0438\u043B\u0438 \u043E\u0433\u043E\u0432\u043E\u0440\u0435\u043D\u044B <em>(av\u0101cya\u1E25)</em>, [\u0442\u043E\u0433\u0434\u0430], \u043E \u0425\u0430\u0440\u0430 --\u0428\u0438\u0432\u0430-- <em>(hara)</em>, \u044D\u0442\u043E\u0442 <em>(e\u1E63a\u1E25)</em> \xAB\u041F\u0430\u0440\u0438\u043A\u0430\u0440\u0430\xBB --\u0440\u044F\u0434 \u044D\u043F\u0438\u0442\u0435\u0442\u043E\u0432 \u0438\u043B\u0438 \u043F\u0440\u0438\u043B\u0430\u0433\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445-- [\u0432 \u0447\u0435\u0441\u0442\u044C \u0422\u0435\u0431\u044F] <em>(parikara\u1E25)</em>, [\u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0445] \u043C\u043D\u043E\u044E <em>(mama)</em> \u0432 \u0433\u0438\u043C\u043D\u0435 <em>(stotre)</em>, \u0442\u043E\u0436\u0435_ <em>(api)</em> \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0434\u0432\u0435\u0440\u0433\u043D\u0443\u0442 \u0446\u0435\u043D\u0437\u0443\u0440\u0435 <em>(nirapav\u0101da\u1E25)</em></p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0905\u0924\u0940\u0924\u0903 \u092A\u0928\u094D\u0925\u093E\u0928\u0902 \u0924\u0935 \u091A \u092E\u0939\u093F\u092E\u093E \u0935\u093E\u0919\u094D\u092E\u093E\u0928\u0938\u092F\u094B\u0930\u0924\u0926\u094D\u0935\u094D\u092F\u093E\u0935\u0943\u0924\u094D\u0924\u094D\u092F\u093E \u092F\u0902 \u091A\u0915\u093F\u0924\u092E\u092D\u093F\u0927\u0924\u094D\u0924\u0947 \u0936\u094D\u0930\u0941\u0924\u093F\u0930\u092A\u093F \u0964<br> \u0938 \u0915\u0938\u094D\u092F \u0938\u094D\u0924\u094B\u0924\u0935\u094D\u092F\u0903 \u0915\u0924\u093F\u0935\u093F\u0927\u0917\u0941\u0923\u0903 \u0915\u0938\u094D\u092F \u0935\u093F\u0937\u092F\u0903 \u092A\u0926\u0947 \u0924\u094D\u0935\u0930\u094D\u0935\u093E\u091A\u0940\u0928\u0947 \u092A\u0924\u0924\u093F \u0928 \u092E\u0928\u0903 \u0915\u0938\u094D\u092F \u0928 \u0935\u091A\u0903 \u0965\u0968\u0965</p><p class="trans">At\u012Bta\u1E25 panth\u0101na\u1E41 tava ca mahim\u0101 v\u0101\u1E45m\u0101nasayoratadvy\u0101v\u1E5Btty\u0101 ya\u1E41 cakitamabhidhatte \u015Brutirapi \u0964<br> Sa kasya stotavya\u1E25 katividhagu\u1E47a\u1E25 kasya vi\u1E63aya\u1E25 pade tvarv\u0101c\u012Bne patati na mana\u1E25 kasya na vaca\u1E25 \u09652\u0965</p><p>\u0422\u0432\u043E\u0435 <em>(tava)</em> \u0432\u0435\u043B\u0438\u0447\u0438\u0435 <em>(mahim\u0101)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(ca)</em> \u0432\u043D\u0435 <em>(at\u012Bta\u1E25)</em> \u0434\u043E\u0441\u044F\u0433\u0430\u0435\u043C\u043E\u0441\u0442\u0438 <em>(panth\u0101nam)</em> \u0440\u0435\u0447\u0438 <em>(v\u0101k)</em> \u0438 \u0443\u043C\u0430 --m\u0101nasa-- <em>(m\u0101nasayo\u1E25)</em>. \u0414\u0430\u0436\u0435 <em>(api)</em> \u0428\u0440\u0443\u0442\u0438 -- \u044D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u043E\u0431\u044B\u0447\u043D\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u043E\u043C \u0412\u0435\u0434, \u0445\u043E\u0442\u044F \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u0440\u0430\u0437\u0434\u0435\u043B\u0430\u043C \xABMantra\xBB \u0438 \xABBr\u0101hma\u1E47a\xBB \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0412\u0435\u0434-- <em>(\u015Bruti\u1E25)</em> \u0441 \u0431\u043B\u0430\u0433\u043E\u0433\u043E\u0432\u0435\u043D\u0438\u0435\u043C <em>(cakitam)</em> \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 <em>(abhidhatte)</em> \u0442\u043E [\u0432\u0435\u043B\u0438\u0447\u0438\u0435] <em>(yam)</em>, \u0437\u0430 \u0438\u0441\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435\u043C [\u043B\u044E\u0431\u044B\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 \u0438\u043C\u0451\u043D] <em>(vy\u0101v\u1E5Btty\u0101)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \xAB\u043D\u0435 \u0442\u043E\xBB <em>(atad)</em>. [\u0418\u0442\u0430\u043A], \u043A\u0435\u043C <em>(kasya)</em> \u041E\u043D --\u0428\u0438\u0432\u0430-- <em>(sa\u1E25)</em> [\u0431\u0443\u0434\u0435\u0442] \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u0442\u044C\u0441\u044F <em>(stotavya\u1E25)</em>? \u0421\u043A\u043E\u043B\u044C\u043A\u0438\u043C\u0438 <em>(katividha)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(gu\u1E47a)</em> [\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0428\u0438\u0432\u0430]? \u041A\u0435\u043C <em>(kasya)</em> [\u041E\u043D \u0431\u0443\u0434\u0435\u0442] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442 <em>(vi\u1E63aya\u1E25)</em>? \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, [\u0433\u0434\u0435 \u0442\u043E\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A], \u0447\u044C\u0438 <em>(kasya)</em> \u0443\u043C <em>(manas)</em> [\u0438] \u0440\u0435\u0447\u044C <em>(vaca\u1E25)</em> \u043D\u0435 <em>(na... na)</em> \u043F\u0440\u043E\u043F\u0430\u0434\u0430\u044E\u0442 <em>(patati)</em> \u043F\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pade)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 [\u0422\u044B] \u0432\u0445\u043E\u0434\u0438\u0448\u044C \u043F\u043E\u0441\u043B\u0435 <em>(arv\u0101c\u012Bne)</em>? \u09652\u0965</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u092E\u0927\u0941\u0938\u094D\u092B\u0940\u0924\u093E \u0935\u093E\u091A\u0903 \u092A\u0930\u092E\u092E\u092E\u0943\u0924\u0902 \u0928\u093F\u0930\u094D\u092E\u093F\u0924\u0935\u0924\u0938\u094D\u0924\u0935 \u092C\u094D\u0930\u0939\u094D\u092E\u0928\u094D\u0915\u093F\u0902 \u0935\u093E\u0917\u092A\u093F \u0938\u0941\u0930\u0917\u0941\u0930\u094B\u0930\u094D\u0935\u093F\u0938\u094D\u092E\u092F\u092A\u0926\u092E\u094D \u0964<br> \u092E\u092E \u0924\u094D\u0935\u0947\u0928\u093E\u0902 \u0935\u093E\u0923\u0940\u0902 \u0917\u0941\u0923\u0915\u0925\u0928\u092A\u0941\u0923\u094D\u092F\u0947\u0928 \u092D\u0935\u0924\u0903 \u092A\u0941\u0928\u093E\u092E\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0947\u093D\u0938\u094D\u092E\u093F\u0928\u094D \u092A\u0941\u0930\u092E\u0925\u0928 \u092C\u0941\u0926\u094D\u0927\u093F\u0930\u094D\u0935\u094D\u092F\u0935\u0938\u093F\u0924\u093E \u0965\u0969\u0965</p><p class="trans">Madhusph\u012Bt\u0101 v\u0101ca\u1E25 paramamam\u1E5Bta\u1E41 nirmitavatastava brahmanki\u1E41 v\u0101gapi suragurorvismayapadam \u0964<br> Mama tven\u0101\u1E41 v\u0101\u1E47\u012B\u1E41 gu\u1E47akathanapu\u1E47yena bhavata\u1E25 pun\u0101m\u012Btyarthe&#39;smin puramathana buddhirvyavasit\u0101 \u09653\u0965</p><p>\u041E, \u0411\u0440\u0430\u0445\u043C\u0430 --\u0410\u0431\u0441\u043E\u043B\u044E\u0442-- <em>(brahman)</em>! \u0423\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043B\u0438 <em>(kim... vismayapadam)</em>, \u0447\u0442\u043E \u0434\u0430\u0436\u0435 <em>(api)</em> \u0433\u0443\u0440\u0443 --\u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A-- <em>(guro\u1E25)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em> --\u0442.e. \xABB\u1E5Bhaspati\xBB-- [\u043F\u0440\u043E\u0438\u0437\u043D\u0451\u0441] \u0441\u043B\u043E\u0432\u0430 <em>(v\u0101k)</em> [\u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u044E\u0449\u0438\u0435] \u0422\u0435\u0431\u044F <em>(tava)</em>, \u0430\u0432\u0442\u043E\u0440\u0430 --nirmitav\u0101n-- <em>(nirmitavata\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(paramam)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(am\u1E5Btam)</em> --\u0442.e. \u0412\u0435\u0434--, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0441\u043B\u043E\u0432 <em>(v\u0101ca\u1E25)</em> \u043F\u043E\u043B\u043D\u044B\u0445 <em>(sph\u012Bt\u0101\u1E25)</em> \u043C\u0451\u0434\u0430 [\u0437\u043D\u0430\u043D\u0438\u044F] <em>(madhu)</em>? \xAB\u042F \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu)</em> \u043E\u0442\u0447\u0438\u0449\u0430\u044E <em>(pun\u0101mi)</em> \u043C\u043E\u044E <em>(mama... en\u0101m)</em> \u0440\u0435\u0447\u044C <em>(v\u0101\u1E47\u012Bm)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0435\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u0430\u043A\u0442\u043E\u043C <em>(pu\u1E47yena)</em> \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F <em>(kathana)</em> \u0422\u0432\u043E\u0438\u0445 <em>(bhavata\u1E25)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432 <em>(gu\u1E47a)</em>\xBB... \u0414\u043B\u044F \u044D\u0442\u043E\u0439 \u0446\u0435\u043B\u0438 <em>(ityarthe)</em>, [\u043C\u043E\u0439] \u0440\u0430\u0437\u0443\u043C <em>(buddhi\u1E25)</em> \u0440\u0435\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0438\u043D\u044F\u043B \u043D\u0430 \u0441\u0435\u0431\u044F <em>(vyavasit\u0101)</em> \u044D\u0442\u0443 [\u0437\u0430\u0434\u0430\u0447\u0443] <em>(asmin)</em>, \u043E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(mathana)</em> [\u0442\u0440\u0451\u0445] \u0433\u043E\u0440\u043E\u0434\u043E\u0432 <em>(pura)</em>! --\u0428\u0438\u0432\u0443 \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \xABpuramathana\xBB, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u041E\u043D \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u043B \u0442\u0440\u0438 \u0433\u043E\u0440\u043E\u0434\u0430, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u0442\u0440\u0451\u043C \u0441\u044B\u043D\u043E\u0432\u044C\u044F\u043C \u0434\u0435\u043C\u043E\u043D\u043E\u0432 \u043F\u043E \u0438\u043C\u0435\u043D\u0438 T\u0101raka--</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u0924\u0935\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u0902 \u092F\u0924\u094D\u0924\u091C\u094D\u091C\u0917\u0926\u0941\u0926\u092F\u0930\u0915\u094D\u0937\u093E\u092A\u094D\u0930\u0932\u092F\u0915\u0943\u0924\u094D\u0924\u094D\u0930\u092F\u0940\u0935\u0938\u094D\u0924\u0941 \u0935\u094D\u092F\u0938\u094D\u0924\u0902 \u0924\u093F\u0938\u0943\u0937\u0941 \u0917\u0941\u0923\u092D\u093F\u0928\u094D\u0928\u093E\u0938\u0941 \u0924\u0928\u0941\u0937\u0941 \u0964<br> \u0905\u092D\u0935\u094D\u092F\u093E\u0928\u093E\u092E\u0938\u094D\u092E\u093F\u0928\u094D \u0935\u0930\u0926 \u0930\u092E\u0923\u0940\u092F\u093E\u092E\u0930\u092E\u0923\u0940\u0902 \u0935\u093F\u0939\u0928\u094D\u0924\u0941\u0902 \u0935\u094D\u092F\u093E\u0915\u094D\u0930\u094B\u0936\u0940\u0902 \u0935\u093F\u0926\u0927\u0924 \u0907\u0939\u0948\u0915\u0947 \u091C\u0921\u0927\u093F\u092F\u0903 \u0965\u096A\u0965</p><p class="trans">Tavai\u015Bvarya\u1E41 yattajjagadudayarak\u1E63\u0101pralayak\u1E5Bttray\u012Bvastu vyasta\u1E41 tis\u1E5B\u1E63u gu\u1E47abhinn\u0101su tanu\u1E63u \u0964<br> Abhavy\u0101n\u0101masmin varada rama\u1E47\u012By\u0101marama\u1E47\u012B\u1E41 vihantu\u1E41 vy\u0101kro\u015B\u012B\u1E41 vidadhata ihaike ja\u1E0Dadhiya\u1E25 \u09654\u0965</p><p>\u0422\u0432\u043E\u0439 <em>(tava)</em> \u0421\u0443\u0432\u0435\u0440\u0435\u043D\u0438\u0442\u0435\u0442 \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0441\u0432\u043E <em>(ai\u015Bvaryam)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(yad-tad)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \xAB\u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 <em>(k\u1E5Bt)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udaya)</em> \u043C\u0438\u0440\u0430 <em>(jagat)</em>\xBB --\u0442.e. Brahm\u0101--, \xAB\u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0434\u0430\u0451\u0442 <em>(k\u1E5Bt)</em> \u0437\u0430\u0449\u0438\u0442\u0443 <em>(rak\u1E63\u0101)</em> \u043C\u0438\u0440\u0443 <em>(jagat)</em>\xBB --\u0442.e. Vi\u1E63\u1E47u--, \xAB\u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(k\u1E5Bt)</em> \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F <em>(pralaya)</em> \u043C\u0438\u0440\u0430 <em>(jagat)</em>\xBB --\u0442.e. Rudra--, \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0442\u0440\u0435\u0445\u043A\u0440\u0430\u0442\u043D\u043E\u0439 <em>(tray\u012B)</em> \u0441\u0443\u0442\u044C\u044E <em>(vastu)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u0430 [\u0432 \u0412\u0435\u0434\u0430\u0445] <em>(vyastam)</em> \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(tis\u1E5B\u1E63u)</em> \u0444\u043E\u0440\u043C\u0435 <em>(tanu\u1E63u)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u0440\u0430\u0437\u043D\u044B\u0445 <em>(bhinn\u0101su)</em> \u0433\u0443\u043D --\u043A\u0430\u0447\u0435\u0441\u0442\u0432 Prak\u1E5Bti-- <em>(gu\u1E47a)</em>. \u041E \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>! \u0412 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(iha)</em> \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(eke)</em> \u0441\u043B\u0430\u0431\u043E\u0443\u043C\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 <em>(ja\u1E0Dadhiya\u1E25)</em> \u043F\u0440\u0438\u0432\u043E\u0434\u044F\u0442 <em>(vidadhate)</em> \u043E\u0441\u043A\u043E\u0440\u0431\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 <em>(vy\u0101kro\u015B\u012Bm)</em> <em>(\u0438)</em> \u043D\u0435\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0435 <em>(arama\u1E47\u012Bm)</em> <em>(\u0434\u043E\u0432\u043E\u0434\u044B),</em> \u0447\u0442\u043E\u0431\u044B \u0434\u043E\u043A\u0443\u0447\u0430\u0442\u044C <em>(vihantum)</em>. [\u042D\u0442\u0438\u043C\u0438 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0442\u0441\u044F [\u0442\u043E\u043B\u044C\u043A\u043E] <em>(rama\u1E47\u012By\u0101m)</em> \u0431\u0435\u0437\u0431\u043E\u0436\u043D\u044B\u0435 \u0438 \u043D\u0435\u043F\u043E\u0441\u0432\u044F\u0449\u0451\u043D\u043D\u044B\u0435 <em>(abhavy\u0101n\u0101m)</em> \u0432 \u044D\u0442\u043E <em>(asmin)</em> --\u0442.e. \xAB\u0432 \u0438\u0441\u0442\u0438\u043D\u0443 \u0421\u0443\u0432\u0435\u0440\u0435\u043D\u0438\u0442\u0435\u0442\u0430 \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 \u0428\u0438\u0432\u044B\xBB--</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u0915\u093F\u092E\u0940\u0939\u0903 \u0915\u093F\u0902\u0915\u093E\u092F\u0903 \u0938 \u0916\u0932\u0941 \u0915\u093F\u092E\u0941\u092A\u093E\u092F\u0938\u094D\u0924\u094D\u0930\u093F\u092D\u0941\u0935\u0928\u0902 \u0915\u093F\u092E\u093E\u0927\u093E\u0930\u094B \u0927\u093E\u0924\u093E \u0938\u0943\u091C\u0924\u093F \u0915\u093F\u092E\u0941\u092A\u093E\u0926\u093E\u0928 \u0907\u0924\u093F \u091A \u0964<br> \u0905\u0924\u0930\u094D\u0915\u094D\u092F\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u0947 \u0924\u094D\u0935\u092F\u094D\u092F\u0928\u0935\u0938\u0930\u0926\u0941\u0903\u0938\u094D\u0925\u094B \u0939\u0924\u0927\u093F\u092F\u0903 \u0915\u0941\u0924\u0930\u094D\u0915\u094B\u093D\u092F\u0902 \u0915\u093E\u0902\u0936\u094D\u091A\u093F\u0928\u094D\u092E\u0941\u0916\u0930\u092F\u0924\u093F \u092E\u094B\u0939\u093E\u092F \u091C\u0917\u0924\u0903 \u0965\u096B\u0965</p><p class="trans">Kim\u012Bha\u1E25 ki\u1E45k\u0101ya\u1E25 sa khalu kimup\u0101yastribhuvana\u1E41 kim\u0101dh\u0101ro dh\u0101t\u0101 s\u1E5Bjati kimup\u0101d\u0101na iti ca \u0964<br> Atarkyai\u015Bvarye tvayyanavasaradu\u1E25stho hatadhiya\u1E25 kutarko&#39;ya\u1E41 k\u0101\u1E41\u015Bcinmukharayati moh\u0101ya jagata\u1E25 \u09655\u0965</p><p>\xAB\u041A\u0430\u043A\u043E\u0435 <em>(kim)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u0435 <em>(\u012Bha\u1E25)</em> \u041E\u043D [\u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u044F\u0435\u0442] <em>(sa\u1E25 khalu)</em>? \u0412 \u043A\u0430\u043A\u043E\u043C <em>(kim)</em> \u0442\u0435\u043B\u0435 <em>(k\u0101ya\u1E25)</em> \u041E\u043D [\u0432\u043E\u043F\u043B\u043E\u0449\u0430\u0435\u0442\u0441\u044F] <em>(sa\u1E25 khalu)</em>? [\u0418] \u043A\u0430\u043A\u043E\u0439 <em>(kim)</em> \u043C\u0435\u0442\u043E\u0434 <em>(up\u0101ya\u1E25)</em>, \u043E\u0441\u043D\u043E\u0432\u0443 <em>(\u0101dh\u0101ra\u1E25)</em> \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B <em>(upad\u0101na\u1E25)</em> \u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044C <em>(dh\u0101t\u0101)</em> [\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0434\u043B\u044F] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(s\u1E5Bjati)</em> \u0442\u0440\u0451\u0445 <em>(tri)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvanam... iti ca)</em>?\xBB --\xABiti\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043A\u0430\u0432\u044B\u0447\u043A\u0438, \u0430 \xABca\xBB \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u0432\u0441\u0442\u0430\u0432\u043D\u044B\u043C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u043C \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435--. \u042D\u0442\u043E\u0442 <em>(ayam)</em> \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u044B\u0439 \u043E\u0431\u0440\u0430\u0437 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F <em>(kutarka\u1E25)</em>, \u043D\u0435\u043C\u0443\u0434\u0440\u044B\u0439 <em>(du\u1E25stha\u1E25)</em> \u0438 \u043D\u0435\u0443\u043C\u0435\u0441\u0442\u043D\u044B\u0439 <em>(anavasara)</em>, \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0422\u0435\u0431\u044F <em>(tvayi)</em> \u0438 [\u0422\u0432\u043E\u0435\u0433\u043E] \u0421\u0443\u0432\u0435\u0440\u0435\u043D\u0438\u0442\u0435\u0442\u0430 \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 <em>(ai\u015Bvarye)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u0438 \u043B\u043E\u0433\u0438\u043A\u0443 <em>(atarkya)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0442 \u0441\u0431\u0438\u0442\u043E\u0439 \u0441 \u0442\u043E\u043B\u043A\u0443 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 <em>(hatadhiya\u1E25)</em>. [\u042D\u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u044B\u0439 \u043E\u0431\u0440\u0430\u0437 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F] \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(k\u0101n-cid)</em> [\u0433\u0440\u043E\u043C\u043A\u043E] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C <em>(mukharayati)</em> [\u0442\u043E\u043B\u044C\u043A\u043E \u043B\u0438\u0448\u044C \u0434\u043B\u044F \u0442\u043E\u0433\u043E], \u0447\u0442\u043E\u0431\u044B \u043C\u0438\u0440 <em>(jagata\u1E25)</em> \u0443\u0442\u0440\u0430\u0442\u0438\u043B \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u043F\u0430\u043B \u0436\u0435\u0440\u0442\u0432\u043E\u0439 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moh\u0101ya)</em></p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u0905\u091C\u0928\u094D\u092E\u093E\u0928\u094B \u0932\u094B\u0915\u093E\u0903 \u0915\u093F\u092E\u0935\u092F\u0935\u0935\u0928\u094D\u0924\u094B\u093D\u092A\u093F \u091C\u0917\u0924\u093E\u092E\u0927\u093F\u0937\u094D\u091F\u093E\u0924\u093E\u0930\u0902 \u0915\u093F\u0902 \u092D\u0935\u0935\u093F\u0927\u093F\u0930\u0928\u093E\u0926\u0943\u0924\u094D\u092F \u092D\u0935\u0924\u093F \u0964<br> \u0905\u0928\u0940\u0936\u094B \u0935\u093E \u0915\u0941\u0930\u094D\u092F\u093E\u0926\u094D\u092D\u0941\u0935\u0928\u091C\u0928\u0928\u0947 \u0915\u0903 \u092A\u0930\u093F\u0915\u0930\u094B \u092F\u0924\u094B \u092E\u0928\u094D\u0926\u093E\u0938\u094D\u0924\u094D\u0935\u093E\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u092E\u0930\u0935\u0930 \u0938\u0902\u0936\u0947\u0930\u0924 \u0907\u092E\u0947 \u0965\u096C\u0965</p><p class="trans">Ajanm\u0101no lok\u0101\u1E25 kimavayavavanto&#39;pi jagat\u0101madhi\u1E63\u1E6Dh\u0101t\u0101ra\u1E41 ki\u1E41 bhavavidhiran\u0101d\u1E5Btya bhavati \u0964<br> An\u012B\u015Bo v\u0101 kury\u0101dbhuvanajanane ka\u1E25 parikaro yato mand\u0101stv\u0101\u1E41 pratyamaravara sa\u1E41\u015Berata ime \u09656\u0965</p><p>\xAB\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u043B\u0438 <em>(kim)</em> \u043C\u0438\u0440\u044B <em>(lok\u0101\u1E25)</em> \u0431\u0435\u0437 \u043A\u0430\u043A\u043E\u0433\u043E \u043B\u0438\u0431\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 <em>(ajanm\u0101na\u1E25)</em>, \u043D\u0435 \u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E <em>(api)</em> \u043E\u043D\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 \u0447\u0430\u0441\u0442\u0435\u0439 <em>(avayavavanta\u1E25)</em>? \u0418\u043C\u0435\u0435\u0442 \u043B\u0438 \u043C\u0435\u0441\u0442\u043E \u0431\u044B\u0442\u044C <em>(kim... bhavati)</em> \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 <em>(vidhi\u1E25)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhava)</em> \u0432\u043D\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 <em>(an\u0101d\u1E5Btya)</em> _\u043E\u0442 _[\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F] \u043A\u043E\u0433\u043E-\u0442\u043E, \u043A\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u0442 <em>(adhi\u1E63\u1E6Dh\u0101t\u0101ram)</em> [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C\u0438] \u043C\u0438\u0440\u0430\u043C\u0438 <em>(jagat\u0101m)</em>? \u0418\u043B\u0438 <em>(v\u0101)</em>, <em>(\u0435\u0441\u043B\u0438)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u0430 \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(an\u012B\u015Ba\u1E25)</em>, \u043A\u0430\u043A\u043E\u0439 <em>(ka\u1E25)</em> \u043F\u043E\u043C\u043E\u0449\u043D\u0438\u043A <em>(parikara\u1E25)</em> \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 <em>(kury\u0101t)</em> \u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 <em>(janane)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em>?\xBB \u041E\u0441\u043D\u043E\u0432\u044B\u0432\u0430\u044F [\u0441\u0432\u043E\u0438 \u0438\u0434\u0435\u0438] \u043D\u0430 [\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u043C \u043E\u0431\u0440\u0430\u0437\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F] <em>(yatas)</em>, \u043E \u0422\u044B, \u0432\u044B\u0441\u0448\u0438\u0439 <em>(vara)</em> \u0441\u0440\u0435\u0434\u0438 \u0431\u043E\u0433\u043E\u0432 <em>(amara)</em>, \u044D\u0442\u0438 <em>(ime)</em> \u0441\u043B\u0430\u0431\u043E\u0443\u043C\u043D\u044B\u0435 \u0438 \u0433\u043B\u0443\u043F\u044B\u0435 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 <em>(mand\u0101\u1E25)</em> \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0442 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(sa\u1E41\u015Berate)</em> \u043E \u0422\u0435\u0431\u0435 <em>(tv\u0101\u1E41 prati)</em></p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0924\u094D\u0930\u092F\u0940 \u0938\u093E\u0919\u094D\u0916\u094D\u092F\u0902 \u092F\u094B\u0917\u0903 \u092A\u0936\u0941\u092A\u0924\u093F\u092E\u0924\u0902 \u0935\u0948\u0937\u094D\u0923\u0935\u092E\u093F\u0924\u093F \u092A\u094D\u0930\u092D\u093F\u0928\u094D\u0928\u0947 \u092A\u094D\u0930\u0938\u094D\u0925\u093E\u0928\u0947 \u092A\u0930\u092E\u093F\u0926\u092E\u0926\u0903 \u092A\u0925\u094D\u092F\u092E\u093F\u0924\u093F \u091A \u0964<br> \u0930\u0941\u091A\u0940\u0928\u093E\u0902 \u0935\u0948\u091A\u093F\u0924\u094D\u0930\u094D\u092F\u093E\u0926\u0943\u091C\u0941\u0915\u0941\u091F\u093F\u0932\u0928\u093E\u0928\u093E\u092A\u0925\u091C\u0941\u0937\u093E\u0902 \u0928\u0943\u0923\u093E\u092E\u0947\u0915\u094B \u0917\u092E\u094D\u092F\u0938\u094D\u0924\u094D\u0935\u092E\u0938\u093F \u092A\u092F\u0938\u093E\u092E\u0930\u094D\u0923\u0935 \u0907\u0935 \u0965\u096D\u0965</p><p class="trans">Tray\u012B s\u0101\u1E45khya\u1E41 yoga\u1E25 pa\u015Bupatimata\u1E41 vai\u1E63\u1E47avamiti prabhinne prasth\u0101ne paramidamada\u1E25 pathyamiti ca \u0964<br> Ruc\u012Bn\u0101\u1E41 vaicitry\u0101d\u1E5Bjuku\u1E6Dilan\u0101n\u0101pathaju\u1E63\u0101\u1E41 n\u1E5B\u1E47\u0101meko gamyastvamasi payas\u0101mar\u1E47ava iva \u09657\u0965</p><p>\xAB\u0422\u0440\u0438 \u0412\u0435\u0434\u044B <em>(tray\u012B)</em>, \u0421\u0430\u043D\u043A\u0445\u044C\u044F <em>(s\u0101\u1E45khyam)</em>, \u0419\u043E\u0433\u0430 <em>(yoga\u1E25)</em>, \u0443\u0447\u0435\u043D\u0438\u0435 <em>(matam)</em> \u041F\u0430\u0448\u0443\u043F\u0430\u0442\u0438 <em>(pa\u015Bupati)</em> --\u0442.e. \u0428\u0438\u0432\u0430\u0438\u0437\u043C-- <em>(\u0438)</em> \u0412\u0430\u0439\u0448\u043D\u0430\u0432\u0438\u0437\u043C -- \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0439\u0441\u044F \u043A \u0413\u043E\u0441\u043F\u043E\u0434\u0443 \u0412\u0438\u0448\u043D\u0443-- <em>(vai\u1E63\u1E47avam iti)</em>\xBB: \u0432 [\u044D\u0442\u0438\u0445] \u0440\u0430\u0437\u043D\u044B\u0445 <em>(prabhinne)</em> \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430\u0445 <em>(prasth\u0101ne)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C [\u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F] <em>(iti ca)</em> \u0442\u043E\u0442 <em>(idam)</em> \u0438\u043B\u0438 \u0438\u043D\u043E\u0439 <em>(adas)</em> \u043F\u0443\u0442\u044C <em>(pathyam)</em> \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 [\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E] <em>(param)</em> --\u0442.e. \u0435\u0441\u0442\u044C \u0440\u0430\u0437\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F \u0438\u043B\u0438 \u0428\u0438\u0432\u044B--. \u0414\u043B\u044F \u043B\u044E\u0434\u0435\u0439 <em>(n\u1E5B\u1E47\u0101m)</em>, \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u0445 <em>(ju\u1E63\u0101m)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C <em>(n\u0101n\u0101)</em> \u043F\u0443\u0442\u044F\u043C <em>(patha)</em>, \u043F\u0440\u044F\u043C\u044B\u043C \u0438 \u0438\u0437\u0432\u0438\u043B\u0438\u0441\u0442\u044B\u043C <em>(\u1E5Bju-ku\u1E6Dila)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u044E <em>(vaicitry\u0101t)</em> \u0438\u0445 \u0430\u043F\u043F\u0435\u0442\u0438\u0442\u043E\u0432 <em>(ruc\u012Bn\u0101m)</em>, \u0422\u044B <em>(tvam)</em> \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F <em>(asi)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(eka\u1E25)</em> \u0446\u0435\u043B\u044C\u044E \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F <em>(gamya\u1E25)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0435\u043C <em>(iva)</em> \u043E\u043A\u0435\u0430\u043D [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(ar\u1E47ava\u1E25)</em> \u0434\u043B\u044F \u0432\u043E\u0434 <em>(payas\u0101m)</em> --\u0442.e. \u0432\u043E\u0434\u044B \u0440\u0435\u043A, \u0434\u043E\u0436\u0434\u044C \u0438 \u0442.\u0434. \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0432\u043F\u0430\u0434\u0430\u044E\u0442 \u0432 \u043E\u043A\u0435\u0430\u043D--</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u092E\u0939\u094B\u0915\u094D\u0937\u0903 \u0916\u091F\u094D\u0935\u093E\u0919\u094D\u0917\u0902 \u092A\u0930\u0936\u0941\u0930\u091C\u093F\u0928\u0902 \u092D\u0938\u094D\u092E \u092B\u0923\u093F\u0928\u0903 \u0915\u092A\u093E\u0932\u0902 \u091A\u0947\u0924\u0940\u092F\u0924\u094D\u0924\u0935 \u0935\u0930\u0926 \u0924\u0928\u094D\u0924\u094D\u0930\u094B\u092A\u0915\u0930\u0923\u092E\u094D \u0964<br> \u0938\u0941\u0930\u093E\u0938\u094D\u0924\u093E\u0902 \u0924\u093E\u092E\u0943\u0926\u094D\u0927\u093F\u0902 \u0926\u0927\u0924\u093F \u0924\u0941 \u092D\u0935\u0926\u094D\u092D\u094D\u0930\u092A\u094D\u0930\u0923\u093F\u0939\u093F\u0924\u093E\u0902 \u0928 \u0939\u093F \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0930\u093E\u092E\u0902 \u0935\u093F\u0937\u092F\u092E\u0943\u0917\u0924\u0943\u0937\u094D\u0923\u093E \u092D\u094D\u0930\u092E\u092F\u0924\u093F \u0965\u096E\u0965</p><p class="trans">Mahok\u1E63a\u1E25 kha\u1E6Dv\u0101\u1E45ga\u1E41 para\u015Burajina\u1E41 bhasma pha\u1E47ina\u1E25 kap\u0101la\u1E41 cet\u012Byattava varada tantropakara\u1E47am \u0964<br> Sur\u0101st\u0101\u1E41 t\u0101m\u1E5Bddhi\u1E41 dadhati tu bhavadbhrapra\u1E47ihit\u0101\u1E41 na hi sv\u0101tm\u0101r\u0101ma\u1E41 vi\u1E63ayam\u1E5Bgat\u1E5B\u1E63\u1E47\u0101 bhramayati \u09658\u0965</p><p>\xAB\u041A\u0440\u0443\u043F\u043D\u044B\u0439 <em>(mah\u0101)</em> \u0431\u044B\u043A <em>(uk\u1E63a\u1E25)</em>, \u043F\u043E\u0441\u043E\u0445 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043E\u0441\u0442\u043E\u0432\u0430 \u043A\u0440\u043E\u0432\u0430\u0442\u0438 --\u0442.e. \u043F\u043E\u0441\u043E\u0445 \u0441 \u0447\u0435\u0440\u0435\u043F\u043E\u043C \u043D\u0430 \u043A\u043E\u043D\u0446\u0435-- <em>(kha\u1E6Dv\u0101\u1E45gam)</em>, \u0442\u043E\u043C\u0430\u0433\u0430\u0432\u043A <em>(para\u015Bu\u1E25)</em>, \u0448\u043A\u0443\u0440\u0430 \u0442\u0438\u0433\u0440\u0430 <em>(ajinam)</em>, \u043F\u0435\u043F\u0435\u043B <em>(bhasma)</em>, \u043A\u043E\u0431\u0440\u044B \u0441 \u0440\u0430\u0437\u0434\u0443\u0442\u044B\u043C\u0438 \u043A\u0430\u043F\u044E\u0448\u043E\u043D\u0430\u043C\u0438 <em>(pha\u1E47ina\u1E25)</em> \u0438 <em>(ca)</em> \u0447\u0435\u0440\u0435\u043F <em>(kap\u0101lam... iti)</em>\xBB -- iti \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043A\u0430\u0432\u044B\u0447\u043A\u0438--: \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u0438 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u044B <em>(iyat)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0422\u0432\u043E\u0435\u0439 <em>(tava)</em> \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u043E\u0439 <em>(tantra)</em> \u0443\u0442\u0432\u0430\u0440\u044C\u044E <em>(upakara\u1E47am)</em>, \u043E \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>! \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0431\u043E\u0433\u0438 <em>(sur\u0101\u1E25)</em> \u043F\u043E\u043B\u0443\u0447\u0430\u044E\u0442 <em>(dadhati)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 <em>(t\u0101m t\u0101m)</em> \xAB\u0440\u0438\u0434\u0434\u0445\u0438\xBB --\u0442.e. \u043F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u043D\u0438\u0435, \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u043E, \u0443\u0441\u043F\u0435\u0445 \u0438 \u0442.\u0434.-- <em>(\u1E5Bddhim)</em>, [\u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F \u043A\u0430\u043A \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442] \u0422\u0432\u043E\u0435\u0439 <em>(bhavat)</em> \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 <em>(pra\u1E47ihit\u0101m)</em> \u043D\u0430 [\u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u043C\u0435\u0436\u0434\u0443] \u0431\u0440\u043E\u0432\u044F\u043C\u0438 <em>(bhra)</em>. \u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u043C\u0438\u0440\u0430\u0436 <em>(m\u1E5Bgat\u1E5B\u1E63\u1E47\u0101)</em> \u0438\u0437 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(vi\u1E63aya)</em> \u043D\u0435 <em>(na)</em> \u0432\u043E\u043B\u043D\u0443\u0435\u0442 <em>(bhramayati)</em> \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(\u0101r\u0101mam)</em> \u0441\u0432\u043E\u0438\u043C <em>(sva)</em> \u0412\u044B\u0441\u0448\u0438\u043C \u042F <em>(\u0101tma)</em></p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u0927\u094D\u0930\u0941\u0935\u0902 \u0915\u0936\u094D\u091A\u093F\u0924\u094D \u0938\u0930\u094D\u0935\u0902 \u0938\u0915\u0932\u092E\u092A\u0930\u0938\u094D\u0924\u094D\u0935\u0927\u094D\u0930\u0941\u0935\u092E\u093F\u0926\u0902 \u092A\u0930\u094B \u0927\u094D\u0930\u094C\u0935\u094D\u092F\u093E\u0927\u094D\u0930\u094C\u0935\u094D\u092F\u0947 \u091C\u0917\u0924\u093F \u0917\u0926\u0924\u093F \u0935\u094D\u092F\u0938\u094D\u0924\u0935\u093F\u0937\u092F\u0947 \u0964<br> \u0938\u092E\u0938\u094D\u0924\u0947\u093D\u092A\u094D\u092F\u0947\u0924\u0938\u094D\u092E\u093F\u0928\u094D \u092A\u0941\u0930\u092E\u0925\u0928 \u0924\u0948\u0930\u094D\u0935\u093F\u0938\u094D\u092E\u093F\u0924 \u0907\u0935 \u0938\u094D\u0924\u0941\u0935\u091E\u094D\u091C\u093F\u0939\u094D\u0930\u0947\u092E\u093F \u0924\u094D\u0935\u093E\u0902 \u0928 \u0916\u0932\u0941 \u0928\u0928\u0941 \u0927\u0943\u0937\u094D\u091F\u093E \u092E\u0941\u0916\u0930\u0924\u093E \u0965\u096F\u0965</p><p class="trans">Dhruva\u1E41 ka\u015Bcit sarva\u1E41 sakalamaparastvadhruvamida\u1E41 paro dhrauvy\u0101dhrauvye jagati gadati vyastavi\u1E63aye \u0964<br> Samaste&#39;pyetasmin puramathana tairvismita iva stuva\xF1jihremi tv\u0101\u1E41 na khalu nanu dh\u1E5B\u1E63\u1E6D\u0101 mukharat\u0101 \u09659\u0965</p><p>\u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ka\u015Bcid)</em> [\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0442, \u0447\u0442\u043E] \u0432\u0441\u0451 <em>(sarvam)</em> \u0432\u0435\u0447\u043D\u043E <em>(dhruvam)</em>. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0434\u0440\u0443\u0433\u0438\u0435 <em>(apara\u1E25)</em> [\u0433\u043E\u0432\u043E\u0440\u044F\u0442, \u0447\u0442\u043E] \u0432\u0441\u0451 <em>(sakalam)</em> \u044D\u0442\u043E <em>(idam)</em> \u043D\u0435 \u0432\u0435\u0447\u043D\u043E <em>(adhruvam)</em>. [\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C] \u0442\u0440\u0435\u0442\u044C\u0438 <em>(para\u1E25)</em> \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u044E\u0442 <em>(gadati)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430 <em>(jagati)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(vyasta)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 <em>(vi\u1E63aye)</em>, \u0447\u0442\u043E \u043E\u043D \u043A\u0430\u043A \u0432\u0435\u0447\u043D\u044B\u0439 <em>(dhrauvya)</em>, \u0442\u0430\u043A \u0438 \u044D\u0444\u0435\u043C\u0435\u0440\u043D\u044B\u0439 --adhrauvya-- <em>(adhrauvye)</em>. \u041E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(mathana)</em> <em>(\u0442\u0440\u0451\u0445)</em> \u0433\u043E\u0440\u043E\u0434\u043E\u0432 <em>(pura)</em>! \u0423\u0434\u0438\u0432\u043B\u0451\u043D\u043D\u044B\u0439 <em>(vismita\u1E25)</em>, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C <em>(iva)</em>, \u0432\u0441\u0435\u043C\u0438 \u044D\u0442\u0438\u043C\u0438 [\u0442\u043E\u0447\u043A\u0430\u043C\u0438 \u0437\u0440\u0435\u043D\u0438\u044F] <em>(tai\u1E25)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0433\u043E <em>(samaste)</em> \u044D\u0442\u043E\u0433\u043E <em>(\u0421\u043E\u0437\u0434\u0430\u043D\u0438\u044F)</em> <em>(api etasmin)</em>, \u042F \u043D\u0435 \u0441\u0442\u044B\u0436\u0443\u0441\u044C <em>(jihremi... na)</em> \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u0442\u044C <em>(stuvan)</em> \u0422\u0435\u0431\u044F <em>(tv\u0101m)</em>... [\u041C\u043E\u044F] \u0440\u0430\u0437\u0433\u043E\u0432\u043E\u0440\u0447\u0438\u0432\u043E\u0441\u0442\u044C <em>(mukharat\u0101)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(khalu nanu)</em> \u0434\u0435\u0440\u0437\u043A\u0430 <em>(dh\u1E5B\u1E63\u1E6D\u0101)</em>!</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">\u0924\u0935\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u0902 \u092F\u0924\u094D\u0928\u093E\u0926\u094D\u092F\u0926\u0941\u092A\u0930\u093F \u0935\u093F\u0930\u093F\u091E\u094D\u091A\u093F\u0930\u094D\u0939\u0930\u093F\u0930\u0927\u0903 \u092A\u0930\u093F\u091A\u094D\u091B\u0947\u0924\u094D\u0924\u0941\u0902 \u092F\u093E\u0924\u093E\u0935\u0928\u0932\u092E\u0928\u0932\u0938\u094D\u0915\u0928\u094D\u0927\u0935\u092A\u0941\u0937\u0903 \u0964<br> \u0924\u0924\u094B \u092D\u0915\u094D\u0924\u093F\u0936\u094D\u0930\u0926\u094D\u0927\u093E\u092D\u0930\u0917\u0941\u0930\u0941\u0917\u0943\u0923\u0926\u094D\u092D\u094D\u092F\u093E\u0902 \u0917\u093F\u0930\u093F\u0936 \u092F\u0924\u094D\u0938\u094D\u0935\u092F\u0902 \u0924\u0938\u094D\u0925\u0947 \u0924\u093E\u092D\u094D\u092F\u093E\u0902 \u0924\u0935 \u0915\u093F\u092E\u0928\u0941\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u0928 \u092B\u0932\u0924\u093F \u0965\u0967\u0966\u0965</p><p class="trans">Tavai\u015Bvarya\u1E41 yatn\u0101dyadupari viri\xF1cirhariradha\u1E25 paricchetu\u1E41 y\u0101t\u0101vanalamanalaskandhavapu\u1E63a\u1E25 \u0964<br> Tato bhakti\u015Braddh\u0101bharagurug\u1E5B\u1E47adbhy\u0101\u1E41 gir\u012B\u015Ba yatsvaya\u1E41 tasthe t\u0101bhy\u0101\u1E41 tava kimanuv\u1E5Bttirna phalati \u096510\u0965</p><p>Brahm\u0101 --\u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044C-- <em>(viri\xF1ci\u1E25)</em> \u0441\u0432\u0435\u0440\u0445\u0443 <em>(yad-upari)</em> <em>(\u0438)</em> Vi\u1E63\u1E47u --\u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0439-- <em>(hari\u1E25)</em> \u0441\u043D\u0438\u0437\u0443 <em>(adhas)</em> \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u043B\u0438 <em>(y\u0101tau)</em> \u0441 \u0443\u0441\u0438\u043B\u0438\u0435\u043C <em>(yatn\u0101t)</em> \u0442\u043E\u0447\u043D\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0442\u044C <em>(paricchettum)</em> \u0422\u0432\u043E\u0439 <em>(tava)</em> \u0421\u0443\u0432\u0435\u0440\u0435\u043D\u0438\u0442\u0435\u0442 \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E <em>(ai\u015Bvaryam)</em>, [\u043A\u043E\u0433\u0434\u0430 \u0422\u044B \u043F\u0440\u0438\u043D\u044F\u043B] \u0444\u043E\u0440\u043C\u0443 <em>(vapu\u1E63a\u1E25)</em> \u043E\u0433\u043D\u0435\u043D\u043D\u043E\u0433\u043E <em>(anala)</em> \u0441\u0442\u043E\u043B\u0431\u0430 <em>(skandha)</em>, [\u043D\u043E] \u044D\u0442\u043E\u0433\u043E \u0431\u044B\u043B\u043E \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E --\u0442.e. \u0443 \u043D\u0438\u0445 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u043E\u0441\u044C-- <em>(analam)</em>. [\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435] \u043F\u043E\u0442\u043E\u043C <em>(tatas)</em>, [\u0442\u043E\u043B\u044C\u043A\u043E] \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043E\u0431\u0430 \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u043B\u0438 [\u0428\u0438\u0432\u0443] <em>(g\u1E5B\u1E47adbhy\u0101m)</em> \u0432 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(guru)</em> \u0441 <em>(bhara)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(bhakti)</em> \u0438 \u0432\u0435\u0440\u043E\u0439 <em>(\u015Braddh\u0101)</em>, \u043E Gir\u012B\u015Ba --\u0442.e. \xAB\u0413\u043E\u0440\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C\xBB, \u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B-- <em>(giri-\u012B\u015Ba)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(yad)</em> \u041E\u043D --\u0428\u0438\u0432\u0430-- \u043F\u043E\u043A\u0430\u0437\u0430\u043B <em>(tasthe)</em> \u0415\u0433\u043E [\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443] <em>(svayam)</em> \u0438\u043C \u043E\u0431\u043E\u0438\u043C <em>(t\u0101bhy\u0101m)</em>. \u041A\u0430\u043A\u043E\u0435 <em>(kim)</em> \u0443\u0432\u0430\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 <em>(anuv\u1E5Btti\u1E25)</em> \u0432 \u0447\u0435\u0441\u0442\u044C \u0422\u0435\u0431\u044F <em>(tava)</em> [\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u0442\u043E\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043B\u0438 \u0411\u0440\u0430\u0445\u043C\u0430\u0430 \u0438 \u0412\u0438\u0448\u043D\u0443] \u043D\u0435 \u043F\u0440\u0438\u043D\u0435\u0441\u0451\u0442 [\u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432] \u043F\u043B\u043E\u0434\u043E\u0432?</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">\u0905\u092F\u0924\u094D\u0928\u093E\u0926\u093E\u092A\u093E\u0926\u094D\u092F \u0924\u094D\u0930\u093F\u092D\u0941\u0935\u0928\u092E\u0935\u0948\u0930\u0935\u094D\u092F\u0924\u093F\u0915\u0930\u0902 \u0926\u0936\u093E\u0938\u094D\u092F\u094B \u092F\u0926\u094D\u092C\u093E\u0939\u0942\u0928\u092D\u0943\u0924 \u0930\u0923\u0915\u0923\u094D\u0921\u0942\u092A\u0930\u0935\u0936\u093E\u0928\u094D \u0964<br> \u0936\u093F\u0930\u0903\u092A\u0926\u094D\u092E\u0936\u094D\u0930\u0947\u0923\u0940\u0930\u091A\u093F\u0924\u091A\u0930\u0923\u093E\u092E\u094D\u092D\u094B\u0930\u0941\u0939\u092C\u0932\u0947\u0903 \u0938\u094D\u0925\u093F\u0930\u093E\u092F\u093E\u0938\u094D\u0924\u094D\u0935\u0926\u094D\u092D\u0915\u094D\u0924\u0947\u0938\u094D\u0924\u094D\u0930\u093F\u092A\u0941\u0930\u0939\u0930 \u0935\u093F\u0938\u094D\u092B\u0942\u0930\u094D\u091C\u093F\u0924\u092E\u093F\u0926\u092E\u094D \u0965\u0967\u0967\u0965</p><p class="trans">Ayatn\u0101d\u0101p\u0101dya tribhuvanamavairavyatikara\u1E41 da\u015B\u0101syo yadb\u0101h\u016Bnabh\u1E5Bta ra\u1E47aka\u1E47\u1E0D\u016Bparava\u015B\u0101n \u0964<br> \u015Aira\u1E25padma\u015Bre\u1E47\u012Bracitacara\u1E47\u0101mbhoruhabale\u1E25 sthir\u0101y\u0101stvadbhaktestripurahara visph\u016Brjitamidam \u096511\u0965</p><p>\u0411\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u0439 <em>(ayatn\u0101t)</em> \u0438\u0437\u0431\u0430\u0432\u0438\u0432\u0448\u0438\u0441\u044C \u043E\u0442 \u0432\u0441\u0435\u0433\u043E \u0432\u0440\u0430\u0436\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F --\u0442.e. \u043E\u0442 \u0432\u0441\u0435\u0445 \u0432\u0440\u0430\u0433\u043E\u0432 \u0438\u0437 \u0442\u0440\u0451\u0445 \u043C\u0438\u0440\u043E\u0432-- \u0434\u043E\u0441\u043B. \xAB\u043F\u0440\u0438\u0432\u0435\u0434\u044F <em>(\u0101p\u0101dya)</em> \u0442\u0440\u0438 <em>(tri)</em> \u043C\u0438\u0440\u0430 <em>(bhuvanam)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0431\u0435\u0437 <em>(a)</em> \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0432\u0440\u0430\u0436\u0435\u0441\u043A\u043E\u0433\u043E <em>(vaira)</em> \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(vyatikaram)</em> \xBB-- <em>(\u0101p\u0101dya tribhuvanam avairavyatikaram)</em>, \u0443 [\u0434\u0435\u043C\u043E\u043D\u0430] \u0441 \u0434\u0435\u0441\u044F\u0442\u044C\u044E \u0440\u0442\u0430\u043C\u0438 --R\u0101va\u1E47a, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0433\u043E \u0432\u0440\u0430\u0433\u0430 R\u0101macandra-- <em>(da\u015Ba-\u0101sya\u1E25)</em> \u0435\u0433\u043E <em>(yad)</em> <em>(\u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C)</em> \u0440\u0443\u043A <em>(b\u0101h\u016Bn... abh\u1E5Bta)</em> <em>(\u0432\u0441\u0451 \u0435\u0449\u0451)</em> \u043E\u0434\u043E\u043B\u0435\u0432\u0430\u043B\u043E <em>(parava\u015B\u0101n)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u0435 --\u0434\u043E\u0441\u043B. \xAB\u043E\u043D\u0438 \u0447\u0435\u0441\u0430\u043B\u0438\u0441\u044C\xBB-- <em>(ka\u1E47\u1E0D\u016B)</em> \u0441\u0440\u0430\u0436\u0435\u043D\u0438\u044F <em>(ra\u1E47a)</em>. [\u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E], \u043E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(hara)</em> \u0442\u0440\u0451\u0445 <em>(tri)</em> \u0433\u043E\u0440\u043E\u0434\u043E\u0432 <em>(pura)</em>!, <em>(R\u0101va\u1E47a)</em> \u0441\u043B\u043E\u0436\u0438\u043B <em>(racita)</em> \u0432 \u0440\u044F\u0434 <em>(\u015Bre\u1E47\u012B)</em> [\u0435\u0433\u043E \u0434\u0435\u0441\u044F\u0442\u044C] \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0433\u043E\u043B\u043E\u0432 <em>(\u015Biras-padma)</em> \u0432 \u0432\u0438\u0434\u0435 \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u044F --bali-- <em>(bale\u1E25)</em> \u043A [\u0422\u0432\u043E\u0438\u043C] \u0441\u0442\u043E\u043F\u0430\u043C <em>(cara\u1E47a)</em>, [\u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u043C] \u043A\u0430\u043A \u043B\u043E\u0442\u043E\u0441 <em>(ambhoruha)</em>. [\u041E\u043D \u0441\u0434\u0435\u043B\u0430\u043B \u044D\u0442\u043E] \u0438\u0437-\u0437\u0430 [\u0441\u0432\u043E\u0435\u0439] \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0439 <em>(sthir\u0101y\u0101\u1E25)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bhakte\u1E25)</em> \u0422\u0435\u0431\u0435 <em>(tvat)</em>. \u042D\u0442\u043E\u0442 [\u0430\u043A\u0442 \u0441\u0434\u0430\u0447\u0438] <em>(idam)</em> \u0441\u043B\u0443\u0447\u0438\u043B\u0441\u044F \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E <em>(visph\u016Brjitam)</em></p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">\u0905\u092E\u0941\u0937\u094D\u092F \u0924\u094D\u0935\u0924\u094D\u0938\u0947\u0935\u093E\u0938\u092E\u0927\u093F\u0917\u0924\u0938\u093E\u0930\u0902 \u092D\u0941\u091C\u0935\u0928\u0902 \u092C\u0932\u093E\u0924\u094D\u0915\u0948\u0932\u093E\u0938\u0947\u093D\u092A\u093F \u0924\u094D\u0935\u0926\u0927\u093F\u0935\u0938\u0924\u094C \u0935\u093F\u0915\u094D\u0930\u092E\u092F\u0924\u0903 \u0964<br> \u0905\u0932\u092D\u094D\u092F\u093E \u092A\u093E\u0924\u093E\u0932\u0947\u093D\u092A\u094D\u092F\u0932\u0938\u091A\u0932\u093F\u0924\u093E\u0919\u094D\u0917\u0941\u0937\u094D\u0920\u0936\u093F\u0930\u0938\u093F \u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093E \u0924\u094D\u0935\u092F\u094D\u092F\u093E\u0938\u0940\u0926\u094D\u0927\u094D\u0930\u0941\u0935\u092E\u0941\u092A\u091A\u093F\u0924\u094B \u092E\u0941\u0939\u094D\u092F\u0924\u093F \u0916\u0932\u0903 \u0965\u0967\u0968\u0965</p><p class="trans">Amu\u1E63ya tvatsev\u0101samadhigatas\u0101ra\u1E41 bhujavana\u1E41 bal\u0101tkail\u0101se&#39;pi tvadadhivasatau vikramayata\u1E25 \u0964<br> Alabhy\u0101 p\u0101t\u0101le&#39;pyalasacalit\u0101\u1E45gu\u1E63\u1E6Dha\u015Birasi prati\u1E63\u1E6Dh\u0101 tvayy\u0101s\u012Bddhruvamupacito muhyati khala\u1E25 \u096512\u0965</p><p>[\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435,] \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E [\u0441\u0430\u043C\u043E\u0433\u043E \u0434\u0435\u043C\u043E\u043D\u0430] <em>(amu\u1E63ya)</em> \u043D\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u043B\u043E\u0441\u044C <em>(alabhy\u0101... \u0101s\u012Bt)</em> \u043C\u0435\u0441\u0442\u0430 \u043F\u043E\u043A\u043E\u044F <em>(prati\u1E63\u1E6Dh\u0101)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u043D\u0438\u0437\u0448\u0435\u043C \u0430\u0434\u0443 --\u0438\u043B\u0438 \u0432 \xAB\u043D\u0438\u0437\u0448\u0435\u0439 \u043E\u0431\u043B\u0430\u0441\u0442\u0438\xBB-- <em>(p\u0101t\u0101le)</em> \u043A\u043E\u0433\u0434\u0430 (\u0422\u044B) \u043F\u0440\u0430\u0437\u0434\u043D\u043E <em>(alasa)</em> \u043F\u043E\u0448\u0435\u0432\u0435\u043B\u0438\u043B <em>(calita)</em> \u043A\u043E\u043D\u0447\u0438\u043A\u043E\u043C --\u015Biras-- <em>(\u015Birasi)</em> \u0422\u0432\u043E\u0435\u0433\u043E --tava-- <em>(tvayi)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043F\u0430\u043B\u044C\u0446\u0430 \u043D\u043E\u0433\u0438 <em>(a\u1E45gu\u1E63\u1E6Dha)</em>, (\u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D) \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> [\u0440\u0430\u043D\u0435\u0435] \u043E\u0442\u043F\u0440\u0430\u0432\u0438\u043B\u0441\u044F \u043C\u0430\u0440\u0448\u0435\u043C <em>(vikramayata\u1E25)</em> \u043D\u0430 \u041A\u0430\u0439\u043B\u0430\u0441\u0443 <em>(kail\u0101se)</em>, \u0422\u0432\u043E\u044E <em>(tvat)</em> \u041E\u0431\u0438\u0442\u0435\u043B\u044C --adhivasati-- <em>(adhivasatau)</em>, [\u0432 \u043F\u043E\u043F\u044B\u0442\u043A\u0435 \u0437\u0430\u0445\u0432\u0430\u0442\u0438\u0442\u044C \u0435\u0451] \u0441\u0438\u043B\u043E\u0439 <em>(bal\u0101t)</em> \u0435\u0433\u043E [\u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0445] \u0440\u0443\u043A <em>(bhuja)</em>, \u043F\u043E\u0445\u043E\u0436\u0438\u0445 \u043D\u0430 \u043B\u0435\u0441 <em>(vanam)</em>, \u0447\u044C\u044F \u0441\u0438\u043B\u0430 <em>(s\u0101ram)</em> \u0431\u044B\u043B\u0430 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u0430 <em>(samadhigatam)</em> \u0441\u043B\u0443\u0436\u0435\u043D\u0438\u0435\u043C <em>(sev\u0101)</em> \u0422\u0435\u0431\u0435 <em>(tvat)</em>. \u041E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u043E <em>(dhruvam)</em>, \u0431\u0435\u0441\u0448\u0430\u0431\u0430\u0448\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A <em>(khala\u1E25)</em> \u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(muhyati)</em> \u0438\u0437-\u0437\u0430 \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u0430 <em>(upacita\u1E25)</em></p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">\u092F\u0926\u0943\u0926\u094D\u0927\u093F\u0902 \u0938\u0941\u0924\u094D\u0930\u093E\u092E\u094D\u0923\u094B \u0935\u0930\u0926 \u092A\u0930\u092E\u094B\u091A\u094D\u091A\u0948\u0930\u092A\u093F \u0938\u0924\u0940\u092E\u0927\u0936\u094D\u091A\u0915\u094D\u0930\u0947 \u092C\u093E\u0923\u0903 \u092A\u0930\u093F\u091C\u0928\u0935\u093F\u0927\u0947\u092F\u0924\u094D\u0930\u093F\u092D\u0941\u0935\u0928\u0903 \u0964<br> \u0928 \u0924\u091A\u094D\u091A\u093F\u0924\u094D\u0930\u0902 \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u0935\u0930\u093F\u0935\u0938\u093F\u0924\u0930\u093F \u0924\u094D\u0935\u091A\u094D\u091A\u0930\u0923\u092F\u094B\u0930\u094D\u0928 \u0915\u0938\u094D\u092F\u093E \u0909\u0928\u094D\u0928\u0924\u094D\u092F\u0948 \u092D\u0935\u0924\u093F \u0936\u093F\u0930\u0938\u0938\u094D\u0924\u094D\u0935\u092F\u094D\u092F\u0935\u0928\u0924\u093F\u0903 \u0965\u0967\u0969\u0965</p><p class="trans">Yad\u1E5Bddhi\u1E41 sutr\u0101m\u1E47o varada paramoccairapi sat\u012Bmadha\u015Bcakre b\u0101\u1E47a\u1E25 parijanavidheyatribhuvana\u1E25 \u0964<br> Na taccitra\u1E41 tasminvarivasitari tvaccara\u1E47ayorna kasy\u0101 unnatyai bhavati \u015Birasastvayyavanati\u1E25 \u096513\u0965</p><p>\u041E \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>! \u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F <em>(yad)</em> B\u0101\u1E47a <em>(b\u0101\u1E47a\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043B \u0442\u0440\u0438 <em>(tri)</em> \u043C\u0438\u0440\u0430 <em>(bhuvana\u1E25)</em> \u0432 \u043F\u043E\u0441\u043B\u0443\u0448\u043D\u044B\u0445 <em>(vidheya)</em> \u0441\u043B\u0443\u0433 <em>(parijana)</em>, [\u043E\u043D \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u043B\u0441\u044F] \u0434\u0430\u0436\u0435 <em>(api)</em> \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u043E\u043C <em>(\u1E5Bddhim)</em> \u0421\u0443\u0442\u0440\u0430\u0430\u043C\u0430\u043D\u0430 --\u044D\u043F\u0438\u0442\u0435\u0442 \u0418\u043D\u0434\u0440\u044B, \u0431\u043E\u0433\u0430 \u0440\u0430\u044F, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0445\u043E\u0440\u043E\u0448\u043E \u0437\u0430\u0449\u0438\u0449\u0430\u044E\u0449\u0438\u0439\xBB-- <em>(sutr\u0101m\u1E47a\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sat\u012Bm)</em> \u043A\u0440\u0430\u0439\u043D\u0435 <em>(uccais)</em> \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u044B\u043C <em>(parama)</em> \u0432 \u043D\u0438\u0436\u043D\u0435\u0439 <em>(adhas)</em> \u0440\u0435\u0430\u043B\u0438\u0438, [\u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043E\u043D \u043F\u0440\u0430\u0432\u0438\u043B \u043A\u0430\u043A \u0446\u0430\u0440\u044C] <em>(cakre)</em>. \u042D\u0442\u043E <em>(tad)</em> (\u0441\u043E\u0432\u0441\u0435\u043C) \u043D\u0435 <em>(na)</em> \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(citram)</em>, [\u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E] \u0442\u043E\u0442 [\u0446\u0430\u0440\u044C \u0434\u0435\u043C\u043E\u043D\u043E\u0432] <em>(tasmin)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u043B\u0441\u044F <em>(varivasitari)</em> \u0422\u0432\u043E\u0438\u043C <em>(tvat)</em> \u0441\u0442\u043E\u043F\u0430\u043C <em>(cara\u1E47ayo\u1E25)</em>. \u041A \u043A\u0430\u043A\u043E\u043C\u0443 \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u0443 <em>(kasyai unnatyai)</em> \u0441\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 <em>(avanati\u1E25)</em> <em>(\u0441\u0432\u043E\u0435\u0439)</em> \u0433\u043E\u043B\u043E\u0432\u044B <em>(\u015Birasa\u1E25)</em> \u043F\u0435\u0440\u0435\u0434 \u0422\u043E\u0431\u043E\u0439 <em>(tvayi)</em> \u043D\u0435 <em>(na)</em> \u043F\u0440\u0438\u0432\u0435\u0434\u0451\u0442 <em>(bhavati)</em>? --\u0442.e. \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u0430, \u043D\u0435\u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0433\u043E \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u0441\u043A\u043B\u043E\u043D\u044F\u0435\u0442 \u0441\u0432\u043E\u044E \u0433\u043E\u043B\u043E\u0432\u0443 \u043F\u0435\u0440\u0435\u0434 \u0422\u043E\u0431\u043E\u0439--</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u0905\u0915\u093E\u0923\u094D\u0921\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0923\u094D\u0921\u0915\u094D\u0937\u092F\u091A\u0915\u093F\u0924\u0926\u0947\u0935\u093E\u0938\u0941\u0930\u0915\u0943\u092A\u093E\u0935\u093F\u0927\u0947\u092F\u0938\u094D\u092F\u093E\u0938\u0940\u0926\u094D\u092F\u0938\u094D\u0924\u094D\u0930\u093F\u0928\u092F\u0928 \u0935\u093F\u0937\u0902 \u0938\u0902\u0939\u0943\u0924\u0935\u0924\u0903 \u0964<br> \u0938 \u0915\u0932\u094D\u092E\u093E\u0937\u0903 \u0915\u0923\u094D\u0920\u0947 \u0924\u0935 \u0928 \u0915\u0941\u0930\u0941\u0924\u0947 \u0928 \u0936\u094D\u0930\u093F\u092F\u092E\u0939\u094B \u0935\u093F\u0915\u093E\u0930\u094B\u093D\u092A\u093F \u0936\u094D\u0932\u093E\u0918\u094D\u092F\u094B \u092D\u0941\u0935\u0928\u092D\u092F\u092D\u0919\u094D\u0917\u0935\u094D\u092F\u0938\u0928\u093F\u0928\u0903 \u0965\u0967\u096A\u0965</p><p class="trans">Ak\u0101\u1E47\u1E0Dabrahm\u0101\u1E47\u1E0Dak\u1E63ayacakitadev\u0101surak\u1E5Bp\u0101vidheyasy\u0101s\u012Bdyastrinayana vi\u1E63a\u1E41 sa\u1E41h\u1E5Btavata\u1E25 \u0964<br> Sa kalm\u0101\u1E63a\u1E25 ka\u1E47\u1E6Dhe tava na kurute na \u015Briyamaho vik\u0101ro&#39;pi \u015Bl\u0101ghyo bhuvanabhayabha\u1E45gavyasanina\u1E25 \u096514\u0965</p><p>\u041E \u0422\u0440\u0451\u0445\u0433\u043B\u0430\u0437\u044B\u0439 <em>(trinayana)</em>! \u0422\u043E <em>(sa\u1E25)</em> [\u0441\u0438\u043D\u0435\u0435] \u043F\u044F\u0442\u043D\u043E <em>(kalm\u0101\u1E63a\u1E25)</em> \u043D\u0430 \u0422\u0432\u043E\u0451\u043C <em>(tava)</em> \u0433\u043E\u0440\u043B\u0435 <em>(ka\u1E47\u1E6Dhe)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u043F\u043E\u044F\u0432\u0438\u043B\u043E\u0441\u044C <em>(\u0101s\u012Bt)</em> \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E [\u0422\u044B] \u0443\u0434\u0435\u0440\u0436\u0430\u043B [\u0442\u0430\u043C] <em>(sa\u1E41h\u1E5Btavata\u1E25)</em> \u044F\u0434 [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A <em>K\u0101lak\u016B\u1E6Da</em>] <em>(vi\u1E63am)</em>, \u043A\u043E\u0433\u0434\u0430 \u0431\u044B\u043B \u043E\u0445\u0432\u0430\u0447\u0435\u043D <em>(vidheyasya)</em> \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435\u043C <em>(k\u1E5Bp\u0101)</em> \u043A \u0431\u043E\u0433\u0430\u043C <em>(deva)</em> \u0438 \u0434\u0435\u043C\u043E\u043D\u0430\u043C <em>(asura)</em>, \u043D\u0430\u043F\u0443\u0433\u0430\u043D\u043D\u044B\u043C <em>(cakita)</em> \u043D\u0435\u043E\u0436\u0438\u0434\u0430\u043D\u043D\u044B\u043C <em>(ak\u0101\u1E47\u1E0Da)</em> \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435\u043C <em>(k\u1E63aya)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(brahm\u0101\u1E47\u1E0Da)</em>, \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(na... na)</em> \u0443\u043A\u0440\u0430\u0448\u0430\u0435\u0442 [\u0422\u0435\u0431\u044F] <em>(kurute...\u015Briyam)</em>. \u0410\u0445 <em>(aho)</em>! \u0414\u0430\u0436\u0435 <em>(api)</em> [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435] \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0435 \u0432 \u0442\u0435\u043B\u0435 <em>(vik\u0101ra\u1E25)</em> \u0442\u043E\u0433\u043E [\u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0430], \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u0431\u043E\u0436\u0430\u0435\u0442 <em>(vyasanina\u1E25)</em> \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u0442\u044C <em>(bha\u1E45ga)</em> \u0441\u0442\u0440\u0430\u0445 <em>(bhaya)</em> \u0432\u043E \u0432\u0441\u0451\u043C \u043C\u0438\u0440\u0435 <em>(bhuvana)</em>, \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u043E \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u044F <em>(\u015Bl\u0101ghya\u1E25)</em></p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u0905\u0938\u093F\u0926\u094D\u0927\u093E\u0930\u094D\u0925\u093E \u0928\u0948\u0935 \u0915\u094D\u0935\u091A\u093F\u0926\u092A\u093F \u0938\u0926\u0947\u0935\u093E\u0938\u0941\u0930\u0928\u0930\u0947 \u0928\u093F\u0935\u0930\u094D\u0924\u0928\u094D\u0924\u0947 \u0928\u093F\u0924\u094D\u092F\u0902 \u091C\u0917\u0924\u093F \u091C\u092F\u093F\u0928\u094B \u092F\u0938\u094D\u092F \u0935\u093F\u0936\u093F\u0916\u093E\u0903 \u0964<br> \u0938 \u092A\u0936\u094D\u092F\u0928\u094D\u0928\u0940\u0936 \u0924\u094D\u0935\u093E\u092E\u093F\u0924\u0930\u0938\u0941\u0930\u0938\u093E\u0927\u093E\u0930\u0923\u092E\u092D\u0942\u0924\u094D\u0938\u094D\u092E\u0930\u0903 \u0938\u094D\u092E\u0930\u094D\u0924\u0935\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0928 \u0939\u093F \u0935\u0936\u093F\u0937\u0941 \u092A\u0925\u094D\u092F\u0903 \u092A\u0930\u093F\u092D\u0935\u0903 \u0965\u0967\u096B\u0965</p><p class="trans">Asiddh\u0101rth\u0101 naiva kvacidapi sadev\u0101suranare nivartante nitya\u1E41 jagati jayino yasya vi\u015Bikh\u0101\u1E25 \u0964<br> Sa pa\u015Byann\u012B\u015Ba tv\u0101mitarasuras\u0101dh\u0101ra\u1E47amabh\u016Btsmara\u1E25 smartavy\u0101tm\u0101 na hi va\u015Bi\u1E63u pathya\u1E25 paribhava\u1E25 \u096515\u0965</p><p>\u041E \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Ba)</em>! \u041E\u043D --K\u0101madeva, \u0431\u043E\u0433 \u043B\u044E\u0431\u0432\u0438-- <em>(sa\u1E25)</em>, \u0447\u044C\u0438 <em>(yasya)</em> \u0441\u0442\u0440\u0435\u043B\u044B <em>(vi\u015Bikh\u0101\u1E25)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> \u043F\u043E\u0431\u0435\u0434\u043E\u043D\u043E\u0441\u043D\u044B <em>(jayina\u1E25)</em> \u0438 \u043D\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0430\u044E\u0442 \u0446\u0435\u043B\u0438 <em>(asiddha-arth\u0101\u1E25... nivartante)</em> \u043D\u0438\u0433\u0434\u0435 <em>(na eva kvacid-api)</em> \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(jagati)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u043C <em>(sa)</em> \u0438\u0437 \u0431\u043E\u0433\u043E\u0432 <em>(deva)</em>, \u0434\u0435\u043C\u043E\u043D\u043E\u0432 <em>(asura)</em> <em>(\u0438)</em> \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 --nara-- <em>(nare)</em>, [\u043F\u0440\u043E\u0441\u0442\u043E] \u0441\u0447\u0438\u0442\u0430\u043B <em>(pa\u015Byan)</em> \u0422\u0435\u0431\u044F <em>(tv\u0101m)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C <em>(s\u0101dh\u0101ra\u1E47am)</em> \u0431\u043E\u043B\u0435\u0435 \u043D\u0438\u0437\u043A\u043E\u043C\u0443 <em>(itara)</em> \u0431\u043E\u0433\u0443 <em>(sura)</em>, \u0438 <em>(\u043F\u043E\u044D\u0442\u043E\u043C\u0443)</em> \u0441\u0442\u0430\u043B <em>(abh\u016Bt)</em> \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435\u043C <em>(smara\u1E25)</em>, \u0436\u0438\u0432\u0443\u0449\u0438\u043C [\u0442\u043E\u043B\u044C\u043A\u043E] \u0432 \u043F\u0430\u043C\u044F\u0442\u0438 [\u043B\u044E\u0434\u0435\u0439] <em>(smartavya-\u0101tm\u0101)</em>. \u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u043E\u0441\u043A\u043E\u0440\u0431\u043B\u0435\u043D\u0438\u0435 <em>(paribhava\u1E25)</em>, [\u043D\u0430\u043D\u0435\u0441\u0451\u043D\u043D\u043E\u0435] \u043E\u0431\u0443\u0437\u0434\u0430\u0432\u0448\u0438\u043C \u0441\u0435\u0431\u044F <em>(va\u015Bi\u1E63u)</em>, \u043D\u0435 <em>(na)</em> \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u0431\u043B\u0430\u0433\u043E\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E <em>(pathya\u1E25)</em></p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u092E\u0939\u0940 \u092A\u093E\u0926\u093E\u0918\u093E\u0924\u093E\u0926\u094D\u0935\u094D\u0930\u091C\u0924\u093F \u0938\u0939\u0938\u093E \u0938\u0902\u0936\u092F\u092A\u0926\u0902 \u092A\u0926\u0902 \u0935\u093F\u0937\u094D\u0923\u094B\u0930\u094D\u092D\u094D\u0930\u093E\u092E\u094D\u092F\u0926\u094D\u092D\u0941\u091C\u092A\u0930\u093F\u0918\u0930\u0941\u0917\u094D\u0923\u0917\u094D\u0930\u0939\u0917\u0923\u092E\u094D \u0964<br> \u092E\u0941\u0939\u0941\u0930\u094D\u0926\u094D\u092F\u094C\u0930\u094D\u0926\u094C\u0938\u094D\u0925\u094D\u092F\u0902 \u092F\u093E\u0924\u094D\u092F\u0928\u093F\u092D\u0943\u0924\u091C\u091F\u093E\u0924\u093E\u0921\u093F\u0924\u0924\u091F\u093E \u091C\u0917\u0926\u094D\u0930\u0915\u094D\u0937\u093E\u092F\u0948 \u0924\u094D\u0935\u0902 \u0928\u091F\u0938\u093F \u0928\u0928\u0941 \u0935\u093E\u092E\u0948\u0935 \u0935\u093F\u092D\u0941\u0924\u093E \u0965\u0967\u096C\u0965</p><p class="trans">Mah\u012B p\u0101d\u0101gh\u0101t\u0101dvrajati sahas\u0101 sa\u1E41\u015Bayapada\u1E41 pada\u1E41 vi\u1E63\u1E47orbhr\u0101myadbhujaparigharug\u1E47agrahaga\u1E47am \u0964<br> Muhurdyaurdausthya\u1E41 y\u0101tyanibh\u1E5Btaja\u1E6D\u0101t\u0101\u1E0Ditata\u1E6D\u0101 jagadrak\u1E63\u0101yai tva\u1E41 na\u1E6Dasi nanu v\u0101maiva vibhut\u0101 \u096516\u0965</p><p>\u0418\u0437-\u0437\u0430 \u0443\u0434\u0430\u0440\u0430 <em>(\u0101gh\u0101t\u0101t)</em> [\u0422\u0432\u043E\u0438\u0445] \u0441\u0442\u043E\u043F <em>(p\u0101da)</em>, \u0437\u0435\u043C\u043B\u044F <em>(mah\u012B)</em> \u0432\u0434\u0440\u0443\u0433 <em>(sahas\u0101)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 \u0441\u043E\u043C\u043D\u0435\u0432\u0430\u0442\u044C\u0441\u044F <em>(vrajati... sa\u1E41\u015Baya-padam)</em>. [\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u0432\u0441\u0435] \u0442\u0440\u0438 \u043C\u0438\u0440\u0430 --\u0434\u043E\u0441\u043B. \xAB[\u0442\u0440\u0438] \u0448\u0430\u0433\u0430 Vi\u1E63\u1E47u\xBB-- <em>(padam vi\u1E63\u1E47o\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(ga\u1E47am)</em> \u043F\u043B\u0430\u043D\u0435\u0442 <em>(graha)</em>, \u0440\u0430\u0437\u0431\u0438\u0442\u044B\u0435 \u0432\u0434\u0440\u0435\u0431\u0435\u0437\u0433\u0438 <em>(rug\u1E47a)</em> <em>(\u0422\u0432\u043E\u0438\u043C\u0438)</em> \u0440\u0443\u043A\u0430\u043C\u0438 <em>(bhuja)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C\u0438 \u0436\u0435\u043B\u0435\u0437\u043D\u044B\u043C \u0431\u0440\u0443\u0441\u044C\u044F\u043C <em>(parigha)</em>, \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0442 \u0441\u043C\u044F\u0442\u0435\u043D\u0438\u0435 <em>(bhr\u0101myat)</em>. \u041D\u0435\u043E\u0436\u0438\u0434\u0430\u043D\u043D\u043E <em>(muhur)</em>, \u043D\u0435\u0431\u043E <em>(dyaus)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(y\u0101ti)</em> \u043D\u0435\u0441\u0447\u0430\u0441\u0442\u043D\u044B\u043C <em>(dausthyam)</em>, [\u043A\u043E\u0433\u0434\u0430 \u0435\u0433\u043E] \u043F\u043E\u043A\u0430\u0442\u044B\u0435 \u043A\u0440\u0430\u044F <em>(ta\u1E6D\u0101\u1E25)</em> \u0445\u043B\u044B\u0441\u0442\u0430\u044E\u0442\u0441\u044F <em>(t\u0101\u1E0Dita)</em> <em>(\u0422\u0432\u043E\u0438\u043C\u0438)</em> \u0432\u043E\u043B\u043D\u0438\u0441\u0442\u044B\u043C\u0438 <em>(anibh\u1E5Bta)</em> \u0441\u043A\u0440\u0443\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u043B\u043E\u043A\u043E\u043D\u0430\u043C\u0438 <em>(ja\u1E6D\u0101)</em> [\u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0442\u043E\u0433\u043E, \u043A\u0430\u043A] \u0422\u044B <em>(tvam)</em> \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0448\u044C \u0442\u0430\u043D\u0435\u0446 <em>(na\u1E6Dasi)</em> \u0434\u043B\u044F \u0437\u0430\u0449\u0438\u0442\u044B <em>(rak\u1E63\u0101yai)</em> \u043C\u0438\u0440\u0430 <em>(jagat)</em>. \u041E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(eva)</em>, <em>(\u0422\u0432\u043E\u0438)</em> \u0421\u0438\u043B\u0430 \u0438 \u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u043E <em>(vibhut\u0101)</em> \u043D\u0435\u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u044B [\u0432 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442] <em>(v\u0101m\u0101)</em>, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(nanu)</em></p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u0935\u093F\u092F\u0926\u094D\u0935\u094D\u092F\u093E\u092A\u0940 \u0924\u093E\u0930\u093E\u0917\u0923\u0917\u0941\u0923\u093F\u0924\u092B\u0947\u0928\u094B\u0926\u094D\u0917\u092E\u0930\u0941\u091A\u093F\u0903 \u092A\u094D\u0930\u0935\u093E\u0939\u094B \u0935\u093E\u0930\u093E\u0902 \u092F\u0903 \u092A\u0943\u0937\u0924\u0932\u0918\u0941\u0926\u0943\u0937\u094D\u091F\u0903 \u0936\u093F\u0930\u0938\u093F \u0924\u0947 \u0964<br> \u091C\u0917\u0926\u094D\u0926\u094D\u0935\u0940\u092A\u093E\u0915\u093E\u0930\u0902 \u091C\u0932\u0927\u093F\u0935\u0932\u092F\u0902 \u0924\u0947\u0928 \u0915\u0943\u0924\u092E\u093F\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935\u094B\u0928\u094D\u0928\u0947\u092F\u0902 \u0927\u0943\u0924\u092E\u0939\u093F\u092E \u0926\u093F\u0935\u094D\u092F\u0902 \u0924\u0935 \u0935\u092A\u0941\u0903 \u0965\u0967\u096D\u0965</p><p class="trans">Viyadvy\u0101p\u012B t\u0101r\u0101ga\u1E47agu\u1E47itaphenodgamaruci\u1E25 prav\u0101ho v\u0101r\u0101\u1E41 ya\u1E25 p\u1E5B\u1E63atalaghud\u1E5B\u1E63\u1E6Da\u1E25 \u015Birasi te \u0964<br> Jagaddv\u012Bp\u0101k\u0101ra\u1E41 jaladhivalaya\u1E41 tena k\u1E5Btamityanenaivonneya\u1E41 dh\u1E5Btamahima divya\u1E41 tava vapu\u1E25 \u096517\u0965</p><p>\u0422\u043E\u0442 <em>(ya\u1E25)</em> \u043D\u0435\u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u044E\u0449\u0438\u0439\u0441\u044F \u043F\u043E\u0442\u043E\u043A <em>(prav\u0101ha\u1E25)</em> \u0432\u043E\u0434 --\u044D\u0442\u043E \u044D\u043F\u0438\u0442\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0440\u0435\u043A\u0438 \u043F\u043E \u0438\u043C\u0435\u043D\u0438 \xABMand\u0101kin\u012B\xBB-- <em>(v\u0101r\u0101m)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0441\u0442\u0435\u043A\u0430\u0435\u0442\u0441\u044F <em>(vy\u0101p\u012B)</em> \u043F\u043E \u043D\u0435\u0431\u0435\u0441\u0430\u043C <em>(viyat)</em> [\u0438 \u0447\u044C\u044F] \u043A\u0440\u0430\u0441\u043E\u0442\u0430 <em>(ruci\u1E25)</em>, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u044E\u0449\u0430\u044F <em>(udgama)</em> \u0432 \u0432\u0438\u0434\u0435 \u043F\u0435\u043D\u044B <em>(phena)</em>, \u0443\u0441\u0438\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(gu\u1E47ita)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(ga\u1E47a)</em> \u0437\u0432\u0451\u0437\u0434 <em>(t\u0101r\u0101)</em>, \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 <em>(d\u1E5B\u1E63\u1E6Da\u1E25)</em> \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u043E\u0439 <em>(laghu)</em> \u043A\u0430\u043F\u0435\u043B\u044C\u043A\u043E\u0439 <em>(p\u1E5B\u1E63ata)</em> \u043D\u0430 \u0422\u0432\u043E\u0435\u0439 <em>(te)</em> \u0433\u043E\u043B\u043E\u0432\u0435 <em>(\u015Birasi)</em>. \u041C\u0438\u0440 <em>(jagat)</em> \u0441\u043E\u0437\u0434\u0430\u0451\u0442\u0441\u044F <em>(k\u1E5Btam)</em> \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 [\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0440\u0435\u043A\u043E\u0439] <em>(tena)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(\u0101k\u0101ram)</em> <em>(\u0441\u0435\u043C\u0438)</em> \u043E\u0441\u0442\u0440\u043E\u0432\u043E\u0432 <em>(dv\u012Bpa)</em>, \u043E\u043A\u0440\u0443\u0436\u0451\u043D\u043D\u044B\u0445 <em>(valayam)</em> \u043E\u043A\u0435\u0430\u043D\u043E\u043C <em>(jaladhi)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em> \u0438\u0437 \u044D\u0442\u043E\u0433\u043E [\u0437\u0430\u044F\u0432\u043B\u0435\u043D\u0438\u044F] <em>(anena eva)</em> [\u043C\u043E\u0436\u043D\u043E \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E] \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0447\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0432\u044B\u0432\u043E\u0434 <em>(unneyam)</em> \u043E \u0422\u0432\u043E\u0435\u0439 <em>(tava)</em> \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(divyam)</em> \u0424\u043E\u0440\u043C\u0435 <em>(vapus)</em>, \u043D\u0430\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0439 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u043C \u0438 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C <em>(dh\u1E5Bta)</em> \u0432\u0435\u043B\u0438\u0447\u0438\u0435\u043C <em>(mahima)</em></p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0930\u0925\u0903 \u0915\u094D\u0937\u094B\u0923\u0940 \u092F\u0928\u094D\u0924\u093E \u0936\u0924\u0927\u0943\u0924\u093F\u0930\u0917\u0947\u0928\u094D\u0926\u094D\u0930\u094B \u0927\u0928\u0941\u0930\u0925\u094B \u0930\u0925\u093E\u0919\u094D\u0917\u0947 \u091A\u0928\u094D\u0926\u094D\u0930\u093E\u0930\u094D\u0915\u094C \u0930\u0925\u091A\u0930\u0923\u092A\u093E\u0923\u093F\u0903 \u0936\u0930 \u0907\u0924\u093F \u0964<br> \u0926\u093F\u0927\u0915\u094D\u0937\u094B\u0938\u094D\u0924\u0947 \u0915\u094B\u093D\u092F\u0902 \u0924\u094D\u0930\u093F\u092A\u0941\u0930\u0924\u0943\u0923\u092E\u093E\u0921\u092E\u094D\u092C\u0930\u0935\u093F\u0927\u093F\u0930\u094D\u0935\u093F\u0927\u0947\u092F\u0948\u0903 \u0915\u094D\u0930\u0940\u0921\u0928\u094D\u0924\u094D\u092F\u094B \u0928 \u0916\u0932\u0941 \u092A\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u093E\u0903 \u092A\u094D\u0930\u092D\u0941\u0927\u093F\u092F\u0903 \u0965\u0967\u096E\u0965</p><p class="trans">Ratha\u1E25 k\u1E63o\u1E47\u012B yant\u0101 \u015Batadh\u1E5Btiragendro dhanuratho rath\u0101\u1E45ge candr\u0101rkau rathacara\u1E47ap\u0101\u1E47i\u1E25 \u015Bara iti \u0964<br> Didhak\u1E63oste ko&#39;ya\u1E41 tripurat\u1E5B\u1E47am\u0101\u1E0Dambaravidhirvidheyai\u1E25 kr\u012B\u1E0Dantyo na khalu paratantr\u0101\u1E25 prabhudhiya\u1E25 \u096518\u0965</p><p>[\u0422\u0432\u043E\u0435\u0439] \u043A\u043E\u043B\u0435\u0441\u043D\u0438\u0446\u0435\u0439 <em>(ratha\u1E25)</em> <em>(\u0431\u044B\u043B\u0430)</em> \u0437\u0435\u043C\u043B\u044F <em>(k\u1E63o\u1E47\u012B)</em>, \u043A\u043E\u043B\u0435\u0441\u043D\u0438\u0447\u0438\u043C <em>(yant\u0101)</em> <em>(\u0431\u044B\u043B)</em> Brahm\u0101 --\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 \xAB\u015Aatadh\u1E5Bti\xBB, \u0434\u043E\u0441\u043B. \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0439 \u0441\u043E\u0442\u043D\u0435\u0439 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0439\xBB-- <em>(\u015Batadh\u1E5Bti\u1E25)</em>, \u0433\u043E\u0440\u0430 \u041C\u0435\u0440\u0443 -- \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A \xABAgendra\xBB, \u0434\u043E\u0441\u043B. \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u0446\u0430\u0440\u044C \u0433\u043E\u0440\xBB-- <em>(agendra\u1E25)</em> [\u0431\u044B\u043B\u0430 \u0422\u0432\u043E\u0438\u043C] \u043B\u0443\u043A\u043E\u043C <em>(dhanus)</em>. \u0422\u0430\u043A\u0436\u0435 <em>(atho)</em> \u0434\u0432\u0443\u043C\u044F \u043A\u043E\u043B\u0451\u0441\u0430\u043C\u0438 <em>(a\u1E45ge)</em> [\u0422\u0432\u043E\u0435\u0439] \u043A\u043E\u043B\u0435\u0441\u043D\u0438\u0446\u044B <em>(ratha\u1E25)</em> <em>(\u0431\u044B\u043B\u0438)</em> \u0441\u043E\u043B\u043D\u0446\u0435 --arka-- \u0438 \u043B\u0443\u043D\u0430 --candra-- <em>(candr\u0101rkau)</em>. Vi\u1E63\u1E47u --\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 \xABRathacara\u1E47ap\u0101\u1E47i\xBB, \u0434\u043E\u0441\u043B. \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0439 \u0432 \u0440\u0443\u043A\u0430\u0445 \u043A\u043E\u043B\u0435\u0441\u043E \u043A\u043E\u043B\u0435\u0441\u043D\u0438\u0446\u044B\xBB-- <em>(rathacara\u1E47ap\u0101\u1E47i\u1E25)</em> [\u0431\u044B\u043B \u0422\u0432\u043E\u0435\u0439] \u0441\u0442\u0440\u0435\u043B\u043E\u0439 <em>(\u015Bara\u1E25 iti)</em>, \u043A\u043E\u0433\u0434\u0430 \u0422\u044B --tvam-- <em>(te)</em> \u043F\u043E\u0436\u0435\u043B\u0430\u043B \u0441\u0436\u0435\u0447\u044C --didhak\u1E63u-- <em>(didhak\u1E63o\u1E25)</em> \u0442\u0440\u0438 <em>(tri)</em> \u0433\u043E\u0440\u043E\u0434\u0430 <em>(pura)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u043A\u0430\u043A] \u0442\u0440\u0430\u0432\u0430 <em>(t\u1E5B\u1E47am)</em> [\u0434\u043B\u044F \u0422\u0435\u0431\u044F]. [\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435], \u0432 \u0447\u0451\u043C \u0441\u043C\u044B\u0441\u043B <em>(ka\u1E25)</em> \u044D\u0442\u043E\u0433\u043E <em>(ayam)</em> \u0433\u0440\u043E\u043C\u043A\u043E\u0433\u043E <em>(\u0101\u1E0Dambara)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(vidhi\u1E25)</em>? [\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435] \u041C\u044B\u0441\u043B\u0438 <em>(dhiya\u1E25)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(prabhu)</em> \u043D\u0435 <em>(na khalu)</em> \u0437\u0430\u0432\u0438\u0441\u044F\u0442 <em>(tantr\u0101\u1E25)</em> \u043D\u0438 \u043E\u0442 \u0447\u0435\u0433\u043E <em>(para)</em>, [\u0430] \u0438\u0433\u0440\u0430\u044E\u0442 <em>(kr\u012B\u1E0Dantya\u1E25)</em> \u0441 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438\u0441\u044F \u0432 \u0415\u0433\u043E \u0440\u0430\u0441\u043F\u043E\u0440\u044F\u0436\u0435\u043D\u0438\u0438 <em>(vidheyai\u1E25)</em></p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0939\u0930\u093F\u0938\u094D\u0924\u0947 \u0938\u093E\u0939\u0938\u094D\u0930\u0902 \u0915\u092E\u0932\u092C\u0932\u093F\u092E\u093E\u0927\u093E\u092F \u092A\u0926\u092F\u094B\u0930\u094D\u092F\u0926\u0947\u0915\u094B\u0928\u0947 \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u0928\u093F\u091C\u092E\u0941\u0926\u0939\u0930\u0928\u094D\u0928\u0947\u0924\u094D\u0930\u0915\u092E\u0932\u092E\u094D \u0964<br> \u0917\u0924\u094B \u092D\u0915\u094D\u0924\u094D\u092F\u0941\u0926\u094D\u0930\u0947\u0915\u0903 \u092A\u0930\u093F\u0923\u0924\u093F\u092E\u0938\u094C \u091A\u0915\u094D\u0930\u0935\u092A\u0941\u0937\u093E \u0924\u094D\u0930\u092F\u093E\u0923\u093E\u0902 \u0930\u0915\u094D\u0937\u093E\u092F\u0948 \u0924\u094D\u0930\u093F\u092A\u0941\u0930\u0939\u0930 \u091C\u093E\u0917\u0930\u094D\u0924\u093F \u091C\u0917\u0924\u093E\u092E\u094D \u0965\u0967\u096F\u0965</p><p class="trans">Hariste s\u0101hasra\u1E41 kamalabalim\u0101dh\u0101ya padayoryadekone tasminnijamudaharannetrakamalam \u0964<br> Gato bhaktyudreka\u1E25 pari\u1E47atimasau cakravapu\u1E63\u0101 tray\u0101\u1E47\u0101\u1E41 rak\u1E63\u0101yai tripurahara j\u0101garti jagat\u0101m \u096519\u0965</p><p>\u041E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(hara)</em> \u0442\u0440\u0451\u0445 <em>(tri)</em> \u0433\u043E\u0440\u043E\u0434\u043E\u0432 <em>(pura)</em>! \u0425\u0430\u0440\u0438 --\u0442.e. Vi\u1E63\u1E47u-- <em>(hari\u1E25)</em>, \u043F\u043E\u043B\u043E\u0436\u0438\u0432 <em>(\u0101dh\u0101ya)</em> <em>(\u0441\u0432\u043E\u0451)</em> \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435 <em>(balim)</em> \u0438\u0437 \u0442\u044B\u0441\u044F\u0447\u0438 <em>(s\u0101hasram)</em> \u043B\u043E\u0442\u043E\u0441\u043E\u0432 <em>(kamala)</em> \u043A \u0422\u0432\u043E\u0438\u043C <em>(te)</em> \u0441\u0442\u043E\u043F\u0430\u043C <em>(padayo\u1E25)</em>, <em>(\u0437\u0430\u043C\u0435\u0442\u0438\u043B),</em> \u0447\u0442\u043E <em>(yad)</em> \u043E\u0434\u043D\u043E\u0433\u043E [\u0438\u0437 \u043B\u043E\u0442\u043E\u0441\u043E\u0432] \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u043B\u043E <em>(ekone)</em> \u0432 \u044D\u0442\u043E\u043C [\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0438] <em>(tasmin)</em>. [\u0418 \u043F\u043E\u044D\u0442\u043E\u043C\u0443], \u043E\u043D \u0432\u044B\u0440\u0432\u0430\u043B <em>(udaharat)</em> [\u043E\u0434\u0438\u043D] \u0438\u0437 \u0441\u0432\u043E\u0438\u0445 <em>(nijam)</em> \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0433\u043B\u0430\u0437 <em>(netrakamalam)</em>, [\u0447\u0442\u043E\u0431\u044B \u0440\u0435\u0448\u0438\u0442\u044C \u044D\u0442\u0443 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443]. [\u0412 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435], \u0438\u0437\u043E\u0431\u0438\u043B\u0438\u0435 <em>(udreka\u1E25)</em> <em>(\u0435\u0433\u043E)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bhakti)</em> <em>(\u0431\u044B\u043B\u043E)</em> \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0435\u043D\u043E <em>(gata\u1E25... pari\u1E47atim)</em> <em>(\u0422\u043E\u0431\u043E\u044E)</em> \u0432 \u0442\u043E <em>(asau)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u0435 <em>(vapu\u1E63\u0101)</em> \u041A\u043E\u043B\u0435\u0441\u043E [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u043A\u0430\u043A \xABSudar\u015Bana\xBB] <em>(cakra)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441 \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(j\u0101garti)</em> \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 <em>(rak\u1E63\u0101yai)</em> \u0442\u0440\u0438 <em>(tray\u0101\u1E47\u0101m)</em> \u043C\u0438\u0440\u0430 <em>(jagat\u0101m)</em></p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u0915\u094D\u0930\u0924\u094C \u0938\u0941\u092A\u094D\u0924\u0947 \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0924\u094D\u0935\u092E\u0938\u093F \u092B\u0932\u092F\u094B\u0917\u0947 \u0915\u094D\u0930\u0924\u0941\u092E\u0924\u093E\u0902 \u0915\u094D\u0935 \u0915\u0930\u094D\u092E \u092A\u094D\u0930\u0927\u094D\u0935\u0938\u094D\u0924\u0902 \u092B\u0932\u0924\u093F \u092A\u0941\u0930\u0941\u0937\u093E\u0930\u093E\u0927\u0928\u092E\u0943\u0924\u0947 \u0964<br> \u0905\u0924\u0938\u094D\u0924\u094D\u0935\u093E\u0902 \u0938\u092E\u094D\u092A\u094D\u0930\u0947\u0915\u094D\u0937\u094D\u092F \u0915\u094D\u0930\u0924\u0941\u0937\u0941 \u092B\u0932\u0926\u093E\u0928\u092A\u094D\u0930\u0924\u093F\u092D\u0941\u0935\u0902 \u0936\u094D\u0930\u0941\u0924\u094C \u0936\u094D\u0930\u0926\u094D\u0927\u093E\u0902 \u092C\u0926\u094D\u0927\u094D\u0935\u093E \u0926\u0943\u0922\u092A\u0930\u093F\u0915\u0930\u0903 \u0915\u0930\u094D\u092E\u0938\u0941 \u091C\u0928\u0903 \u0965\u0968\u0966\u0965</p><p class="trans">Kratau supte j\u0101grattvamasi phalayoge kratumat\u0101\u1E41 kva karma pradhvasta\u1E41 phalati puru\u1E63\u0101r\u0101dhanam\u1E5Bte \u0964<br> Atastv\u0101\u1E41 samprek\u1E63ya kratu\u1E63u phalad\u0101napratibhuva\u1E41 \u015Brutau \u015Braddh\u0101\u1E41 baddhv\u0101 d\u1E5B\u1E0Dhaparikara\u1E25 karmasu jana\u1E25 \u096520\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435 --kratu-- <em>(kratau)</em> \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F --\u0434\u043E\u0441\u043B. \xAB\u0437\u0430\u0441\u044B\u043F\u0430\u0435\u0442\xBB-- <em>(supte)</em>, \u0422\u044B <em>(tvam)</em> \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0448\u044C <em>(asi)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C <em>(j\u0101grat)</em>, \u0447\u0442\u043E\u0431\u044B \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0434\u0438\u0442\u044C <em>(phalayoge)</em> \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E \u0436\u0435\u0440\u0442\u0432\u0443 <em>(kratumat\u0101m)</em>. \u041A\u0430\u043A <em>(kva)</em> \u0440\u0438\u0442\u0443\u0430\u043B \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F <em>(karma)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0437\u0430\u043A\u043E\u043D\u0447\u0438\u043B\u0441\u044F <em>(pradhvastam)</em> \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u043D\u0435\u0441\u0442\u0438 \u043F\u043B\u043E\u0434\u044B <em>(phalati)</em> \u0431\u0435\u0437 <em>(\u1E5Bte)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044F <em>(\u0101r\u0101dhanam)</em> \u041F\u0443\u0440\u0443\u0448\u0435 \u0438\u043B\u0438 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0439 \u041B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 -- \u0428\u0438\u0432\u0435-- <em>(puru\u1E63a)</em>? \u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas)</em>, \u043E\u0441\u043E\u0437\u043D\u0430\u0432 <em>(samprek\u1E63ya)</em>, \u0447\u0442\u043E \u0422\u044B [\u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F] <em>(tv\u0101m)</em> \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u043C \u043F\u043B\u043E\u0434\u044B <em>(phala-d\u0101napratibhuvam)</em> \u0432 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u0445 <em>(kratu\u1E63u)</em>, \u0438 \u043E\u0431\u043B\u0430\u0434\u0430\u044F <em>(baddhv\u0101)</em> \u0432\u0435\u0440\u043E\u044E <em>(\u015Braddh\u0101m)</em> \u0432 \u0428\u0440\u0443\u0442\u0438 --\u0442.e. \u0432 \u0412\u0435\u0434\u044B-- <em>(\u015Brutau)</em>, \u043B\u044E\u0434\u0438 <em>(jana\u1E25)</em> \u0440\u0435\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(d\u1E5B\u1E0Dha)</em> \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0442 <em>(parikara\u1E25)</em> \u043E\u0431\u0440\u044F\u0434\u044B \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F <em>(karmasu)</em></p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">\u0915\u094D\u0930\u093F\u092F\u093E\u0926\u0915\u094D\u0937\u094B \u0926\u0915\u094D\u0937\u0903 \u0915\u094D\u0930\u0924\u0941\u092A\u0924\u093F\u0930\u0927\u0940\u0936\u0938\u094D\u0924\u0928\u0941\u092D\u0943\u0924\u093E\u092E\u0943\u0937\u0940\u0923\u093E\u092E\u093E\u0930\u094D\u0924\u094D\u0935\u093F\u091C\u094D\u092F\u0902 \u0936\u0930\u0923\u0926 \u0938\u0926\u0938\u094D\u092F\u093E\u0903 \u0938\u0941\u0930\u0917\u0923\u093E\u0903 \u0964<br> \u0915\u094D\u0930\u0924\u0941\u092D\u094D\u0930\u0902\u0936\u0938\u094D\u0924\u094D\u0935\u0924\u094D\u0924\u0903 \u0915\u094D\u0930\u0924\u0941\u092B\u0932\u0935\u093F\u0927\u093E\u0928\u0935\u094D\u092F\u0938\u0928\u093F\u0928\u094B \u0927\u094D\u0930\u0941\u0935\u0902 \u0915\u0930\u094D\u0924\u0941\u0903 \u0936\u094D\u0930\u0926\u094D\u0927\u093E\u0935\u093F\u0927\u0941\u0930\u092E\u092D\u093F\u091A\u093E\u0930\u093E\u092F \u0939\u093F \u092E\u0916\u093E\u0903 \u0965\u0968\u0967\u0965</p><p class="trans">Kriy\u0101dak\u1E63o dak\u1E63a\u1E25 kratupatiradh\u012B\u015Bastanubh\u1E5Bt\u0101m\u1E5B\u1E63\u012B\u1E47\u0101m\u0101rtvijya\u1E41 \u015Bara\u1E47ada sadasy\u0101\u1E25 suraga\u1E47\u0101\u1E25 \u0964<br> Kratubhra\u1E41\u015Bastvatta\u1E25 kratuphalavidh\u0101navyasanino dhruva\u1E41 kartu\u1E25 \u015Braddh\u0101vidhuramabhic\u0101r\u0101ya hi makh\u0101\u1E25 \u096521\u0965</p><p>\u041E \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u0443\u0431\u0435\u0436\u0438\u0449\u0435 <em>(\u015Bara\u1E47a)</em>! \u0422\u044B --tvam-- <em>(tvatta\u1E25)</em>, \u043E\u0431\u043E\u0436\u0430\u044E\u0449\u0438\u0439 <em>(vyasanina\u1E25)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(dhruvam)</em> \u0434\u0430\u0440\u043E\u0432\u0430\u0442\u044C <em>(vidh\u0101na)</em> \u043F\u043B\u043E\u0434\u044B <em>(phala)</em> \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0439 <em>(kratu)</em>, \u0438\u0441\u043F\u043E\u0440\u0442\u0438\u043B --ababhra\u1E41\u015Bas \u0438\u043B\u0438 abhra\u1E41\u015Bayas-- <em>(bhra\u1E41\u015Ba\u1E25)</em> [\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435] \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435 <em>(kratu)</em>, [\u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C] <em>Dak\u1E63a</em> -- \u043E\u0442\u0435\u0446 <em>Sat\u012B</em>, \u043F\u0435\u0440\u0432\u043E\u0439 \u0436\u0435\u043D\u044B \u0428\u0438\u0432\u044B-- <em>(dak\u1E63a\u1E25)</em>, \u044D\u043A\u0441\u043F\u0435\u0440\u0442 <em>(dak\u1E63a\u1E25)</em> \u0432 \u0440\u0438\u0442\u0443\u0430\u043B\u0430\u0445 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0439 <em>(kriy\u0101)</em> \u0438 \u0433\u043E\u0441\u043F\u043E\u0434\u0438\u043D <em>(adh\u012B\u015Ba\u1E25)</em> \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043D\u0430\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u0445 <em>(bh\u1E5Bt\u0101m)</em> \u0442\u0435\u043B\u043E\u043C <em>(tanu)</em>, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u043B \u0440\u043E\u043B\u044C \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E \u0436\u0435\u0440\u0442\u0432\u0443 <em>(kratupati\u1E25)</em>. [\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C] \u0440\u043E\u043B\u044C \xAB\u1E5Btvij\xBB --\u0436\u0440\u0435\u0446\u043E\u0432-- <em>(\u0101rtvijyam)</em> \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u043B\u0430\u0441\u044C [\u0441\u0430\u043C\u0438\u043C\u0438] \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u041C\u0443\u0434\u0440\u0435\u0446\u0430\u043C\u0438 --\u1E5A\u1E63i-- <em>(\u1E5B\u1E63\u012B\u1E47\u0101m)</em>, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] \u043F\u043E\u043B\u043A\u0438 <em>(ga\u1E47\u0101\u1E25)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em> [\u0441\u043B\u0443\u0436\u0438\u043B\u0438] \u0432\u0435\u0440\u0445\u043E\u0432\u043D\u044B\u043C\u0438 \u0436\u0440\u0435\u0446\u0430\u043C\u0438 <em>(sadasy\u0101\u1E25)</em>. \u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F <em>(makh\u0101\u1E25)</em>, [\u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435] \u0434\u043B\u044F \u043E\u0447\u0430\u0440\u043E\u0432\u0430\u043D\u0438\u044F [\u0434\u0440\u0443\u0433\u0438\u0445] <em>(abhic\u0101r\u0101ya)</em>, \u043D\u0435\u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u044B <em>(vidhuram)</em> \u0434\u043B\u044F \u0432\u0435\u0440\u044B <em>(\u015Braddh\u0101)</em> \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0435\u0433\u043E \u0438\u0445 <em>(kartu\u1E25)</em></p></div><div class="stanza"><a href="#s22" id="s22" class="num">22</a><p class="sans">\u092A\u094D\u0930\u091C\u093E\u0928\u093E\u0925\u0902 \u0928\u093E\u0925 \u092A\u094D\u0930\u0938\u092D\u092E\u092D\u093F\u0915\u0902 \u0938\u094D\u0935\u093E\u0902 \u0926\u0941\u0939\u093F\u0924\u0930\u0902 \u0917\u0924\u0902 \u0930\u094B\u0939\u093F\u0926\u094D\u092D\u0942\u0924\u093E\u0902 \u0930\u093F\u0930\u092E\u092F\u093F\u0937\u0941\u092E\u0943\u0937\u094D\u092F\u0938\u094D\u092F \u0935\u092A\u0941\u0937\u093E \u0964<br> \u0927\u0928\u0941\u0937\u094D\u092A\u093E\u0923\u0947\u0930\u094D\u092F\u093E\u0924\u0902 \u0926\u093F\u0935\u092E\u092A\u093F \u0938\u092A\u0924\u094D\u0930\u093E\u0915\u0943\u0924\u092E\u092E\u0941\u0902 \u0924\u094D\u0930\u0938\u0928\u094D\u0924\u0902 \u0924\u0947\u093D\u0926\u094D\u092F\u093E\u092A\u093F \u0924\u094D\u092F\u091C\u0924\u093F \u0928 \u092E\u0943\u0917\u0935\u094D\u092F\u093E\u0927\u0930\u092D\u0938\u0903 \u0965\u0968\u0968\u0965</p><p class="trans">Praj\u0101n\u0101tha\u1E41 n\u0101tha prasabhamabhika\u1E41 sv\u0101\u1E41 duhitara\u1E41 gata\u1E41 rohidbh\u016Bt\u0101\u1E41 riramayi\u1E63um\u1E5B\u1E63yasya vapu\u1E63\u0101 \u0964<br> Dhanu\u1E63p\u0101\u1E47ery\u0101ta\u1E41 divamapi sapatr\u0101k\u1E5Btamamu\u1E41 trasanta\u1E41 te&#39;dy\u0101pi tyajati na m\u1E5Bgavy\u0101dharabhasa\u1E25 \u096522\u0965</p><p>\u041E \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D <em>(n\u0101tha)</em>! \u0422\u0432\u043E\u044F <em>(te)</em> \u043C\u043E\u0449\u043D\u0430\u044F \u044F\u0440\u043E\u0441\u0442\u044C <em>(rabhasa\u1E25)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 \u043E\u0445\u043E\u0442\u043D\u0438\u043A\u0430 <em>(m\u1E5Bgavy\u0101dha)</em> \u0434\u0430\u0436\u0435 \u0441\u0435\u0439\u0447\u0430\u0441 <em>(adya-api)</em> \u043D\u0435 <em>(na)</em> \u043F\u043E\u043A\u0438\u0434\u0430\u0435\u0442 <em>(tyajati)</em> \u0442\u043E\u0433\u043E <em>(amum)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0430 <em>(n\u0101tham)</em> <em>(\u0432\u0441\u0435\u0445)</em> \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(praj\u0101)</em> --\u0442.e. \u0411\u0440\u0430\u0445\u043C\u0443, \u0438\u043B\u0438 \u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044F, \u0438\u0437 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 \u0442\u0440\u0438\u0430\u0434\u044B--, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0431\u044B\u043B \u0440\u0430\u043D\u0435\u043D <em>(sapatr\u0101-k\u1E5Btam)</em> [\u0441\u0442\u0440\u0435\u043B\u0430\u043C\u0438 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E] \u043E\u0445\u043E\u0442\u043D\u0438\u043A\u0430 \u0441 \u043B\u0443\u043A\u043E\u043C \u0432 \u0440\u0443\u043A\u0430\u0445 <em>(dhanu\u1E63p\u0101\u1E47e\u1E25)</em> [\u0438] \u0443\u0431\u0435\u0436\u0430\u043B <em>(y\u0101tam)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043D\u0430 \u043D\u0435\u0431\u0435\u0441\u0430 <em>(divam)</em> \u0432 \u0441\u0442\u0440\u0430\u0445\u0435 [\u0422\u0435\u0431\u044F] <em>(trasantam)</em>. [\u0412\u0441\u0451 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u043E \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E <em>Brahm\u0101</em>] \u0431\u044B\u043B \u043E\u0445\u0432\u0430\u0447\u0435\u043D <em>(gatam)</em> \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0439 <em>(prasabham)</em> \u043F\u043E\u0445\u043E\u0442\u044C\u044E <em>(abhikam)</em> \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sv\u0101m)</em> \u0434\u043E\u0447\u0435\u0440\u0438 <em>(duhitaram)</em>. [\u041E\u043D \u043F\u0440\u0438\u043D\u044F\u043B] \u0444\u043E\u0440\u043C\u0443 --vapus-- <em>(vapu\u1E63\u0101)</em> \u0431\u0435\u043B\u043E\u043D\u043E\u0433\u043E\u0439 \u0430\u043D\u0442\u0438\u043B\u043E\u043F\u044B <em>(\u1E5B\u1E63yasya)</em>, \u0447\u0442\u043E\u0431\u044B \u043E\u0432\u043B\u0430\u0434\u0435\u0442\u044C [\u0435\u044E] <em>(riramayi\u1E63um)</em> [\u0438 \u0442\u043E\u0433\u0434\u0430 \u043E\u043D\u0430] \u0441\u0442\u0430\u043B\u0430 <em>(bh\u016Bt\u0101m)</em> \u043A\u0440\u0430\u0441\u043D\u044B\u043C \u043E\u043B\u0435\u043D\u0435\u043C <em>(rohit)</em>, [\u0447\u0442\u043E\u0431\u044B \u0443\u043B\u0435\u0442\u0435\u0442\u044C \u043E\u0442 \u043D\u0435\u0433\u043E]</p></div><div class="stanza"><a href="#s23" id="s23" class="num">23</a><p class="sans">\u0938\u094D\u0935\u0932\u093E\u0935\u0923\u094D\u092F\u093E\u0936\u0902\u0938\u093E \u0927\u0943\u0924\u0927\u0928\u0941\u0937\u092E\u0939\u094D\u0928\u093E\u092F \u0924\u0943\u0923\u0935\u0924\u094D\u092A\u0941\u0930\u0903 \u092A\u094D\u0932\u0941\u0937\u094D\u091F\u0902 \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u092A\u0941\u0930\u092E\u0925\u0928 \u092A\u0941\u0937\u094D\u092A\u093E\u092F\u0941\u0927\u092E\u092A\u093F \u0964<br> \u092F\u0926\u093F \u0938\u094D\u0924\u094D\u0930\u0948\u0923\u0902 \u0926\u0947\u0935\u0940 \u092F\u092E\u0928\u093F\u0930\u0924 \u0926\u0947\u0939\u093E\u0930\u094D\u0927\u0918\u091F\u0928\u093E\u0926\u0935\u0948\u0924\u093F \u0924\u094D\u0935\u093E\u092E\u0926\u094D\u0927\u093E \u092C\u0924 \u0935\u0930\u0926 \u092E\u0941\u0917\u094D\u0927\u093E \u092F\u0935\u0924\u092F\u0903 \u0965\u0968\u0969\u0965</p><p class="trans">Sval\u0101va\u1E47y\u0101\u015Ba\u1E41s\u0101 dh\u1E5Btadhanu\u1E63amahn\u0101ya t\u1E5B\u1E47avatpura\u1E25 plu\u1E63\u1E6Da\u1E41 d\u1E5B\u1E63\u1E6Dv\u0101 puramathana pu\u1E63p\u0101yudhamapi \u0964<br> Yadi strai\u1E47a\u1E41 dev\u012B yamanirata deh\u0101rdhagha\u1E6Dan\u0101davaiti tv\u0101maddh\u0101 bata varada mugdh\u0101 yuvataya\u1E25 \u096523\u0965</p><p>\u041E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(mathana)</em> [\u0442\u0440\u0451\u0445] \u043C\u0438\u0440\u043E\u0432 <em>(pura)</em>! \u0415\u0441\u043B\u0438 <em>(yadi)</em> \u0431\u043E\u0433\u0438\u043D\u044F <em>(P\u0101rvat\u012B)</em> <em>(dev\u012B)</em>, <em>(\u0447\u044C\u044F)</em> \u043D\u0430\u0434\u0435\u0436\u0434\u0430 <em>(\u0101\u015Ba\u1E41s\u0101)</em> \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0430 \u043D\u0430 \u0435\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u043A\u0440\u0430\u0441\u043E\u0442\u0435 \u0438 \u043E\u0447\u0430\u0440\u043E\u0432\u0430\u043D\u0438\u0438 <em>(l\u0101va\u1E47ya)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u043F\u0440\u043E\u0448\u043B\u043E\u043C <em>(puras)</em> \u0443\u0432\u0438\u0434\u0435\u0432 <em>(d\u1E5B\u1E63\u1E6Dv\u0101)</em> <em>(\u043A\u0430\u043A)</em> Pu\u1E63p\u0101yudha --\u0434\u043E\u0441\u043B. \xAB\u0446\u0432\u0435\u0442\u043E-\u0440\u0443\u043A\u0438\u0439\xBB, \u044D\u043F\u0438\u0442\u0435\u0442 \u041A\u0430\u0430\u043C\u0430\u0434\u0435\u0432\u044B, \u0431\u043E\u0433\u0430 \u043B\u044E\u0431\u0432\u0438-- <em>(pu\u1E63p\u0101yudham)</em>, \u043E\u0441\u043D\u0430\u0449\u0435\u043D\u043D\u044B\u0439 \u043B\u0443\u043A\u043E\u043C <em>(dh\u1E5Btadhanu\u1E63am)</em> [\u0431\u044B\u043B] \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(ahn\u0101ya)</em> \u0438\u0441\u043F\u0435\u043F\u0435\u043B\u0451\u043D <em>(plu\u1E63\u1E6Dam)</em> <em>(\u0422\u043E\u0431\u043E\u0439)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u0442\u0440\u0430\u0432\u0438\u043D\u043A\u0435 <em>(t\u1E5B\u1E47a)</em>, [\u0432\u0441\u0451 \u0435\u0449\u0451] \u0441\u0447\u0438\u0442\u0430\u0435\u0442 <em>(avaiti)</em>, \u0447\u0442\u043E \u0422\u044B <em>(tv\u0101m)</em> \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439 <em>(strai\u1E47am)</em>, \u043E \u0422\u044B, \u043F\u043E\u0441\u0432\u044F\u0449\u0430\u044E\u0449\u0438\u0439 \u0441\u0435\u0431\u044F <em>(nirata)</em> [\u0440\u0430\u0437\u043D\u043E\u043C\u0443 \u0440\u043E\u0434\u0443] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 <em>(yama)</em>! \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u043E\u043D\u0430] \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442 <em>(gha\u1E6Dan\u0101t)</em> \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0443 <em>(ardha)</em> [\u0422\u0432\u043E\u0435\u0433\u043E] \u0442\u0435\u043B\u0430 <em>(deha)</em>... [\u0443\u0432\u044B], \u043E <em>(bata)</em> \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>, \u043C\u043E\u043B\u043E\u0434\u044B\u0435 \u0436\u0435\u043D\u0449\u0438\u043D\u044B <em>(yuvataya\u1E25)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(addh\u0101)</em> \u043D\u0435\u043E\u043F\u044B\u0442\u043D\u044B \u0438 \u043F\u0440\u043E\u0441\u0442\u044B <em>(mugdh\u0101\u1E25)</em>!</p></div><div class="stanza"><a href="#s24" id="s24" class="num">24</a><p class="sans">\u0936\u094D\u092E\u0936\u093E\u0928\u0947\u0937\u094D\u0935\u093E\u0915\u094D\u0930\u0940\u0921\u093E \u0938\u094D\u092E\u0930\u0939\u0930 \u092A\u093F\u0936\u093E\u091A\u093E\u0903 \u0938\u0939\u091A\u0930\u093E\u0936\u094D\u091A\u093F\u0924\u093E\u092D\u0938\u094D\u092E\u093E\u0932\u0947\u092A\u0903 \u0938\u094D\u0930\u0917\u092A\u093F \u0928\u0943\u0915\u0930\u094B\u091F\u0940\u092A\u0930\u093F\u0915\u0930\u0903 \u0964<br> \u0905\u092E\u093E\u0919\u094D\u0917\u0932\u094D\u092F\u0902 \u0936\u0940\u0932\u0902 \u0924\u0935 \u092D\u0935\u0924\u0941 \u0928\u093E\u092E\u0948\u0935\u092E\u0916\u093F\u0932\u0902 \u0924\u0925\u093E\u092A\u093F \u0938\u094D\u092E\u0930\u094D\u0924\u0944\u0923\u093E\u0902 \u0935\u0930\u0926 \u092A\u0930\u092E\u0902 \u092E\u0919\u094D\u0917\u0932\u092E\u0938\u093F \u0965\u0968\u096A\u0965</p><p class="trans">\u015Ama\u015B\u0101ne\u1E63v\u0101kr\u012B\u1E0D\u0101 smarahara p\u012B\u015B\u0101c\u0101\u1E25 sahacar\u0101\u015Bcit\u0101bhasm\u0101lepa\u1E25 sragapi n\u1E5Bkaro\u1E6D\u012Bparikara\u1E25 \u0964<br> Am\u0101\u1E45galya\u1E41 \u015B\u012Bla\u1E41 tava bhavatu n\u0101maivamakhila\u1E41 tath\u0101pi smart\u1E5D\u1E47\u0101\u1E41 varada parama\u1E41 ma\u1E45galamasi \u096524\u0965</p><p>\u041E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(hara)</em> \u0421\u043C\u0430\u0440\u044B --\u0442.e. \u041A\u0430\u0430\u043C\u0430\u0434\u0435\u0432\u044B, \u0431\u043E\u0433\u0430 \u043B\u044E\u0431\u0432\u0438-- <em>(smara)</em>! <em>(\u0422\u0432\u043E\u0435\u0439)</em> \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u043E\u0439 \u0434\u043B\u044F \u0438\u0433\u0440 <em>(\u0101kr\u012B\u1E0D\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043A\u0440\u0435\u043C\u0430\u0442\u043E\u0440\u0438\u0439 <em>(\u015Bma\u015B\u0101ne\u1E63u)</em>, <em>(\u0430)</em> Pi\u015B\u0101ca --\u0432\u0438\u0434 \u0434\u0435\u043C\u043E\u043D\u043E\u0432-- <em>(pi\u015B\u0101c\u0101\u1E25)</em> <em>(\u0422\u0432\u043E\u0438)</em> \u0441\u043F\u0443\u0442\u043D\u0438\u043A\u0438 <em>(sahacar\u0101\u1E25)</em>. <em>(\u0422\u044B)</em> \u043D\u0430\u043D\u043E\u0441\u0438\u0448\u044C <em>(\u0101lepa\u1E25)</em> \u043F\u0435\u043F\u0435\u043B <em>(bhasma)</em> \u043F\u043E\u0445\u043E\u0440\u043E\u043D\u043D\u044B\u0445 \u043A\u043E\u0441\u0442\u0440\u043E\u0432 [\u043D\u0430 \u0421\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E] <em>(cit\u0101)</em> <em>(\u0438)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> [\u043D\u043E\u0441\u0438\u0448\u044C] \u0433\u0438\u0440\u043B\u044F\u043D\u0434\u0443 <em>(srak)</em> [\u0438\u0437] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(parikara\u1E25)</em> \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u0445 <em>(n\u1E5B)</em> \u0447\u0435\u0440\u0435\u043F\u043E\u0432 <em>(karo\u1E6D\u012B)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(evam)</em>, <em>(\u043F\u0443\u0441\u0442\u044C)</em> \u0432\u0441\u0451 <em>(akhilam)</em> \u0422\u0432\u043E\u0451 <em>(tava)</em> \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 <em>(\u015B\u012Blam)</em> \u0431\u0443\u0434\u0435\u0442 <em>(bhavatu)</em> \u043D\u0430\u0437\u0432\u0430\u043D\u043E <em>(n\u0101ma)</em> \xAB\u043D\u0435\u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u043C\xBB <em>(am\u0101\u1E45galyam)</em>!... \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tath\u0101-api)</em>, \u043E \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>, \u0422\u044B <em>(asi)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(paramam)</em> \u0411\u043B\u0430\u0433\u043E\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(ma\u1E45galam)</em> \u0434\u043B\u044F \u0442\u0435\u0445, \u043A\u0442\u043E \u043F\u043E\u043C\u043D\u0438\u0442 [\u0422\u0435\u0431\u044F]! <em>(smart\u1E5D\u1E47\u0101m)</em></p></div><div class="stanza"><a href="#s25" id="s25" class="num">25</a><p class="sans">\u092E\u0928\u0903 \u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u091A\u093F\u0924\u094D\u0924\u0947 \u0938\u0935\u093F\u0927\u092E\u0935\u0927\u093E\u092F\u093E\u0924\u094D\u0924\u092E\u0930\u0941\u0924\u0903 \u092A\u094D\u0930\u0939\u0943\u0937\u094D\u092F\u0926\u094D\u0930\u094B\u092E\u093E\u0923\u0903 \u092A\u094D\u0930\u092E\u0926\u0938\u0932\u093F\u0932\u094B\u0924\u094D\u0938\u0919\u094D\u0917\u093F\u0924\u0926\u0943\u0936\u0903 \u0964<br> \u092F\u0926\u093E\u0932\u094B\u0915\u094D\u092F\u093E\u0939\u094D\u0932\u093E\u0926\u0902 \u0939\u094D\u0930\u0926 \u0907\u0935 \u0928\u093F\u092E\u091C\u094D\u091C\u094D\u092F\u093E\u092E\u0943\u0924\u092E\u092F\u0947 \u0926\u0927\u0924\u094D\u092F\u0928\u094D\u0924\u0938\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u0915\u093F\u092E\u092A\u093F \u092F\u092E\u093F\u0928\u0938\u094D\u0924\u0924\u094D \u0915\u093F\u0932 \u092D\u0935\u093E\u0928\u094D \u0965\u0968\u096B\u0965</p><p class="trans">Mana\u1E25 pratyakcitte savidhamavadh\u0101y\u0101ttamaruta\u1E25 prah\u1E5B\u1E63yadrom\u0101\u1E47a\u1E25 pramadasalilotsa\u1E45gitad\u1E5B\u015Ba\u1E25 \u0964<br> Yad\u0101loky\u0101hl\u0101da\u1E41 hrada iva nimajjy\u0101m\u1E5Btamaye dadhatyantastattva\u1E41 kimapi yaminastat kila bhav\u0101n \u096525\u0965</p><p>\u041F\u043E\u0433\u0440\u0443\u0437\u0438\u0432 <em>(avadh\u0101ya)</em> \u0443\u043C <em>(manas)</em> \u0432 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(pratyakcitte)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C \u043F\u0438\u0441\u0430\u043D\u0438\u0439 <em>(savidham)</em>, <em>(\u0438)</em> \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044F <em>(\u0101tta)</em> \u0434\u044B\u0445\u0430\u043D\u0438\u0435 <em>(maruta\u1E25)</em>, \u0441 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 <em>(d\u1E5B\u015Ba\u1E25)</em> \u043F\u043E\u043B\u043D\u044B\u043C\u0438 <em>(utsa\u1E45gita)</em> \u0441\u043B\u0451\u0437 <em>(salila)</em>, [\u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044F] \u0420\u0430\u0434\u043E\u0441\u0442\u044C <em>(pramada)</em>, \u043E\u0442 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u0441\u0442\u0430\u044E\u0442 \u0434\u044B\u0431\u043E\u043C <em>(prah\u1E5B\u1E63yat)</em> \u0432\u043E\u043B\u043E\u0441\u044B <em>(\u043D\u0430 \u0438\u0437 \u0442\u0435\u043B\u0430\u0445)</em> <em>(rom\u0101\u1E47a\u1E25)</em>, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0435 \u0441\u0430\u043C\u043E\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C [\u043C\u0443\u0434\u0440\u0435\u0446\u044B] <em>(yamina\u1E25)</em>, \u0432\u043E \u0432\u0440\u0435\u043C\u044F <em>(yad\u0101)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F <em>(\u0101lokya)</em> \u0412\u043E\u0441\u0442\u043E\u0440\u0433\u0430 <em>(\u0101hl\u0101dam)</em> <em>(\u0438)</em> \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C <em>(nimajjya)</em>, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C <em>(iva)</em>, \u0432 \u041E\u0437\u0435\u0440\u043E <em>(hrade)</em> \u0438\u0437 --maya\u1E25-- <em>(maye)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(am\u1E5Bta)</em>, \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0442 -- \u0442.\u0435. \xAB\u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442\xBB-- <em>(dadhati)</em> \u0412\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 <em>(antar)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F <em>(tattvam)</em> \u0432 \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(kim-api)</em>. \u0422\u044B <em>(bhav\u0101n)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E [\u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F] <em>(kila)</em> \u0442\u0435\u043C [\u0412\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C] <em>(tad)</em></p></div><div class="stanza"><a href="#s26" id="s26" class="num">26</a><p class="sans">\u0924\u094D\u0935\u092E\u0930\u094D\u0915\u0938\u094D\u0924\u094D\u0935\u0902 \u0938\u094B\u092E\u0938\u094D\u0924\u094D\u0935\u092E\u0938\u093F \u092A\u0935\u0928\u0938\u094D\u0924\u094D\u0935\u0902 \u0939\u0941\u0924\u0935\u0939\u0938\u094D\u0924\u094D\u0935\u092E\u093E\u092A\u0938\u094D\u0924\u094D\u0935\u0902 \u0935\u094D\u092F\u094B\u092E \u0924\u094D\u0935\u092E\u0941 \u0927\u0930\u0923\u093F\u0930\u093E\u0924\u094D\u092E\u093E \u0924\u094D\u0935\u092E\u093F\u0924\u093F \u091A \u0964<br> \u092A\u0930\u093F\u091A\u094D\u091B\u093F\u0928\u094D\u0928\u093E\u092E\u0947\u0935\u0902 \u0924\u094D\u0935\u092F\u093F \u092A\u0930\u093F\u0923\u0924\u093E \u0935\u093F\u092D\u094D\u0930\u0924\u0941 \u0917\u093F\u0930\u0902 \u0928 \u0935\u093F\u0926\u094D\u092E\u0938\u094D\u0924\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u0935\u092F\u092E\u093F\u0939 \u0924\u0941 \u092F\u0924\u094D\u0924\u094D\u0935\u0902 \u0928 \u092D\u0935\u0938\u093F \u0965\u0968\u096C\u0965</p><p class="trans">Tvamarkastva\u1E41 somastvamasi pavanastva\u1E41 hutavahastvam\u0101pastva\u1E41 vyoma tvamu dhara\u1E47ir\u0101tm\u0101 tvamiti ca \u0964<br> Paricchinn\u0101meva\u1E41 tvayi pari\u1E47at\u0101 bibhratu gira\u1E41 na vidmastattattva\u1E41 vayamiha tu yattva\u1E41 na bhavasi \u096526\u0965</p><p>\xAB\u0422\u044B <em>(tvam)</em> \u2014 \u0441\u043E\u043B\u043D\u0446\u0435 <em>(arka\u1E25)</em>; \u0422\u044B <em>(tvam)</em>\u2014 \u043B\u0443\u043D\u0430 <em>(soma\u1E25)</em>; \u0422\u044B <em>(tvam)</em> \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F <em>(asi)</em> \u0432\u043E\u0437\u0434\u0443\u0445\u043E\u043C <em>(pavana\u1E25)</em>; \u0422\u044B <em>(tvam)</em> \u2014 \u043E\u0433\u043E\u043D\u044C --\xAB\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435\xBB-- <em>(huta-vaha\u1E25)</em>; \u0422\u044B <em>(tvam)</em> \u2014 \u0432\u043E\u0434\u0430 <em>(\u0101pa\u1E25)</em>; \u0422\u044B <em>(tvam)</em> \u2014 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E_ <em>(vyoma)</em>._ \u0422\u044B <em>(tvam)</em> \u2014 \u0432\u043E \u0438\u0441\u0442\u0438\u043D\u0443 <em>(u)</em> \u0437\u0435\u043C\u043B\u044F <em>(dhara\u1E47i\u1E25)</em> \u0438 <em>(ca)</em> \u0422\u044B <em>(tvam)</em> \u2014 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tm\u0101)</em>\xBB --\xABiti\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043A\u0430\u0432\u044B\u0447\u043A\u0438--. \u0418\u0442\u0430\u043A <em>(evam)</em>, [\u043F\u0443\u0441\u0442\u044C] \u0442\u0435, \u043A\u0442\u043E \u043F\u0440\u0435\u0442\u0435\u0440\u043F\u0435\u043B \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F --\u043C\u0443\u0434\u0440\u0435\u0446\u044B-- <em>(pari\u1E47at\u0101\u1E25)</em> \u0442\u0440\u0435\u043F\u0435\u0442\u043D\u043E \u0445\u0440\u0430\u043D\u044F\u0442 <em>(bibhratu)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 <em>(paricchinn\u0101m)</em> \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F --\u0434\u043E\u0441\u043B. \xAB\u0441\u043B\u043E\u0432\u0430\xBB-- <em>(giram)</em> \u0422\u0435\u0431\u044F <em>(tvayi)</em>! \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(iha)</em>, \u043C\u044B <em>(vayam)</em> \u043D\u0435 <em>(na)</em> \u0437\u043D\u0430\u0435\u043C <em>(vidma\u1E25)</em> \u0442\u043E\u0439 <em>(tad)</em> \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(tattvam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0439 <em>(yad)</em> \u0422\u044B <em>(tvam)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u043B\u0441\u044F \u0431\u044B <em>(na bhavasi)</em></p></div><div class="stanza"><a href="#s27" id="s27" class="num">27</a><p class="sans">\u0924\u094D\u0930\u092F\u0940\u0902 \u0924\u093F\u0938\u094D\u0930\u094B \u0935\u0943\u0924\u094D\u0924\u0940\u0938\u094D\u0924\u094D\u0930\u093F\u092D\u0941\u0935\u0928\u092E\u0925\u094B \u0924\u094D\u0930\u0940\u0928\u092A\u093F \u0938\u0941\u0930\u093E\u0928\u0915\u093E\u0930\u093E\u0926\u094D\u092F\u0948\u0930\u094D\u0935\u0930\u094D\u0923\u0948\u0938\u094D\u0924\u094D\u0930\u093F\u092D\u093F\u0930\u092D\u093F\u0926\u0927\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u0935\u093F\u0915\u0943\u0924\u093F \u0964<br> \u0924\u0941\u0930\u0940\u092F\u0902 \u0924\u0947 \u0927\u093E\u092E \u0927\u094D\u0935\u0928\u093F\u092D\u093F\u0930\u0935\u0930\u0941\u0928\u094D\u0927\u093E\u0928\u092E\u0923\u0941\u092D\u093F\u0903 \u0938\u092E\u0938\u094D\u0924\u0902 \u0935\u094D\u092F\u0938\u094D\u0924\u0902 \u0924\u094D\u0935\u093E\u0902 \u0936\u0930\u0923\u0926 \u0917\u0943\u0923\u093E\u0924\u094D\u092F\u094B\u092E\u093F\u0924\u093F \u092A\u0926\u092E\u094D \u0965\u0968\u096D\u0965</p><p class="trans">Tray\u012B\u1E41 tisro v\u1E5Btt\u012Bstribhuvanamatho tr\u012Bnapi sur\u0101nak\u0101r\u0101dyairvar\u1E47aistribhirabhidadhatt\u012Br\u1E47avik\u1E5Bti \u0964<br> Tur\u012Bya\u1E41 te dh\u0101ma dhvanibhiravarundh\u0101nama\u1E47ubhi\u1E25 samasta\u1E41 vyasta\u1E41 tv\u0101\u1E41 \u015Bara\u1E47ada g\u1E5B\u1E47\u0101tyomiti padam \u096527\u0965</p><p>\u041E \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u0443\u0431\u0435\u0436\u0438\u0449\u0435 <em>(\u015Bara\u1E47a)</em>! \u0421\u043B\u043E\u0432\u043E <em>(padam)</em> \xABOm\xBB <em>(om-iti)</em> \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 <em>(g\u1E5B\u1E47\u0101ti)</em> \u0422\u0435\u0431\u044F <em>(tv\u0101m)</em> \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E <em>(vyastam)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E [\u0441\u0432\u043E\u0438\u0445] \u0442\u0440\u0451\u0445 <em>(tribhi\u1E25)</em> \u0431\u0443\u043A\u0432 <em>(var\u1E47ai\u1E25)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0445 \u0438\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445] \u0444\u043E\u0440\u043C <em>(\u0101k\u0101ra)</em> \u0438 \u0442.\u0434. <em>(\u0101dyai\u1E25)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442] \u0442\u0440\u0438 \u0412\u0435\u0434\u044B <em>(tray\u012Bm)</em>, \u0442\u0440\u0438 <em>(tisras)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] --\u0442.e. \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D-- <em>(v\u1E5Btt\u012B\u1E25)</em>, \u0442\u0440\u0438 <em>(tri)</em> \u043C\u0438\u0440\u0430 <em>(bhuvanam)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(atho... api)</em> \u0442\u0440\u0438 <em>(tr\u012Bn)</em> \u0431\u043E\u0433\u0430 <em>(sur\u0101n)</em>. [\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0422\u044B] \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0448\u044C\u0441\u044F <em>(abhidadhat)</em> \u043A\u0430\u043A <em>(\u0442\u0430 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C),</em> \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0435\u0442\u0435\u0440\u043F\u0435\u043B\u0430 <em>(t\u012Br\u1E47a)</em> [\u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E] \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 <em>(vik\u1E5Bti)</em>. [\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C], \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E [\u044D\u0442\u0438\u0445 \u0441\u0430\u043C\u044B\u0445 \u0442\u0440\u0451\u0445] \u0442\u043E\u043D\u043A\u0438\u0445 <em>(anubhi\u1E25)</em> \u0437\u0432\u0443\u043A\u043E\u0432 --dhvani-- <em>(dhvanibhi\u1E25)</em>, [\u0441\u043B\u043E\u0432\u043E \xAB\u041E\u043C\xBB \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0422\u0435\u0431\u044F] \u0432 \u0446\u0435\u043B\u043E\u043C <em>(samastam)</em>, [\u0442\u0430\u043A \u043A\u0430\u043A] \u043E\u043D\u043E \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 <em>(avarundh\u0101nam)</em> \u0427\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0435 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] --\u0442.e. \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F \u0432\u0441\u0435\u0445 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439-- <em>(tur\u012Byam)</em>, [\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F] \u0422\u0432\u043E\u0435\u0439 <em>(te)</em> [\u0422\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439] \u041E\u0431\u0438\u0442\u0435\u043B\u044C\u044E \u0438\u043B\u0438 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(dh\u0101ma)</em></p></div><div class="stanza"><a href="#s28" id="s28" class="num">28</a><p class="sans">\u092D\u0935\u0903 \u0936\u0930\u094D\u0935\u094B \u0930\u0941\u0926\u094D\u0930\u0903 \u092A\u0936\u0941\u092A\u0924\u093F\u0930\u0925\u094B\u0917\u094D\u0930\u0903 \u0938\u0939\u092E\u0939\u093E\u0902\u0938\u094D\u0924\u0925\u093E \u092D\u0940\u092E\u0947\u0936\u093E\u0928\u093E\u0935\u093F\u0924\u093F \u092F\u0926\u092D\u093F\u0927\u093E\u0928\u093E\u0937\u094D\u091F\u0915\u092E\u093F\u0926\u092E\u094D \u0964<br> \u0905\u092E\u0941\u0937\u094D\u092E\u093F\u0928\u094D\u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915\u0902 \u092A\u094D\u0930\u0935\u093F\u091A\u0930\u0924\u093F \u0926\u0947\u0935 \u0936\u094D\u0930\u0941\u0924\u093F\u0930\u092A\u093F \u092A\u094D\u0930\u093F\u092F\u093E\u092F\u093E\u0938\u094D\u092E\u0948 \u0927\u093E\u092E\u094D\u0928\u0947 \u092A\u094D\u0930\u0935\u093F\u0939\u093F\u0924\u0928\u092E\u0938\u094D\u092F\u094B\u093D\u0938\u094D\u092E\u093F \u092D\u0935\u0924\u0947 \u0965\u0968\u096E\u0965</p><p class="trans">Bhava\u1E25 \u015Barvo rudra\u1E25 pa\u015Bupatirathogra\u1E25 sahamah\u0101\u1E41stath\u0101 bh\u012Bme\u015B\u0101n\u0101viti yadabhidh\u0101n\u0101\u1E63\u1E6Dakamidam \u0964<br> Amu\u1E63minpratyeka\u1E41 pravicarati deva \u015Brutirapi priy\u0101y\u0101smai dh\u0101mne pravihitanamasyo&#39;smi bhavate \u096528\u0965</p><p>\xAB\u0411\u0445\u0430\u0432\u0430 <em>(bhava\u1E25)</em>, \u0428\u0430\u0440\u0432\u0430 <em>(\u015Barva\u1E25)</em>, \u0420\u0443\u0434\u0440\u0430 <em>(rudra\u1E25)</em>, \u041F\u0430\u0448\u0443\u043F\u0430\u0442\u0438 <em>(pa\u015Bupati\u1E25)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(atha)</em> \u0423\u0433\u0440\u0430 <em>(ugra\u1E25)</em> \u0438 <em>(saha)</em> \u041C\u0430\u0445\u0430\u0430\u0434\u0435\u0432\u0430 <em>(mah\u0101n)</em> \u0438 <em>(tath\u0101)</em> \u0411\u0445\u0438\u0438\u043C\u0430 <em>(bh\u012Bma)</em> \u0438 \u0418\u0438\u0448\u0430\u0430\u043D\u0430 <em>(\u012B\u015B\u0101nau)</em>\xBB --\xABiti\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043A\u0430\u0432\u044B\u0447\u043A\u0438--. \u042D\u0442\u043E <em>(idam)</em> \u2013 \u0433\u0440\u0443\u043F\u043F\u0430, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 \u0432\u043E\u0441\u044C\u043C\u0438 <em>(a\u1E63\u1E6Dakam)</em> \u0438\u043C\u0451\u043D <em>(abhidh\u0101na)</em> \u0442\u043E\u0433\u043E <em>(\u0428\u0438\u0432\u044B)</em> <em>(yad)</em>. \u041E \u0411\u043E\u0433 <em>(deva)</em>! \u0414\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u0428\u0440\u0443\u0442\u0438 --\u0412\u0435\u0434\u044B-- <em>(\u015Bruti\u1E25)</em> \u0442\u0449\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442 <em>(pravicarati)</em> \u043A\u0430\u0436\u0434\u043E\u0435 \u0438\u0437 \u043D\u0438\u0445 <em>(pratyekam)</em> \u0432 \u044D\u0442\u043E\u0439 <em>(\u0433\u0440\u0443\u043F\u043F\u0435)</em> <em>(amu\u1E63min)</em>, \u042F \u043F\u0440\u0435\u043A\u043B\u043E\u043D\u044F\u044E\u0441\u044C <em>(pravihita-namasya\u1E25 asmi)</em> \u043F\u0435\u0440\u0435\u0434 \u044D\u0442\u043E\u0439 <em>(asmai)</em> \u0434\u043E\u0440\u043E\u0433\u043E\u0439 <em>(priy\u0101ya)</em> [\u0422\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439] \u041E\u0431\u0438\u0442\u0435\u043B\u044C\u044E \u0438\u043B\u0438 [\u0412\u044B\u0441\u0448\u0438\u043C] \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C --dh\u0101ma-- <em>(dh\u0101mne)</em>, [\u0441\u0443\u0442\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F] \u0422\u044B --bhav\u0101n-- <em>(bhavate)</em></p></div><div class="stanza"><a href="#s29" id="s29" class="num">29</a><p class="sans">\u0928\u092E\u094B \u0928\u0947\u0926\u093F\u0937\u094D\u0920\u093E\u092F \u092A\u094D\u0930\u093F\u092F\u0926\u0935 \u0926\u0935\u093F\u0937\u094D\u0920\u093E\u092F \u091A \u0928\u092E\u094B \u0928\u092E\u0903 \u0915\u094D\u0937\u094B\u0926\u093F\u0937\u094D\u0920\u093E\u092F \u0938\u094D\u092E\u0930\u0939\u0930 \u092E\u0939\u093F\u0937\u094D\u0920\u093E\u092F \u091A \u0928\u092E\u0903 \u0964<br> \u0928\u092E\u094B \u0935\u0930\u094D\u0937\u093F\u0937\u094D\u0920\u093E\u092F \u0924\u094D\u0930\u093F\u0928\u092F\u0928 \u092F\u0935\u093F\u0937\u094D\u0920\u093E\u092F \u091A \u0928\u092E\u094B \u0928\u092E\u0903 \u0938\u0930\u094D\u0935\u0938\u094D\u092E\u0948 \u0924\u0947 \u0924\u0926\u093F\u0926\u092E\u093F\u0924\u093F\u0938\u0930\u094D\u0935\u093E\u092F \u091A \u0928\u092E\u0903 \u0965\u0968\u096F\u0965</p><p class="trans">Namo nedi\u1E63\u1E6Dh\u0101ya priyadava davi\u1E63\u1E6Dh\u0101ya ca namo nama\u1E25 k\u1E63odi\u1E63\u1E6Dh\u0101ya smarahara mahi\u1E63\u1E6Dh\u0101ya ca nama\u1E25 \u0964<br> Namo var\u1E63i\u1E63\u1E6Dh\u0101ya trinayana yavi\u1E63\u1E6Dh\u0101ya ca namo nama\u1E25 sarvasmai te tadidamitisarv\u0101ya ca nama\u1E25 \u096529\u0965</p><p>\u041E \u0422\u044B, \u043E\u0431\u043E\u0436\u0430\u044E\u0449\u0438\u0439 <em>(priya)</em> \u043E\u0433\u043E\u043D\u044C <em>(dava)</em>! \u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u043C\u043E\u043C\u0443 \u0411\u043B\u0438\u0437\u043A\u043E\u043C\u0443 <em>(nedi\u1E63\u1E6Dh\u0101ya)</em> \u0438 <em>(ca)</em> \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u043C\u043E\u043C\u0443 \u0414\u0430\u043B\u0451\u043A\u043E\u043C\u0443 <em>(davi\u1E63\u1E6Dh\u0101ya)</em>. \u041E \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C <em>(hara)</em> \u041A\u0430\u0430\u043C\u0430\u0434\u0435\u0432\u044B [\u2014 \u0431\u043E\u0433\u0430 \u043B\u044E\u0431\u0432\u0438] <em>(smara)</em>! \u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u043C\u043E\u043C\u0443 \u041C\u0430\u043B\u043E\u043C\u0443 <em>(k\u1E63odi\u1E63\u1E6Dh\u0101ya)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u043C\u043E\u043C\u0443 \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443 <em>(mahi\u1E63\u1E6Dh\u0101ya)</em>. \u041E \u0422\u0440\u0435\u0445\u0433\u043B\u0430\u0437\u044B\u0439 [\u0428\u0438\u0432\u0430] <em>(trinayana)</em>! \u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0442\u0430\u0440\u0435\u0439\u0448\u0435\u043C\u0443 <em>(var\u1E63i\u1E63\u1E6Dh\u0101ya)</em> \u0438 <em>(ca)</em> \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u043C\u043E\u043C\u0443 \u041C\u043E\u043B\u043E\u0434\u043E\u043C\u0443 <em>(yavi\u1E63\u1E6Dh\u0101ya)</em>. \u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0422\u0435\u0431\u0435 <em>(te)</em>, \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043C --sarva-- <em>(sarvasmai)</em>, <em>\u0430 \u0442\u0430\u043A\u0436\u0435</em> <em>(ca)</em> \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F <em>(namas)</em> \u0421\u0430\u0440\u0432\u0435 --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B-- <em>(sarv\u0101ya)</em>, [\u0442\u0430\u043A \u043A\u0430\u043A \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] \xAB\u0442\u043E\u0433\u043E <em>(tad)</em> \u0438 \u0441\u0435\u0433\u043E <em>(idam-iti)</em>\xBB --\u0428\u0438\u0432\u0430 \u0437\u043E\u0432\u0451\u0442\u0441\u044F \xAB\u0421\u0430\u0440\u0432\u043E\u0439\xBB, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u041E\u043D \u2014 \u044D\u0442\u043E\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0438 \u0442\u043E\u0442, \u044D\u0442\u043E \u0436\u0438\u0432\u043E\u0442\u043D\u043E\u0435 \u0438 \u0442\u043E, \u044D\u0442\u043E\u0442 \u043E\u0431\u044A\u0435\u043A\u0442 \u0438 \u0442\u043E\u0442 \u0438 \u0442.\u0434... \u041E\u043D \u0432\u0441\u0451 \u0438 \u0432\u0441\u0435--</p></div><div class="stanza"><a href="#s30" id="s30" class="num">30</a><p class="sans">\u092C\u0939\u0932\u0930\u091C\u0938\u0947 \u0935\u093F\u0936\u094D\u0935\u094B\u0924\u094D\u092A\u0924\u094D\u0924\u094C \u092D\u0935\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u092A\u094D\u0930\u092C\u0932\u0924\u092E\u0938\u0947 \u0924\u0924\u094D\u0938\u0902\u0939\u093E\u0930\u0947 \u0939\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0964<br> \u091C\u0928\u0938\u0941\u0916\u0915\u0943\u0924\u0947 \u0938\u0924\u094D\u0924\u094D\u0935\u094B\u0926\u094D\u0930\u093F\u0915\u094D\u0924\u094C \u092E\u0943\u0921\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u092A\u094D\u0930\u092E\u0939\u0938\u093F \u092A\u0926\u0947 \u0928\u093F\u0938\u094D\u0924\u094D\u0930\u0948\u0917\u0941\u0923\u094D\u092F\u0947 \u0936\u093F\u0935\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u0969\u0966\u0965</p><p class="trans">Bahalarajase vi\u015Bvotpattau bhav\u0101ya namo nama\u1E25 prabalatamase tatsa\u1E41h\u0101re har\u0101ya namo nama\u1E25 \u0964<br> Janasukhak\u1E5Bte sattvodriktau m\u1E5B\u1E0D\u0101ya namo nama\u1E25 pramahasi pade nistraigu\u1E47ye \u015Biv\u0101ya namo nama\u1E25 \u096530\u0965</p><p>\u041C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0439 <em>(namas namas)</em> \u0411\u0445\u0430\u0432\u0435 -- \u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435\xBB-- <em>(bhav\u0101ya)</em>, [\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] <em>Vi\u015Bvotpatti</em> --\u0434\u043E\u0441\u043B. \xAB\u0442\u043E\u0442, \u0438\u0437 \u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F\xBB, \u0442\u043E \u0435\u0441\u0442\u044C Brahm\u0101, \u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044C-- <em>(vi\u015Bvotpattau)</em>, [\u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442] \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E <em>(bahala)</em> Rajogu\u1E47a --\u0442.e. \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \xAB\u0440\u0430\u0434\u0436\u0430\u0441\xBB-- <em>(rajase)</em>. \u042F \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C <em>(namas namas)</em> \u0425\u0430\u0440\u0443 --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C\xBB-- <em>(har\u0101ya)</em>, [\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] <em>Tatsa\u1E41h\u0101ra</em> --\u0434\u043E\u0441\u043B. \xAB\u0442\u043E\u0442, \u043A\u0442\u043E \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0435\u0442 \u044D\u0442\u0443 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E]\xBB, \u0442\u043E \u0435\u0441\u0442\u044C, \u0420\u0443\u0434\u0440\u0430, \u0420\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C-- <em>(tatsa\u1E41h\u0101re)</em> [\u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442] \u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E <em>(prabala)</em> Tamogu\u1E47a --\u0442.e. \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \xAB\u0442\u0430\u043C\u0430\u0441\xBB-- <em>(tamase)</em>. \u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C <em>(namas namas)</em> \u041C\u0440\u0438\u0434\u0443 --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439\xBB \u0438\u043B\u0438 \xAB\u043C\u0438\u043B\u043E\u0441\u0442\u0438\u0432\u044B\u0439\xBB-- <em>(m\u1E5B\u1E0D\u0101ya)</em>, [\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] <em>Sattvodrikti</em> --\u0434\u043E\u0441\u043B. \xAB\u0442\u043E\u0442, \u0432 \u043A\u043E\u043C \u043E\u0431\u0438\u043B\u044C\u043D\u0430 Sattvagu\u1E47a \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \xAB\u0441\u0430\u0442\u0442\u0432\u0430\xBB, \u0442\u043E \u0435\u0441\u0442\u044C, \u0412\u0438\u0448\u043D\u0443, \u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u0442\u0435\u043B\u044F-- <em>(sattvodriktau)</em> \u0432\u043E \u0438\u043C\u044F <em>(k\u1E5Bte)</em> \u0441\u0447\u0430\u0441\u0442\u044C\u044F <em>(sukha)</em> [\u0432\u0441\u0435\u0445] \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(jana)</em>. \u041C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0439 <em>(namas namas)</em> \u0428\u0438\u0432\u0435 --\u0434\u043E\u0441\u043B. \xAB\u0411\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0439\xBB-- <em>(\u015Biv\u0101ya)</em>, [\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] \u0441\u0438\u044F\u044E\u0449\u0435\u0433\u043E <em>(pramahasi)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pade)</em>, \u043D\u0435 \u043D\u0430\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0433\u0443\u043D\u0430\u043C\u0438 \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(nistraigu\u1E47ye)</em></p></div><div class="stanza"><a href="#s31" id="s31" class="num">31</a><p class="sans">\u0915\u0943\u0936\u092A\u0930\u093F\u0923\u0924\u093F \u091A\u0947\u0924\u0903 \u0915\u094D\u0932\u0947\u0936\u0935\u0936\u094D\u092F\u0902 \u0915\u094D\u0935 \u091A\u0947\u0926\u0902 \u0915\u094D\u0935 \u091A \u0924\u0935 \u0917\u0941\u0923\u0938\u0940\u092E\u094B\u0932\u094D\u0932\u0919\u094D\u0918\u093F\u0928\u0940 \u0936\u0936\u094D\u0935\u0926\u0943\u0926\u094D\u0927\u093F\u0903 \u0964<br> \u0907\u0924\u093F \u091A\u0915\u093F\u0924\u092E\u092E\u0928\u094D\u0926\u0940\u0915\u0943\u0924\u094D\u092F \u092E\u093E\u0902 \u092D\u0915\u094D\u0924\u093F\u0930\u093E\u0927\u093E\u0926\u094D\u0935\u0930\u0926 \u091A\u0930\u0923\u092F\u094B\u0938\u094D\u0924\u0947 \u0935\u093E\u0915\u094D\u092F\u092A\u0941\u0937\u094D\u092A\u094B\u0939\u093E\u0930\u092E\u094D \u0965\u0969\u0967\u0965</p><p class="trans">K\u1E5B\u015Bapari\u1E47ati ceta\u1E25 kle\u015Bava\u015Bya\u1E41 kva ceda\u1E41 kva ca tava gu\u1E47as\u012Bmolla\u1E45ghin\u012B \u015Ba\u015Bvad\u1E5Bddhi\u1E25 \u0964<br> Iti cakitamamand\u012Bk\u1E5Btya m\u0101\u1E41 bhaktir\u0101dh\u0101dvarada cara\u1E47ayoste v\u0101kyapu\u1E63popah\u0101ram \u096531\u0965</p><p>\u041A\u0430\u043A <em>(kva ca)</em> \u0441\u043B\u0430\u0431\u043E <em>(k\u1E5B\u015Ba)</em> \u0440\u0430\u0437\u0432\u0438\u0442 <em>(pari\u1E47ati)</em> \u044D\u0442\u043E\u0442 <em>(idam)</em> \u0443\u043C <em>(cetas)</em>, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u044B\u0439 <em>(va\u015Byam)</em> \u041A\u043B\u0435\u0448\u0430\u043C\u0438 --\u0442.e. \u0448\u0438\u0440\u043E\u043A\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C\u0438 \u043F\u044F\u0442\u044C\u044E \u043D\u0430\u043F\u0430\u0441\u0442\u044F\u043C\u0438: \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E\u043C, \u044D\u0433\u043E, \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C\u044E, \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C \u0438 \u0441\u0442\u0440\u0430\u0445\u043E\u043C \u0441\u043C\u0435\u0440\u0442\u0438-- <em>(kle\u015Ba)</em>. \u0418 \u043A\u0430\u043A <em>(kva ca)</em> \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E \u0438 \u0432\u0435\u0447\u043D\u043E <em>(\u015Ba\u015Bvat)</em> \u0422\u0432\u043E\u0451 <em>(tava)</em> \u041F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u043D\u0438\u0435 <em>(\u1E5Bddhi\u1E25)</em>, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u0437\u0430 <em>(ulla\u1E45ghin\u012B)</em> \u0433\u0440\u0430\u043D\u0438\u0446\u0443 <em>(s\u012Bm\u0101)</em>, [\u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u0443\u044E \u0442\u0440\u0435\u043C\u044F] \u0433\u0443\u043D\u0430\u043C\u0438 \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(gu\u1E47a)</em>! \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, [\u0445\u043E\u0442\u044F \u044F \u0438] \u043E\u0447\u0435\u043D\u044C <em>(amand\u012Bk\u1E5Btya)</em> \u043D\u0430\u043F\u0443\u0433\u0430\u043D <em>(cakitam)</em> <em>(\u044D\u0442\u0438\u043C)</em>, \u043E \u0414\u0430\u0440\u0443\u044E\u0449\u0438\u0439 <em>(da)</em> \u043C\u0438\u043B\u043E\u0441\u0442\u044C <em>(vara)</em>, \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(bhakti\u1E25)</em> \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u043B\u0430 <em>(\u0101dh\u0101t)</em> \u043C\u0435\u043D\u044F <em>(m\u0101m)</em> \u043F\u0440\u0435\u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 <em>(upah\u0101ram)</em> \u0446\u0432\u0435\u0442\u044B <em>(pu\u1E63pa)</em> [\u0432 \u0432\u0438\u0434\u0435] \u0441\u043B\u043E\u0432 <em>(v\u0101kya)</em> \u043A \u0422\u0432\u043E\u0438\u043C <em>(te)</em> \u0441\u0442\u043E\u043F\u0430\u043C <em>(cara\u1E47ayo\u1E25)</em></p></div><div class="stanza"><a href="#s32" id="s32" class="num">32</a><p class="sans">\u0905\u0938\u093F\u0924\u0917\u093F\u0930\u093F\u0938\u092E\u0902 \u0938\u094D\u092F\u093E\u0924\u094D\u0915\u091C\u094D\u091C\u0932\u0902 \u0938\u093F\u0928\u094D\u0927\u0941\u092A\u093E\u0924\u094D\u0930\u0947 \u0938\u0941\u0930\u0924\u0930\u0941\u0935\u0930\u0936\u093E\u0916\u093E \u0932\u0947\u0916\u0928\u0940 \u092A\u0924\u094D\u0930\u092E\u0941\u0930\u094D\u0935\u0940 \u0964<br> \u0932\u093F\u0916\u0924\u093F \u092F\u0926\u093F \u0917\u0943\u0939\u0940\u0924\u094D\u0935\u093E \u0936\u093E\u0930\u0926\u093E \u0938\u0930\u094D\u0935\u0915\u093E\u0932\u0902 \u0924\u0926\u092A\u093F \u0924\u0935 \u0917\u0941\u0923\u093E\u0928\u093E\u092E\u0940\u0936 \u092A\u093E\u0930\u0902 \u0928 \u092F\u093E\u0924\u093F \u0965\u0969\u0968\u0965</p><p class="trans">Asitagirisama\u1E41 sy\u0101tkajjala\u1E41 sindhup\u0101tre surataruvara\u015B\u0101kh\u0101 lekhan\u012B patramurv\u012B \u0964<br> Likhati yadi g\u1E5Bh\u012Btv\u0101 \u015B\u0101rad\u0101 sarvak\u0101la\u1E41 tadapi tava gu\u1E47\u0101n\u0101m\u012B\u015Ba p\u0101ra\u1E41 na y\u0101ti \u096532\u0965</p><p>[\u0415\u0441\u043B\u0438 \u0431\u044B \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E] \u043B\u0430\u043C\u043F\u043E\u0432\u043E\u0439 \u0441\u0430\u0436\u0438 -- \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u043E\u0439 \u043A\u0430\u043A \u0447\u0435\u0440\u043D\u0438\u043B\u0430-- <em>(kajjalam)</em>, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0435 <em>(samam)</em> \u0447\u0435\u0440\u043D\u043E\u0439 <em>(asita)</em> \u0433\u043E\u0440\u0435 <em>(giri)</em>, \u0431\u044B\u043B\u043E \u0431\u044B <em>(sy\u0101t)</em> <em>(\u043D\u0430\u043B\u0438\u0442\u043E \u0432)</em> \u043E\u043A\u0435\u0430\u043D <em>(sindhu)</em>, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0439 \u0440\u043E\u043B\u044C \u0441\u043E\u0441\u0443\u0434\u0430 --\u0442.e. \u0447\u0435\u0440\u043D\u0438\u043B\u044C\u043D\u0438\u0446\u044B-- <em>(p\u0101tre)</em>, <em>(\u0438 \u0435\u0441\u043B\u0438 \u0431\u044B)</em> \u0432\u0435\u0442\u0432\u044C <em>(\u015B\u0101kh\u0101)</em> \u043B\u0443\u0447\u0448\u0435\u0433\u043E <em>(vara)</em> \u0434\u0435\u0440\u0435\u0432\u0430 <em>(taru)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em> --\u0442.e. \u043F\u0440\u043E\u0441\u043B\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E Kalpav\u1E5Bk\u1E63a-- [\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043B\u0430\u0441\u044C \u0431\u044B] \u0432 \u0432\u0438\u0434\u0435 \u0440\u0443\u0447\u043A\u0438 <em>(lekhan\u012B)</em>, <em>(\u0430 \u0441\u0430\u043C\u0430</em>_)_ \u0437\u0435\u043C\u043B\u044F <em>(urv\u012B)</em> \u2014 [\u0432 \u0432\u0438\u0434\u0435] \u043B\u0438\u0441\u0442\u0430 \u0434\u043B\u044F \u043F\u0438\u0441\u044C\u043C\u0430 <em>(patram)</em>, [\u0438] \u0435\u0441\u043B\u0438 \u0431\u044B <em>(yadi)</em> \u015A\u0101rad\u0101 --\u0442.e. \xABSarasvat\u012B\xBB, \u0440\u0435\u043A\u0430-\u0431\u043E\u0433\u0438\u043D\u044F, \u043E\u0431\u044B\u0447\u043D\u043E \u0430\u0441\u0441\u043E\u0446\u0438\u0438\u0440\u0443\u0435\u043C\u0430\u044F \u0441 \u043A\u0440\u0430\u0441\u043D\u043E\u0440\u0435\u0447\u0438\u0435\u043C \u0438 \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C-- <em>(\u015B\u0101rad\u0101)</em>, \u0432\u0437\u044F\u0432 [\u044D\u0442\u0438 \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u043D\u043E\u0441\u0442\u0438] <em>(g\u1E5Bh\u012Btv\u0101)</em>, \u043F\u0438\u0441\u0430\u043B\u0430 \u0431\u044B <em>(likhati)</em> \u0432\u0435\u0447\u043D\u043E <em>(sarvak\u0101lam)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u044D\u0442\u0430 [\u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u043C\u0435\u0442\u0430\u0444\u043E\u0440\u0430] <em>(tad)</em>, \u043E \u0411\u043E\u0433 <em>(\u012B\u015Ba)</em>, \u043D\u0435 <em>(na)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u043B\u0430 \u0431\u044B <em>(y\u0101ti)</em> \u043A\u043E\u043D\u0446\u0430 <em>(p\u0101ram)</em> \u0422\u0432\u043E\u0438\u0445 <em>(tava)</em> \u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 <em>(gu\u1E47\u0101n\u0101m)</em> --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0432\u0441\u0435 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0428\u0438\u0432\u044B \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0431\u044B\u0442\u044C \u043E\u043F\u0438\u0441\u0430\u043D\u044B, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u0442\u0430\u043A\u043E\u0439 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u0436, \u043A\u0430\u043A \u0441\u0430\u043C\u0430 Sarasvat\u012B \u0432\u0435\u0447\u043D\u043E \u0437\u0430\u043F\u0438\u0441\u044B\u0432\u0430\u043B\u0430 \u0431\u044B \u0438\u0445, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0435 \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u043D\u043E\u0441\u0442\u0438--</p></div><div class="stanza"><a href="#s33" id="s33" class="num">33</a><p class="sans">\u0905\u0938\u0941\u0930\u0938\u0941\u0930\u092E\u0941\u0928\u0940\u0928\u094D\u0926\u094D\u0930\u0948\u0930\u0930\u094D\u091A\u093F\u0924\u0938\u094D\u092F\u0947\u0928\u094D\u0926\u0941\u092E\u094C\u0932\u0947\u0930\u094D\u0917\u094D\u0930\u0925\u093F\u0924\u0917\u0941\u0923\u092E\u0939\u093F\u092E\u094D\u0928\u094B \u0928\u093F\u0930\u094D\u0917\u0941\u0923\u0938\u094D\u092F\u0947\u0936\u094D\u0935\u0930\u0938\u094D\u092F \u0964<br> \u0938\u0915\u0932\u0917\u0923\u0935\u0930\u093F\u0937\u094D\u0920\u0903 \u092A\u0941\u0937\u094D\u092A\u0926\u0928\u094D\u0924\u093E\u092D\u093F\u0927\u093E\u0928\u094B \u0930\u0941\u091A\u093F\u0930\u092E\u0932\u0918\u0941\u0935\u0943\u0924\u094D\u0924\u0948\u0903 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u092E\u0947\u0924\u091A\u094D\u091A\u0915\u093E\u0930 \u0965\u0969\u0969\u0965</p><p class="trans">Asurasuramun\u012Bndrairarcitasyendumaulergrathitagu\u1E47amahimno nirgu\u1E47asye\u015Bvarasya \u0964<br> Sakalaga\u1E47avari\u1E63\u1E6Dha\u1E25 pu\u1E63padant\u0101bhidh\u0101no ruciramalaghuv\u1E5Bttai\u1E25 stotrametaccak\u0101ra \u096533\u0965</p><p>[\u0413\u0430\u043D\u0434\u0445\u0430\u0440\u0432\u0430 \u0438\u043B\u0438 \u043D\u0435\u0431\u0435\u0441\u043D\u044B\u0439 \u043C\u0443\u0437\u044B\u043A\u0430\u043D\u0442] \u043F\u043E \u0438\u043C\u0435\u043D\u0438 <em>(abhidh\u0101na\u1E25)</em> Pu\u1E63padanta --\u0434\u043E\u0441\u043B. \xAB\u0441 \u0437\u0443\u0431\u0430\u043C\u0438 \u0438\u0437 \u0446\u0432\u0435\u0442\u043E\u0432\xBB-- <em>(pu\u1E63padanta)</em>, \u043B\u0443\u0447\u0448\u0438\u0439 <em>(vari\u1E63\u1E6Dha\u1E25)</em> \u0438\u0437 \u0432\u0441\u0435\u0439 <em>(sakala)</em> \u0433\u0440\u0443\u043F\u043F\u044B \u0441\u043B\u0443\u0433 \u0428\u0438\u0432\u044B <em>(ga\u1E47a)</em>, \u0441\u043E\u0447\u0438\u043D\u0438\u043B <em>(cak\u0101ra)</em> \u044D\u0442\u043E\u0442 <em>(etad)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0439 <em>(ruciram)</em> \u0433\u0438\u043C\u043D <em>(stotram)</em>, \u043D\u0430\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u0439 \u0434\u043B\u0438\u043D\u043D\u044B\u043C\u0438 <em>(alaghu)</em> \u043C\u0435\u0440\u0430\u043C\u0438 \u0441\u0442\u0438\u0445\u043E\u0441\u043B\u043E\u0436\u0435\u043D\u0438\u044F <em>(v\u1E5Bttai\u1E25)</em>, <em>(\u0432 \u0447\u0435\u0441\u0442\u044C)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvarasya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u043E\u0441\u0438\u0442 \u043B\u0443\u043D\u0443 <em>(indu)</em> \u043D\u0430 \u0421\u0432\u043E\u0435\u0439 \u0433\u043E\u043B\u043E\u0432\u0435 --mauli-- <em>(maule\u1E25)</em> \u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u044E\u0442\u0441\u044F <em>(arcitasya)</em> \u0418\u043D\u0434\u0440\u0430 --indre\u1E47a-- <em>(indrai\u1E25)</em>, \u043C\u0443\u0434\u0440\u0435\u0446\u044B <em>(muni)</em>, \u0431\u043E\u0433\u0438 <em>(sura)</em> \u0438 \u0434\u0435\u043C\u043E\u043D\u044B <em>(asura)</em>, \u0438 \u0447\u044C\u0451 \u0412\u0435\u043B\u0438\u0447\u0438\u0435 <em>(mahimna\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0445)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432 <em>(gu\u1E47a)</em>, \u043D\u0430\u043D\u0438\u0437\u0430\u043D\u043D\u044B\u0445 \u0432\u043C\u0435\u0441\u0442\u0435 [\u043D\u0430 \u043E\u0434\u043D\u0443 \u043D\u0438\u0442\u044C, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0431\u0443\u0441\u0438\u043D\u0430\u043C \u0432 \u043E\u0436\u0435\u0440\u0435\u043B\u044C\u0435] <em>(grathita)</em>, [\u0445\u043E\u0442\u044F \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E] \u043B\u0438\u0448\u0451\u043D \u043B\u044E\u0431\u044B\u0445 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 --nirgu\u1E47a-- <em>(nirgu\u1E47asya)</em></p></div><div class="stanza"><a href="#s34" id="s34" class="num">34</a><p class="sans">\u0905\u0939\u0930\u0939\u0930\u0928\u0935\u0926\u094D\u092F\u0902 \u0927\u0942\u0930\u094D\u091C\u091F\u0947\u0903 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u092E\u0947\u0924\u0924\u094D\u092A\u0920\u0924\u093F \u092A\u0930\u092E\u092D\u0915\u094D\u0924\u094D\u092F\u093E \u0936\u0941\u0926\u094D\u0927\u091A\u093F\u0924\u094D\u0924\u0903 \u092A\u0941\u092E\u093E\u0928\u094D \u092F\u0903 \u0964<br> \u0938 \u092D\u0935\u0924\u093F \u0936\u093F\u0935\u0932\u094B\u0915\u0947 \u0930\u0941\u0926\u094D\u0930\u0924\u0941\u0932\u094D\u092F\u0938\u094D\u0924\u0925\u093E\u093D\u0924\u094D\u0930 \u092A\u094D\u0930\u091A\u0941\u0930\u0924\u0930\u0927\u0928\u093E\u092F\u0941\u0903\u092A\u0941\u0924\u094D\u0930\u0935\u093E\u0928\u094D\u0915\u0940\u0930\u094D\u0924\u093F\u092E\u093E\u0902\u0936\u094D\u091A \u0965\u0969\u096A\u0965</p><p class="trans">Aharaharanavadya\u1E41 dh\u016Brja\u1E6De\u1E25 stotrametatpa\u1E6Dhati paramabhakty\u0101 \u015Buddhacitta\u1E25 pum\u0101n ya\u1E25 \u0964<br> Sa bhavati \u015Bivaloke rudratulyastath\u0101&#39;tra pracurataradhan\u0101yu\u1E25putrav\u0101nk\u012Brtim\u0101\u1E41\u015Bca \u096534\u0965</p><p>\u0427\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(pum\u0101n)</em> \u0441 \u0447\u0438\u0441\u0442\u044B\u043C \u0443\u043C\u043E\u043C <em>(\u015Buddha-citta\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> _\u0441 \u0432\u0435\u043B\u0438\u0447\u0430\u0439\u0448\u0435\u0439 <em>(parama)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(bhakty\u0101)</em> \u0434\u0435\u043D\u044C \u0437\u0430 \u0434\u043D\u0451\u043C <em>(ahar-ahar)</em> \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u043E <em>(anavadyam)</em> \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0435\u0442 <em>(pa\u1E6Dhati)</em> \u044D\u0442\u043E\u0442 <em>(etad)</em> \u0433\u0438\u043C\u043D <em>(stotram)</em> (\u0432 \u0447\u0435\u0441\u0442\u044C) <em>Dh\u016Brja\u1E6Di</em> --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0441 \u0433\u0440\u0443\u0437\u043E\u043C \u0438\u0437 \u0441\u043F\u0443\u0442\u0430\u043D\u043D\u044B\u0445 \u043B\u043E\u043A\u043E\u043D\u043E\u0432\xBB-- <em>(dh\u016Brja\u1E6De\u1E25)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(sa\u1E25 bhavati)</em> \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u044B\u043C <em>(tulya\u1E25)</em> \u0420\u0443\u0434\u0440\u0435 --\u0442.e. \u0428\u0438\u0432\u0435-- <em>(rudra)</em> \u0432 \u043C\u0438\u0440\u0435 \u0428\u0438\u0432\u044B <em>(\u015Biva-loke)</em> [\u043F\u043E\u0441\u043B\u0435 \u0441\u043C\u0435\u0440\u0442\u0438]. \u0422\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em>, [\u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C <em>(k\u012Brtim\u0101n)</em>, \u043C\u043D\u043E\u0433\u043E\u0434\u0435\u0442\u043D\u044B\u043C <em>(putrav\u0101n)</em>, [\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0434\u043E\u043B\u0433\u043E\u0439] \u0436\u0438\u0437\u043D\u044C\u044E <em>(\u0101yus)</em> \u0438 <em>(ca)</em> \u0431\u043E\u043B\u0435\u0435 <em>(tara)</em> \u043E\u0431\u0438\u043B\u044C\u043D\u044B\u043C <em>(pracura)</em> \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u043E\u043C <em>(dhana)</em> \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(atra)</em></p></div><div class="stanza"><a href="#s35" id="s35" class="num">35</a><p class="sans">\u0926\u0940\u0915\u094D\u0937\u093E \u0926\u093E\u0928\u0902 \u0924\u092A\u0938\u094D\u0924\u0940\u0930\u094D\u0925\u0902 \u092F\u094B\u0917\u092F\u093E\u0917\u093E\u0926\u093F\u0915\u093E\u0903 \u0915\u094D\u0930\u093F\u092F\u093E\u0903 \u0964<br> \u092E\u0939\u093F\u092E\u094D\u0928\u0903 \u0938\u094D\u0924\u0935 \u092A\u093E\u0920\u0938\u094D\u092F \u0915\u0932\u093E\u0902 \u0928\u093E\u0930\u094D\u0939\u0928\u094D\u0924\u093F \u0937\u094B\u0921\u0936\u0940\u092E\u094D \u0965\u0969\u096B\u0965</p><p class="trans">D\u012Bk\u1E63\u0101 d\u0101na\u1E41 tapast\u012Brtha\u1E41 yogay\u0101g\u0101dik\u0101\u1E25 kriy\u0101\u1E25 \u0964<br> Mahimna\u1E25 stavap\u0101\u1E6Dhasya kal\u0101\u1E41 n\u0101rhanti \u1E63o\u1E0Da\u015B\u012Bm \u096535\u0965</p><p>\u0418\u043D\u0438\u0446\u0438\u0430\u0446\u0438\u044F <em>(d\u012Bk\u1E63\u0101)</em>, \u0431\u043B\u0430\u0433\u043E\u0442\u0432\u043E\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(d\u0101nam)</em>, \u0430\u0441\u043A\u0435\u0437\u044B <em>(tapas)</em>, \u043F\u0430\u043B\u043E\u043C\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E <em>(t\u012Brtham)</em> <em>(\u0438 \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(kriy\u0101\u1E25)</em>, [\u0442\u0430\u043A\u0430\u044F \u043A\u0430\u043A] \u0419\u043E\u0433\u0430 <em>(yoga)</em>, \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435 <em>(y\u0101ga)</em> \u0438 \u0442.\u0434., <em>(\u0101dik\u0101\u1E25)</em> \u043D\u0435 <em>(na)</em> \u0441\u0442\u043E\u0438\u0442 <em>(arhanti)</em> [\u0434\u0430\u0436\u0435] \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 <em>(\u1E63o\u1E0Da\u015B\u012Bm)</em> \u0447\u0430\u0441\u0442\u0438 <em>(kal\u0101m)</em> [\u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0441\u0442\u043E\u0438\u0442] \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435 <em>(p\u0101\u1E6Dhasya)</em> [\u044D\u0442\u043E\u0433\u043E] \u0433\u0438\u043C\u043D\u0430 <em>(stava)</em> \u0412\u0435\u043B\u0438\u0447\u0438\u044F <em>(mahimna\u1E25)</em> \u0428\u0438\u0432\u044B</p></div><div class="stanza"><a href="#s36" id="s36" class="num">36</a><p class="sans">\u0906\u0938\u092E\u093E\u092A\u094D\u0924\u092E\u093F\u0926\u0902 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0902 \u092A\u0941\u0923\u094D\u092F\u0902 \u0917\u0928\u094D\u0927\u0930\u094D\u0935\u092D\u093E\u0937\u093F\u0924\u092E\u094D \u0964<br> \u0905\u0928\u094C\u092A\u092E\u094D\u092F\u0902 \u092E\u0928\u094B\u0939\u093E\u0930\u093F \u0936\u093F\u0935\u092E\u0940\u0936\u094D\u0935\u0930\u0935\u0930\u094D\u0923\u0928\u092E\u094D \u0965\u0969\u096C\u0965</p><p class="trans">\u0100sam\u0101ptamida\u1E41 stotra\u1E41 pu\u1E47ya\u1E41 gandharvabh\u0101\u1E63itam \u0964<br> Anaupamya\u1E41 manoh\u0101ri \u015Bivam\u012B\u015Bvaravar\u1E47anam \u096536\u0965</p><p>\u042D\u0442\u043E\u0442 <em>(idam)</em> \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0439 <em>(pu\u1E47yam)</em> \u0433\u0438\u043C\u043D <em>(stotram)</em>, \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0451\u043D\u043D\u044B\u0439 <em>(bh\u0101\u1E63itam)</em> [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C] \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043C\u0443\u0437\u044B\u043A\u0430\u043D\u0442\u043E\u043C [\u043F\u043E \u0438\u043C\u0435\u043D\u0438 Pu\u1E63padanta] <em>(gandharva)</em>, [\u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0439] \u043D\u0435\u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0451\u043D\u043D\u044B\u0435 <em>(anaupamyam)</em>, \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 <em>(manoh\u0101ri)</em> \u0438 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0435 <em>(\u015Bivam)</em> \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F <em>(var\u1E47anam)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em>, \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(\u0101sam\u0101ptam)</em></p></div><div class="stanza"><a href="#s37" id="s37" class="num">37</a><p class="sans">\u092E\u0939\u0947\u0936\u093E\u0928\u094D\u0928\u093E\u092A\u0930\u094B \u0926\u0947\u0935\u094B \u092E\u0939\u093F\u092E\u094D\u0928\u094B \u0928\u093E\u092A\u0930\u093E \u0938\u094D\u0924\u0941\u0924\u093F\u0903 \u0964<br> \u0905\u0918\u094B\u0930\u093E\u0928\u094D\u0928\u093E\u092A\u0930\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u094B \u0928\u093E\u0938\u094D\u0924\u093F \u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u0917\u0941\u0930\u094B\u0903 \u092A\u0930\u092E\u094D \u0965\u0969\u096D\u0965</p><p class="trans">Mahe\u015B\u0101nn\u0101paro devo mahimno n\u0101par\u0101 stuti\u1E25 \u0964<br> Aghor\u0101nn\u0101paro mantro n\u0101sti tattva\u1E41 guro\u1E25 param \u096537\u0965</p><p>\u041D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u0431\u043E\u0433\u0430 <em>(deva\u1E25)</em> \u0432\u044B\u0448\u0435 <em>(apara\u1E25)</em> \u041C\u0430\u0445\u0435\u0448\u0438 --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C\xBB-- <em>(mahe\u015B\u0101t)</em>, \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0433\u0438\u043C\u043D\u0430 <em>(stuti\u1E25)</em> \u0432\u044B\u0448\u0435 <em>(apar\u0101)</em> [\u044D\u0442\u043E\u0433\u043E] \xAB\u015Aivamahimna\u1E25 stotram\xBB <em>(mahimna\u1E25)</em>. \u041D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u041C\u0430\u043D\u0442\u0440\u044B --\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u043B\u043E\u0432\u0430-- <em>(mantra\u1E25)</em> \u0432\u044B\u0448\u0435 <em>(apara\u1E25)</em> \xABAghora\xBB --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u043D\u0435 \u0443\u0436\u0430\u0441\u0430\u044E\u0449\u0438\u0439\xBB-- <em>(aghora)</em> [\u0438] \u043D\u0435\u0442 <em>(na asti)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattvam)</em> \u0432\u044B\u0448\u0435 <em>(param)</em> \u0413\u0443\u0440\u0443 --\u0432 \u0441\u043C\u044B\u0441\u043B\u0435 \u043F\u044F\u0442\u043E\u0433\u043E \xABk\u1E5Btya\xBB \u0438\u043B\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0428\u0438\u0432\u044B, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u0430\u0440\u0443\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u041C\u0438\u043B\u043E\u0441\u0442\u044C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443-- <em>(guro\u1E25)</em></p></div><div class="stanza"><a href="#s38" id="s38" class="num">38</a><p class="sans">\u0915\u0941\u0938\u0941\u092E\u0926\u0936\u0928\u0928\u093E\u092E\u093E \u0938\u0930\u094D\u0935\u0917\u0928\u094D\u0927\u0930\u094D\u0935\u0930\u093E\u091C\u0903 \u0936\u093F\u0936\u0941\u0936\u0936\u0927\u0930\u092E\u094C\u0932\u0947\u0930\u094D\u0926\u0947\u0935\u0926\u0947\u0935\u0938\u094D\u092F \u0926\u093E\u0938\u0903 \u0964<br> \u0938 \u0916\u0932\u0941 \u0928\u093F\u091C\u092E\u0939\u093F\u092E\u094D\u0928\u094B \u092D\u094D\u0930\u0937\u094D\u0920 \u090F\u0935\u093E\u0938\u094D\u092F \u0930\u094B\u0937\u093E\u0924\u094D\u0938\u094D\u0924\u0935\u0928\u092E\u093F\u0926\u092E\u0915\u093E\u0930\u094D\u0937\u0940\u0926\u094D\u0926\u093F\u0935\u094D\u092F\u0926\u093F\u0935\u094D\u092F\u0902 \u092E\u0939\u093F\u092E\u094D\u0928\u0903 \u0965\u0969\u096E\u0965</p><p class="trans">Kusumada\u015Banan\u0101m\u0101 sarvagandharvar\u0101ja\u1E25 \u015Bi\u015Bu\u015Ba\u015Badharamaulerdevadevasya d\u0101sa\u1E25 \u0964<br> Sa khalu nijamahimno bhra\u1E63\u1E6Da ev\u0101sya ro\u1E63\u0101tstavanamidamak\u0101r\u1E63\u012Bddivyadivya\u1E41 mahimna\u1E25 \u096538\u0965</p><p>\u0426\u0430\u0440\u044C <em>(r\u0101ja\u1E25)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043C\u0443\u0437\u044B\u043A\u0430\u043D\u0442\u043E\u0432 <em>(gandharva)</em> \u043F\u043E \u0438\u043C\u0435\u043D\u0438 <em>(n\u0101m\u0101)</em> <em>Kusumada\u015Bana</em> --\u0441\u0438\u043D\u043E\u043D\u0438\u043C \u0442\u0435\u0440\u043C\u0438\u043D\u0443 \xABPu\u1E63padanta\xBB, \u0442.e. \xAB\u0441 \u0437\u0443\u0431\u0430\u043C\u0438 \u0438\u0437 \u0446\u0432\u0435\u0442\u043E\u0432\xBB, \u0442\u0430\u043A \u043A\u0430\u043A \xABkusuma\xBB = pu\u1E63pa (\u0446\u0432\u0435\u0442\u043E\u043A) \u0438 \xABda\u015Bana\xBB = danta (\u0437\u0443\u0431)-- <em>(kusumada\u015Bana)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043B\u0443\u0433\u043E\u0439 <em>(d\u0101sa\u1E25)</em> \u0411\u043E\u0433\u0430 <em>(devasya)</em> \u0431\u043E\u0433\u043E\u0432 <em>(deva)</em>, \u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E \u043C\u0435\u0441\u044F\u0446 _(\u015Bi\u015Bu _<em>\u015Ba\u015Badhara)</em> \u043D\u0430 \u0421\u0432\u043E\u0435\u0439 \u0433\u043E\u043B\u043E\u0432\u0435 --mauli-- <em>(maule\u1E25)</em>. \u041E\u043D --Pu\u1E63padanta-- <em>(sa\u1E25)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(khalu... eva)</em> \u043F\u0430\u043B <em>(bhra\u1E63\u1E6Da\u1E25)</em> \u0438\u0437 \u0441\u0432\u043E\u0435\u0433\u043E <em>(nija)</em> \u0432\u0435\u043B\u0438\u0447\u0438\u044F <em>(mahimna\u1E25)</em> \u0438\u0437-\u0437\u0430 \u044F\u0440\u043E\u0441\u0442\u0438 <em>(ro\u1E63\u0101t)</em> \u0428\u0438\u0432\u044B <em>(asya)</em> --\u0442\u0430\u043A \u043A\u0430\u043A Pu\u1E63padanta \u043D\u0435\u0447\u0430\u044F\u043D\u043D\u043E \u043D\u0430\u0441\u0442\u0443\u043F\u0438\u043B \u043D\u0430 \u0442\u0440\u0430\u0432\u0443, \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u0443\u044E \u0434\u043B\u044F \u0428\u0438\u0432\u044B-- [\u0438] \u0441\u043E\u0447\u0438\u043D\u0438\u043B <em>(ak\u0101r\u1E63\u012Bt)</em> \u044D\u0442\u043E\u0442 <em>(idam)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0439 <em>(divya)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 <em>(divyam)</em> \u0433\u0438\u043C\u043D \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u044F <em>(stavanam)</em> <em>(\u0432 \u0447\u0435\u0441\u0442\u044C)</em> \u0412\u0435\u043B\u0438\u0447\u0438\u044F [\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E \u0428\u0438\u0432\u044B] <em>(mahimna\u1E25)</em>, [\u0447\u0442\u043E\u0431 \u043E\u0431\u0440\u0435\u0441\u0442\u0438 \u0415\u0433\u043E \u043C\u0438\u043B\u043E\u0441\u0442\u044C]</p></div><div class="stanza"><a href="#s39" id="s39" class="num">39</a><p class="sans">\u0938\u0941\u0930\u0935\u0930\u092E\u0941\u0928\u093F\u092A\u0942\u091C\u094D\u092F\u0902 \u0938\u094D\u0935\u0930\u094D\u0917\u092E\u094B\u0915\u094D\u0937\u0948\u0915\u0939\u0947\u0924\u0941\u0902 \u092A\u0920\u0924\u093F \u092F\u0926\u093F \u092E\u0928\u0941\u0937\u094D\u092F\u0903 \u092A\u094D\u0930\u093E\u091E\u094D\u091C\u0932\u093F\u0930\u094D\u0928\u093E\u0928\u094D\u092F\u091A\u0947\u0924\u093E\u0903 \u0964<br> \u0935\u094D\u0930\u091C\u0924\u093F \u0936\u093F\u0935\u0938\u092E\u0940\u092A\u0902 \u0915\u093F\u0928\u094D\u0928\u0930\u0948\u0903 \u0938\u094D\u0924\u0942\u092F\u092E\u093E\u0928\u0903 \u0938\u094D\u0924\u0935\u0928\u092E\u093F\u0926\u092E\u092E\u094B\u0918\u0902 \u092A\u0941\u0937\u094D\u092A\u0926\u0928\u094D\u0924\u092A\u094D\u0930\u0923\u0940\u0924\u092E\u094D \u0965\u0969\u096F\u0965</p><p class="trans">Suravaramunip\u016Bjya\u1E41 svargamok\u1E63aikahetu\u1E41 pa\u1E6Dhati yadi manu\u1E63ya\u1E25 pr\u0101\xF1jalirn\u0101nyacet\u0101\u1E25 \u0964<br> Vrajati \u015Bivasam\u012Bpa\u1E41 kinnarai\u1E25 st\u016Byam\u0101na\u1E25 stavanamidamamogha\u1E41 pu\u1E63padantapra\u1E47\u012Btam \u096539\u0965</p><p>\u0415\u0441\u043B\u0438 <em>(yadi)</em> \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(manu\u1E63ya\u1E25)</em>, \u0447\u0435\u0439 \u0443\u043C <em>(cet\u0101\u1E25)</em> \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D \u0432 \u043E\u0434\u043D\u0443 \u0442\u043E\u0447\u043A\u0443 <em>(na-anya)</em>, \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0435\u0442 <em>(pa\u1E6Dhati)</em>, \u0441\u043B\u043E\u0436\u0438\u0432 \u043F\u0443\u0441\u0442\u044B\u0435 \u043B\u0430\u0434\u043E\u043D\u0438 <em>(pr\u0101\xF1jali\u1E25)</em>, \u044D\u0442\u043E\u0442 <em>(idam)</em> \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u044B\u0439 <em>(amogham)</em> \u0433\u0438\u043C\u043D \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u0435\u043D\u0438\u044F <em>(stavanam)</em>, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 <em>(pra\u1E47\u012Btam)</em> \u041F\u0443\u0448\u043F\u0430\u0434\u0430\u043D\u0442\u043E\u0439 <em>(pu\u1E63padanta)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u044E\u0442\u0441\u044F <em>(p\u016Bjyam)</em> \u0431\u043E\u0433\u0438 <em>(sura)</em> \u0438 \u043B\u0443\u0447\u0448\u0438\u0435 <em>(vara)</em> \u043C\u0443\u0434\u0440\u0435\u0446\u044B <em>(muni)</em>, \u0438 \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(eka)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(hetu)</em> \u043D\u0435\u0431\u0435\u0441\u043D\u043E\u0433\u043E <em>(svarga)</em> \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(mok\u1E63a)</em>, [\u0442\u043E\u0433\u0434\u0430 \u0442\u0430\u043A\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C], \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u0435\u043C\u0430\u044F <em>(st\u016Byam\u0101na\u1E25)</em> \u041A\u0438\u043D\u043D\u0430\u0440\u0430\u043C\u0438 --\u0432\u0438\u0434\u043E\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(kinnarai\u1E25)</em>, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(vrajati)</em> \u043A <em>(sam\u012Bpam)</em> \u0428\u0438\u0432\u0435 <em>(\u015Biva)</em></p></div><div class="stanza"><a href="#s40" id="s40" class="num">40</a><p class="sans">\u0936\u094D\u0930\u0940\u092A\u0941\u0937\u094D\u092A\u0926\u0928\u094D\u0924\u092E\u0941\u0916\u092A\u0919\u094D\u0915\u091C\u0928\u093F\u0930\u094D\u0917\u0924\u0947\u0928 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0947\u0923 \u0915\u093F\u0932\u094D\u092C\u093F\u0937\u0939\u0930\u0947\u0923 \u0939\u0930\u092A\u094D\u0930\u093F\u092F\u0947\u0923 \u0964<br> \u0915\u0923\u094D\u0920\u0938\u094D\u0925\u093F\u0924\u0947\u0928 \u092A\u0920\u093F\u0924\u0947\u0928 \u0938\u092E\u093E\u0939\u093F\u0924\u0947\u0928 \u0938\u0941\u092A\u094D\u0930\u0940\u0923\u093F\u0924\u094B \u092D\u0935\u0924\u093F \u092D\u0942\u0924\u092A\u0924\u093F\u0930\u094D\u092E\u0939\u0947\u0936\u0903 \u0965\u096A\u0966\u0965</p><p class="trans">\u015Ar\u012Bpu\u1E63padantamukhapa\u1E45kajanirgatena stotre\u1E47a kilbi\u1E63ahare\u1E47a harapriye\u1E47a \u0964<br> Ka\u1E47\u1E6Dhasthitena pa\u1E6Dhitena sam\u0101hitena supr\u012B\u1E47ito bhavati bh\u016Btapatirmahe\u015Ba\u1E25 \u096540\u0965</p><p>Mahe\u015Ba --\u0434\u043E\u0441\u043B. \xAB\u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C\xBB-- <em>(mahe\u015Ba\u1E25)</em>, \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D <em>(pati\u1E25)</em> [\u0432\u0441\u0435\u0445] \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(bh\u016Bta)</em>, \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F <em>(bhavati)</em> \u0434\u043E\u0432\u043E\u043B\u0435\u043D <em>(supr\u012B\u1E47ita\u1E25)</em> [\u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0433\u043E] \u0433\u0438\u043C\u043D\u0430 <em>(stotre\u1E47a)</em>, \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u0435\u0434\u0448\u0435\u0433\u043E \u0438\u0437 --nirgata-- <em>(nirgatena)</em> \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0443\u0441\u0442 <em>(mukha-pa\u1E45kaja)</em> \u0414\u043E\u0441\u0442\u043E\u043F\u043E\u0447\u0442\u0438\u043C\u043E\u0433\u043E <em>(\u015Br\u012B)</em> \u041F\u0443\u0448\u043F\u0430\u0434\u0430\u043D\u0442\u044B <em>(pu\u1E63padanta)</em>, \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u044E\u0449\u0435\u0433\u043E --hara-- <em>(hare\u1E47a)</em> \u0433\u0440\u0435\u0445\u0438 <em>(kilbi\u1E63a)</em> <em>(\u0438)</em> \u0434\u043E\u0440\u043E\u0433\u043E\u0433\u043E --priya-- <em>(priye\u1E47a)</em> \u0425\u0430\u0440\u0435 --\u0428\u0438\u0432\u0435-- <em>(hara)</em>, [\u0431\u0443\u0434\u044C] \u043E\u043D \u0437\u0430\u0443\u0447\u0435\u043D \u043D\u0430\u0438\u0437\u0443\u0441\u0442\u044C --ka\u1E47\u1E6Dhasthita-- <em>(ka\u1E47\u1E6Dhasthitena)</em> <em>(\u0438\u043B\u0438)</em> \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0435\u043C --pa\u1E6Dhita-- <em>(pa\u1E6Dhitena)</em> [\u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u043E] \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u043D --sam\u0101hita-- <em>(sam\u0101hitena)</em> --\u0434\u0440\u0443\u0433\u043E\u0439 \u0432\u0430\u0440\u0438\u0430\u043D\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430: \xAB[\u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u043E] \u0445\u0440\u0430\u043D\u0438\u043C [\u0434\u043E\u043C\u0430]\xBB--</p></div><div class="stanza"><a href="#s41" id="s41" class="num">41</a><p class="sans">\u0907\u0924\u094D\u092F\u0947\u0937\u093E \u0935\u093E\u0919\u094D\u092E\u092F\u0940 \u092A\u0942\u091C\u093E \u0936\u094D\u0930\u0940\u092E\u091A\u094D\u091B\u0919\u094D\u0915\u0930\u092A\u093E\u0926\u092F\u094B\u0903 \u0964<br> \u0905\u0930\u094D\u092A\u093F\u0924\u093E \u0924\u0947\u0928 \u0926\u0947\u0935\u0947\u0936\u0903 \u092A\u094D\u0930\u0940\u092F\u0924\u093E\u0902 \u092E\u0947 \u0938\u0926\u093E\u0936\u093F\u0935\u0903 \u0965\u096A\u0967\u0965</p><p class="trans">Itye\u1E63\u0101 v\u0101\u1E45may\u012B p\u016Bj\u0101 \u015Br\u012Bmaccha\u1E45karap\u0101dayo\u1E25 \u0964<br> Arpit\u0101 tena deve\u015Ba\u1E25 pr\u012Byat\u0101\u1E41 me sad\u0101\u015Biva\u1E25 \u096541\u0965</p><p>\u0418\u0442\u0430\u043A <em>(iti)</em>, \u044D\u0442\u043E <em>(e\u1E63\u0101)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 <em>(p\u016Bj\u0101)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 <em>(may\u012B)</em> \u0438\u0437 \u0441\u043B\u043E\u0432 <em>(v\u0101k)</em>, \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442\u0441\u044F <em>(arpit\u0101)</em> \u0441\u0442\u043E\u043F\u0430\u043C <em>(p\u0101dayo\u1E25)</em> \u0414\u043E\u0441\u0442\u043E\u043F\u043E\u0447\u0442\u0438\u043C\u043E\u0433\u043E <em>(\u015Br\u012Bmat)</em> <em>\u0428\u0430\u043D\u043A\u0430\u0440\u044B</em> --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 \u043F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u043D\u0438\u0435, \u0431\u043B\u0430\u0433\u043E\u0442\u0432\u043E\u0440\u043D\u044B\u0439 \u0438 \u0442.\u0434.\xBB-- <em>(\u015Ba\u1E45kara)</em>. \u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u044D\u0442\u043E\u0433\u043E [\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u044F] <em>(tena)</em>, [\u0434\u0430 \u0431\u0443\u0434\u0435\u0442] <em>Sad\u0101\u015Biva</em> --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0438\u0439 \xAB\u0432\u0435\u0447\u043D\u043E \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0439\xBB-- <em>(sad\u0101\u015Biva\u1E25)</em>, \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D <em>(\u012B\u015Ba)</em> \u0431\u043E\u0433\u043E\u0432 <em>(deva)</em>, \u0434\u043E\u0432\u043E\u043B\u0435\u043D <em>(pr\u012Byat\u0101m)</em> \u043C\u043D\u043E\u044E <em>(me)</em>!</p></div><div class="stanza"><a href="#s42" id="s42" class="num">42</a><p class="sans">\u092F\u0926\u0915\u094D\u0937\u0930\u0902 \u092A\u0926\u0902 \u092D\u094D\u0930\u0937\u094D\u091F\u0902 \u092E\u093E\u0924\u094D\u0930\u093E\u0939\u0940\u0928\u0902 \u091A \u092F\u0926\u094D\u092D\u0935\u0947\u0924\u094D \u0964<br> \u0924\u0924\u094D\u0938\u0930\u094D\u0935\u0902 \u0915\u094D\u0937\u092E\u094D\u092F\u0924\u093E\u0902 \u0926\u0947\u0935 \u092A\u094D\u0930\u0938\u0940\u0926 \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930 \u0965\u096A\u0968\u0965</p><p class="trans">Yadak\u1E63ara\u1E41 pada\u1E41 bhra\u1E63\u1E6Da\u1E41 m\u0101tr\u0101h\u012Bna\u1E41 ca yadbhavet \u0964<br> Tatsarva\u1E41 k\u1E63amyat\u0101\u1E41 deva pras\u012Bda parame\u015Bvara \u096542\u0965</p><p>\u041B\u044E\u0431\u043E\u0439 <em>(yad... yad)</em> \u0441\u043B\u043E\u0433 <em>(ak\u1E63aram)</em> <em>(\u0438\u043B\u0438)</em> \u0441\u043B\u043E\u0432\u043E <em>(padam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0431\u044B\u043B\u043E <em>(bhavet)</em> \u043F\u0440\u043E\u043F\u0443\u0449\u0435\u043D\u043E <em>(bhra\u1E63\u1E6Dam)</em> \u0438\u043B\u0438 --\u0434\u043E\u0441\u043B. \xAB\u0438\xBB -- <em>(ca)</em> \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u043E \u043D\u0435 \u0432\u043E\u0432\u0440\u0435\u043C\u044F <em>(m\u0101tr\u0101-h\u012Bnam)</em>, \u0434\u0430 \u043F\u0440\u043E\u0441\u0442\u0438\u0442 <em>(k\u1E63amyat\u0101m)</em> \u0411\u043E\u0433 <em>(deva)</em> \u0432\u0441\u0451 <em>(sarva)</em> \u044D\u0442\u043E <em>(tad)</em>. \u041E \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0438\u0439 <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Bvara)</em>, \u0431\u0443\u0434\u044C \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0451\u043D <em>(pras\u012Bda)</em>!</p></div><div class="stanza"><p class="sans">\u0950 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903\u0965</p><p class="trans">Om\u0310 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25\u0965</p><p>Om\u0310 <em>(om\u0310)</em>, \u043C\u0438\u0440 <em>(\u015B\u0101nti\u1E25)</em>, \u043C\u0438\u0440 <em>(\u015B\u0101nti\u1E25)</em>, \u043C\u0438\u0440 <em>(\u015B\u0101nti\u1E25)</em>.</p></div>',45);function d(u,y,l,c,k,b){const m=s,e=t;return h(),r("div",null,[v,a(m,{id:"xaKaZvgkKm8"}),a(e,{title:"Shiv mahimna Stotram with lyrics Chorus Shyamal Saumil",file:"/audio/mahimna/Shiv mahimna Stotram with lyrics Chorus Shyamal Saumil Devotional Songs.mp3"})])}var _=i(p,[["render",d]]);export{f as __pageData,_ as default};
